def _artifact_state_for_status(status: str) -> str:
    value = str(status or "").strip().lower()
    if value == "deprecated":
        return "deprecated"
    if value == "published":
        return "canonical"
    return "provisional"


def _truthy_env(value: Any, *, default: bool) -> bool:
    raw = str(value or "").strip().lower()
    if not raw:
        return default
    return raw in {"1", "true", "yes", "on"}


def _uuid_string_or_none(value: Any) -> Optional[str]:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        return str(uuid.UUID(raw))
    except (ValueError, TypeError, AttributeError):
        return None


def _intent_engine_enabled() -> bool:
    if "XYN_INTENT_ENGINE_V1" in os.environ:
        return _truthy_env(os.environ.get("XYN_INTENT_ENGINE_V1"), default=False)
    return bool(getattr(settings, "DEBUG", False))


def _intent_category_options() -> List[Dict[str, str]]:
    _ensure_default_article_categories_and_bindings()
    rows = ArticleCategory.objects.filter(enabled=True).order_by("name")
    return [{"slug": str(row.slug), "name": str(row.name)} for row in rows]


def _intent_contract_registry() -> DraftIntakeContractRegistry:
    return DraftIntakeContractRegistry(category_options_provider=_intent_category_options)


def _intent_dev_task_candidates(identity: UserIdentity, query: str, workspace_id: str) -> List[Dict[str, Any]]:
    search = str(query or "").strip()
    qs = DevTask.objects.all().order_by("-updated_at", "-created_at")
    dev_task_fields = {field.name for field in DevTask._meta.get_fields()}
    has_runtime_workspace = "runtime_workspace_id" in dev_task_fields
    if workspace_id and has_runtime_workspace:
        qs = qs.filter(models.Q(runtime_workspace_id=workspace_id) | models.Q(runtime_workspace_id__isnull=True))
    lowered = search.lower()
    if search:
        qs = qs.filter(
            models.Q(title__icontains=search)
            | models.Q(work_item_id__icontains=search)
            | models.Q(task_type__icontains=search)
            | models.Q(last_error__icontains=search)
        )
    elif "failure" in lowered or "error" in lowered:
        qs = qs.filter(status="failed")
    rows = []
    for task in qs[:5]:
        rows.append(
            {
                "id": str(task.id),
                "label": task.title,
                "kind": "dev_task",
                "status": task.status,
                "task_type": task.task_type,
                "work_item_id": task.work_item_id,
                "runtime_run_id": str(task.runtime_run_id) if task.runtime_run_id else None,
                "workspace_id": str(getattr(task, "runtime_workspace_id", "") or ""),
            }
        )
    return rows


def _intent_runtime_run_candidates(identity: UserIdentity, query: str, workspace_id: str) -> List[Dict[str, Any]]:
    search = str(query or "").strip()
    dev_task_fields = {field.name for field in DevTask._meta.get_fields()}
    has_runtime_workspace = "runtime_workspace_id" in dev_task_fields
    has_runtime_run = "runtime_run_id" in dev_task_fields
    if has_runtime_run:
        qs = DevTask.objects.exclude(runtime_run_id__isnull=True).order_by("-updated_at", "-created_at")
    else:
        qs = DevTask.objects.none()
    if workspace_id and has_runtime_workspace:
        qs = qs.filter(runtime_workspace_id=workspace_id)
    lowered = search.lower()
    if search and search not in {"it", "the run", "the work"}:
        qs = qs.filter(
            models.Q(title__icontains=search)
            | models.Q(work_item_id__icontains=search)
            | models.Q(last_error__icontains=search)
        )
    elif "failure" in lowered or "error" in lowered:
        qs = qs.filter(status="failed")
    rows = []
    for task in qs[:5]:
        rows.append(
            {
                "id": str(task.runtime_run_id),
                "label": task.title,
                "kind": "runtime_run",
                "status": task.status,
                "run_id": str(task.runtime_run_id),
                "work_item_id": task.work_item_id,
                "workspace_id": str(getattr(task, "runtime_workspace_id", "") or ""),
            }
        )
    return rows


def _intent_thread_candidates(identity: UserIdentity, query: str, workspace_id: str) -> List[Dict[str, Any]]:
    search = str(query or "").strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_id) if workspace_id else None
    qs = CoordinationThread.objects.all().order_by("-updated_at", "-created_at")
    if workspace is not None:
        qs = qs.filter(workspace=workspace)
    if search and search.lower() not in {"this thread", "the thread", "thread"}:
        qs = qs.filter(
            models.Q(title__icontains=search)
            | models.Q(description__icontains=search)
            | models.Q(domain__icontains=search)
        )
    rows = []
    for thread in qs[:5]:
        rows.append(
            {
                "id": str(thread.id),
                "label": thread.title,
                "kind": "coordination_thread",
                "status": thread.status,
                "priority": thread.priority,
                "workspace_id": str(thread.workspace_id),
            }
        )
    return rows


def _intent_goal_candidates(identity: UserIdentity, query: str, workspace_id: str) -> List[Dict[str, Any]]:
    search = str(query or "").strip()
