def _normalize_doc_route_bindings(raw: Any) -> list[str]:
    values: list[str] = []
    if not isinstance(raw, list):
        return values
    seen: set[str] = set()
    for entry in raw:
        route_id = str(entry or "").strip()
        if not route_id:
            continue
        if route_id in seen:
            continue
        seen.add(route_id)
        values.append(route_id)
    return values


def _normalize_doc_tags(raw: Any) -> list[str]:
    values: list[str] = []
    if not isinstance(raw, list):
        return values
    seen: set[str] = set()
    for entry in raw:
        tag = str(entry or "").strip().lower()
        if not tag:
            continue
        if tag in seen:
            continue
        seen.add(tag)
        values.append(tag)
    return values


