def _platform_initialization_state(identity: UserIdentity) -> Dict[str, Any]:
    workspace_count = _user_visible_workspace_qs().count()
    initialized = workspace_count > 0
    requires_setup = bool(_auth_mode() != "dev" and _is_platform_admin(identity) and not initialized)
    return {
        "initialized": bool(initialized),
        "requires_setup": bool(requires_setup),
        "workspace_count": int(workspace_count),
        "auth_mode": _auth_mode(),
    }


def _is_system_workspace(workspace: Workspace) -> bool:
    slug = str(getattr(workspace, "slug", "") or "").strip().lower()
    if slug in {"platform-builder", "civic-lab"}:
        return True
    metadata = getattr(workspace, "metadata_json", None)
    if isinstance(metadata, dict) and metadata.get("xyn_system_workspace") is True:
        return True
    return False


def _user_visible_workspace_qs():
    return Workspace.objects.exclude(slug__in=["platform-builder", "civic-lab"])


def _workspace_is_visible(workspace: Workspace, *, include_system: bool = False) -> bool:
    if include_system:
        return True
    return not _is_system_workspace(workspace)


DEFAULT_WORKSPACE_RUNTIME_ARTIFACTS: tuple[tuple[str, str, str, str], ...] = (
    (
        "core.workbench",
        "Workbench",
        "registry/modules/workbench.artifact.manifest.json",
        "Console-first, panel-based runtime landing experience.",
    ),
    (
        "xyn-api",
        "xyn-api",
        "registry/modules/xyn-api.artifact.manifest.json",
        "Deployable Xyn API runtime artifact.",
    ),
    (
        "xyn-ui",
        "xyn-ui",
        "registry/modules/xyn-ui.artifact.manifest.json",
        "Deployable Xyn UI runtime artifact.",
    ),
)


def _runtime_artifact_host_workspace(fallback_workspace: Workspace) -> Workspace:
    host_workspace = Workspace.objects.filter(slug="platform-builder").first()
    if host_workspace is not None:
        return host_workspace
    first_workspace = Workspace.objects.order_by("created_at").first()
    if first_workspace is not None:
        return first_workspace
    return fallback_workspace


def _ensure_default_workspace_artifact_bindings(workspace: Workspace) -> None:
    host_workspace = _runtime_artifact_host_workspace(workspace)
    for slug, title, manifest_ref, summary in DEFAULT_WORKSPACE_RUNTIME_ARTIFACTS:
        artifact = _ensure_runtime_artifact(
            workspace=host_workspace,
            slug=slug,
            title=title,
            manifest_ref=manifest_ref,
            summary=summary,
        )
        binding, _ = WorkspaceArtifactBinding.objects.get_or_create(
            workspace=workspace,
            artifact=artifact,
            defaults={"enabled": True, "installed_state": "installed", "config_ref": None},
        )
        update_fields: List[str] = []
        if not binding.enabled:
            binding.enabled = True
            update_fields.append("enabled")
        if str(binding.installed_state or "").strip().lower() != "installed":
            binding.installed_state = "installed"
            update_fields.append("installed_state")
        if update_fields:
            update_fields.append("updated_at")
            binding.save(update_fields=update_fields)


def _ensure_dev_bootstrap_workspace(identity: UserIdentity) -> Optional[Workspace]:
    if _auth_mode() != "dev":
        return None
    if not _is_platform_admin(identity):
        return None
    workspace, _ = Workspace.objects.get_or_create(
        slug="development",
        defaults={
            "name": "Development",
            "org_name": "Development",
            "description": "Default development workspace for local bootstrap.",
            "status": "active",
            "kind": "internal",
            "lifecycle_stage": "internal",
            "auth_mode": "local",
            "metadata_json": {"bootstrap": "dev_default"},
        },
    )
    metadata = workspace.metadata_json if isinstance(workspace.metadata_json, dict) else {}
    if metadata.get("xyn_system_workspace") is True:
        metadata = dict(metadata)
        metadata.pop("xyn_system_workspace", None)
        workspace.metadata_json = metadata
        workspace.save(update_fields=["metadata_json", "updated_at"])
    WorkspaceMembership.objects.update_or_create(
        workspace=workspace,
        user_identity=identity,
        defaults={"role": "admin", "termination_authority": True},
    )
    _ensure_default_workspace_artifact_bindings(workspace)
    return workspace


@csrf_exempt
def platform_initialization_status(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    return JsonResponse({"platform_initialization": _platform_initialization_state(identity)})


@csrf_exempt
def platform_initialization_complete(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if not _is_platform_admin(identity):
        return JsonResponse({"error": "forbidden"}, status=403)
    if _auth_mode() == "dev":
        return JsonResponse({"error": "platform initialization wizard is not used in dev mode"}, status=409)
    if _user_visible_workspace_qs().exists():
        return JsonResponse(
            {"error": "platform already initialized", "platform_initialization": _platform_initialization_state(identity)},
            status=409,
        )

    payload = _parse_json(request)
    requested_name = str(payload.get("workspace_name") or payload.get("company_name") or "").strip()
    workspace_name = requested_name or "Company"
    requested_slug = str(payload.get("workspace_slug") or "").strip().lower()
    slug_base = requested_slug or slugify(workspace_name) or "company"
    slug_value = slug_base
    suffix = 2
    while Workspace.objects.filter(slug=slug_value).exists():
        slug_value = f"{slug_base}-{suffix}"
        suffix += 1

    with transaction.atomic():
        workspace = Workspace.objects.create(
            slug=slug_value,
            name=workspace_name,
            org_name=str(payload.get("org_name") or workspace_name).strip() or workspace_name,
            description=str(payload.get("description") or "").strip(),
            status="active",
            kind="customer",
            lifecycle_stage="customer",
            auth_mode="oidc" if _auth_mode() == "oidc" else "local",
            metadata_json={"bootstrap": "initial_setup"},
        )
        WorkspaceMembership.objects.update_or_create(
            workspace=workspace,
            user_identity=identity,
            defaults={"role": "admin", "termination_authority": True},
        )
        latest_doc = PlatformConfigDocument.objects.order_by("-version").first()
        next_version = int(getattr(latest_doc, "version", 0) or 0) + 1
        PlatformConfigDocument.objects.create(
            version=next_version,
            config_json={
                "initialized": True,
                "initialized_at": timezone.now().isoformat(),
                "initial_workspace_id": str(workspace.id),
                "initial_workspace_slug": workspace.slug,
            },
            created_by=getattr(request, "user", None),
        )

    return JsonResponse(
        {
            "workspace": _serialize_workspace_summary(workspace, role="admin", termination_authority=True),
            "platform_initialization": _platform_initialization_state(identity),
        }
    )


def api_me(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    include_system = str(request.GET.get("include_system") or "").strip().lower() in {"1", "true", "yes"}
    roles = _get_roles(identity)
    bootstrap_workspace = _ensure_dev_bootstrap_workspace(identity)
    if _is_platform_admin(identity):
        rows = Workspace.objects.all().order_by("name")
        if not include_system:
            rows = [row for row in rows if _workspace_is_visible(row, include_system=False)]
        workspace_payload = [
            _serialize_workspace_summary(
                row,
                role="admin",
                termination_authority=True,
            )
            for row in rows
        ]
    else:
        memberships = WorkspaceMembership.objects.filter(user_identity=identity).select_related("workspace").order_by("workspace__name")
        workspace_payload = [
            _serialize_workspace_summary(
                membership.workspace,
                role=membership.role,
                termination_authority=bool(membership.termination_authority),
            )
            for membership in memberships
            if _workspace_is_visible(membership.workspace, include_system=include_system)
        ]

    preferred_workspace_id = ""
    if bootstrap_workspace is not None:
        preferred_workspace_id = str(bootstrap_workspace.id)
    elif workspace_payload:
        dev_entry = next((entry for entry in workspace_payload if str(entry.get("slug") or "").strip().lower() == "development"), None)
        preferred_workspace_id = str((dev_entry or workspace_payload[0]).get("id") or "")

    return JsonResponse(
        {
            "user": {
                "issuer": identity.issuer,
                "subject": identity.subject,
                "email": identity.email,
                "display_name": identity.display_name,
            },
            "roles": roles,
            "actor_roles": list(getattr(request, "actor_roles", []) or roles),
            "preview": _serialize_preview_status(identity, request),
            "auth_mode": _auth_mode(),
            "workspaces": workspace_payload,
            "preferred_workspace_id": preferred_workspace_id,
            "platform_initialization": _platform_initialization_state(identity),
        }
    )


