    payload = list_notifications_for_recipient(
        recipient=identity,
        limit=limit,
        offset=offset,
        unread_only=unread_only,
        source_app_key=source_app_key,
        category=category,
    )
    payload["unread_count"] = get_unread_count_for_recipient(recipient=identity)
    return JsonResponse(payload)


