@csrf_exempt
def ai_agents_collection(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    _ensure_default_agent_purposes()
    if request.method == "GET":
        purpose = str(request.GET.get("purpose") or "").strip().lower()
        enabled_only = str(request.GET.get("enabled") or "").strip().lower() in {"1", "true", "yes"}
        agents = AgentDefinition.objects.select_related("model_config__provider", "model_config__credential").prefetch_related("purposes")
        if purpose:
            agents = agents.filter(purposes__slug=purpose)
        if enabled_only:
            agents = agents.filter(enabled=True)
        return JsonResponse({"agents": [_serialize_agent_definition(item) for item in agents.order_by("name", "slug")]})
    if not _can_manage_ai(identity):
        return JsonResponse({"error": "forbidden"}, status=403)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    slug = str(payload.get("slug") or "").strip().lower()
    name = str(payload.get("name") or "").strip()
    model_config_id = payload.get("model_config_id")
    if not slug or not name or not model_config_id:
        return JsonResponse({"error": "slug, name, and model_config_id are required"}, status=400)
    if AgentDefinition.objects.filter(slug=slug).exists():
        return JsonResponse({"error": "slug already exists"}, status=400)
    model_config = ModelConfig.objects.filter(id=model_config_id).first()
    if not model_config:
        return JsonResponse({"error": "invalid model_config_id"}, status=400)
    agent = AgentDefinition.objects.create(
        slug=slug,
        name=name,
        model_config=model_config,
        system_prompt_text=str(payload.get("override_prompt_text") or payload.get("system_prompt_text") or ""),
        context_pack_refs_json=[],
        is_default=bool(payload.get("is_default", False)),
        enabled=bool(payload.get("enabled", True)),
    )
    raw_default_refs = payload.get("default_context_pack_refs_json")
    if raw_default_refs is None:
        raw_default_refs = payload.get("context_pack_refs_json")
    if raw_default_refs is not None:
        refs, ref_err = _normalize_agent_default_context_pack_refs(raw_default_refs)
        if ref_err:
            agent.delete()
            return JsonResponse({"error": ref_err}, status=400)
        agent.context_pack_refs_json = refs
        agent.save(update_fields=["context_pack_refs_json", "updated_at"])
    if agent.is_default:
        AgentDefinition.objects.exclude(id=agent.id).update(is_default=False)
    purpose_slugs = payload.get("purposes") if isinstance(payload.get("purposes"), list) else []
    purposes = list(AgentPurpose.objects.filter(slug__in=purpose_slugs))
    for purpose in purposes:
        AgentDefinitionPurpose.objects.get_or_create(agent_definition=agent, purpose=purpose)
    agent.refresh_from_db()
    return JsonResponse({"agent": _serialize_agent_definition(agent)})


@csrf_exempt
def ai_agent_detail(request: HttpRequest, agent_id: str) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    agent = get_object_or_404(
        AgentDefinition.objects.select_related("model_config__provider", "model_config__credential").prefetch_related("purposes"),
        id=agent_id,
    )
    if request.method == "GET":
        return JsonResponse({"agent": _serialize_agent_definition(agent)})
    if not _can_manage_ai(identity):
        return JsonResponse({"error": "forbidden"}, status=403)
    if request.method == "DELETE":
        agent.delete()
        return JsonResponse({}, status=204)
    if request.method != "PATCH":
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    if "slug" in payload:
        next_slug = str(payload.get("slug") or agent.slug).strip().lower()
        if next_slug != agent.slug and AgentDefinition.objects.filter(slug=next_slug).exists():
            return JsonResponse({"error": "slug already exists"}, status=400)
        agent.slug = next_slug
    if "name" in payload:
        agent.name = str(payload.get("name") or agent.name).strip()
    if "model_config_id" in payload:
        model_config = ModelConfig.objects.filter(id=payload.get("model_config_id")).first()
        if not model_config:
            return JsonResponse({"error": "invalid model_config_id"}, status=400)
        agent.model_config = model_config
    if "override_prompt_text" in payload or "system_prompt_text" in payload:
        agent.system_prompt_text = str(payload.get("override_prompt_text") or payload.get("system_prompt_text") or "")
    if "default_context_pack_refs_json" in payload or "context_pack_refs_json" in payload:
        raw_default_refs = payload.get("default_context_pack_refs_json")
        if raw_default_refs is None:
            raw_default_refs = payload.get("context_pack_refs_json")
        refs, ref_err = _normalize_agent_default_context_pack_refs(raw_default_refs)
        if ref_err:
            return JsonResponse({"error": ref_err}, status=400)
        agent.context_pack_refs_json = refs
    if "enabled" in payload:
        agent.enabled = bool(payload.get("enabled"))
    if "is_default" in payload:
        agent.is_default = bool(payload.get("is_default"))
    agent.save(
        update_fields=[
            "slug",
            "name",
            "model_config",
            "system_prompt_text",
            "context_pack_refs_json",
            "is_default",
            "enabled",
            "updated_at",
        ]
    )
    if agent.is_default:
        AgentDefinition.objects.exclude(id=agent.id).update(is_default=False)
    if "purposes" in payload and isinstance(payload.get("purposes"), list):
        desired = list(AgentPurpose.objects.filter(slug__in=payload.get("purposes")))
        AgentDefinitionPurpose.objects.filter(agent_definition=agent).exclude(purpose__in=desired).delete()
        for purpose in desired:
            AgentDefinitionPurpose.objects.get_or_create(agent_definition=agent, purpose=purpose)
    agent.refresh_from_db()
    return JsonResponse({"agent": _serialize_agent_definition(agent)})


def _intent_apply_create_draft(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    if not _can_manage_articles(identity):
        return JsonResponse({"error": "forbidden"}, status=403)

    contract = _intent_contract_registry().get("ArticleDraft")
    if contract is None:
        return JsonResponse({"error": "intake contract unavailable"}, status=500)
    merged = contract.merge_defaults(payload or {})
    merged["format"] = contract.normalize_format(merged.get("format"))
    missing = contract.missing_fields(merged)
    if missing:
        return JsonResponse(
            {
                "status": "MissingFields",
                "action_type": "CreateDraft",
                "artifact_type": "ArticleDraft",
                "summary": "Draft requires additional fields before it can proceed.",
                "missing_fields": [
                    {
                        "field": field_name,
                        "reason": "required by intake contract",
                        "options_available": contract.options_available(field_name),
                    }
                    for field_name in missing
                ],
                "audit": {
                    "request_id": request_id,
                    "timestamp": timezone.now().isoformat(),
                    **_intent_context_pack_audit(),
                },
            },
            status=400,
        )

    title = str(merged.get("title") or "").strip()
    category_slug = str(merged.get("category") or "").strip().lower()
    external_format = str(merged.get("format") or "article").strip().lower()
    intent_value = str(merged.get("intent") or "").strip()
    duration_value = str(merged.get("duration") or "").strip()
    tags = _normalize_doc_tags(merged.get("tags"))
    summary = str(merged.get("summary") or "")
    body_markdown = str(merged.get("body") or "")

    category = _resolve_article_category_slug(category_slug, allow_disabled=False)
    if not category:
        return JsonResponse({"error": f"unknown category: {category_slug}"}, status=400)

    workspace = _resolve_article_workspace(identity, str(payload.get("workspace_id") or "")) or _docs_workspace()
    slug = _normalize_artifact_slug(str(payload.get("slug") or ""), fallback_title=title)
    if not slug:
        slug = _normalize_artifact_slug("", fallback_title=title)
    if _artifact_slug_exists(str(workspace.id), slug):
        slug = _normalize_artifact_slug(f"{slug}-{uuid.uuid4().hex[:6]}", fallback_title=title)

    article_type = _ensure_article_artifact_type()
    try:
        internal_format = intent_to_internal_format(external_format)
    except PatchValidationError as exc:
        return JsonResponse({"error": str(exc)}, status=400)
    video_spec = None
    scaffold_quality = "none"
    video_context_pack = None
    if internal_format == "video_explainer":
        generation_fields = _extract_explainer_generation_fields(
            title=title,
            intent=intent_value,
            summary=summary,
            description=str(merged.get("description") or body_markdown or summary),
            audience=str(merged.get("audience") or ""),
            category=category.slug,
        )
        video_spec, scaffold_quality = _build_explainer_video_spec(
            title=title,
            summary=summary,
            intent=generation_fields.get("topic") or intent_value or title,
            topic=generation_fields.get("topic") or "",
            grounding=generation_fields.get("grounding") or "",
            category=generation_fields.get("category") or "",
            duration=duration_value,
            audience=generation_fields.get("audience") or "",
            description=str(merged.get("description") or body_markdown or summary),
        )
        spec_errors = validate_video_spec(video_spec, require_scenes=True)
        if spec_errors:
            return JsonResponse({"error": "invalid video spec", "details": spec_errors}, status=400)
        video_context_pack, pack_error = _resolve_video_context_pack_for_article(
            None,
            payload.get("video_context_pack_id") if isinstance(payload, dict) else None,
            allow_clear=False,
        )
        if pack_error:
            return pack_error
        summary, body_markdown = _derive_explainer_initial_content(
            title=title,
            summary=summary,
            body_markdown=body_markdown,
            scenes=video_spec.get("scenes") if isinstance(video_spec.get("scenes"), list) else [],
        )

    with transaction.atomic():
        artifact = Artifact.objects.create(
            workspace=workspace,
            type=article_type,
            title=title,
            slug=slug,
            format=internal_format,
            status="draft",
            version=1,
            visibility=_artifact_visibility_for_article_type("private"),
            author=identity,
            custodian=identity,
            scope_json={
                "slug": slug,
                "category": category.slug,
                "visibility_type": "private",
                "allowed_roles": [],
                "route_bindings": [],
                "tags": tags,
            },
            article_category=category,
            video_spec_json=video_spec,
            video_context_pack=video_context_pack if internal_format == "video_explainer" else None,
        )
        ArtifactRevision.objects.create(
            artifact=artifact,
            revision_number=1,
            content_json={
                "title": title,
                "summary": summary,
                "body_markdown": body_markdown,
                "body_html": "",
                "tags": tags,
            },
            created_by=identity,
        )
        ArtifactExternalRef.objects.update_or_create(
            artifact=artifact,
            system="shine",
            defaults={"external_id": str(artifact.id), "slug_path": slug},
        )
        emit_ledger_event(
            actor=identity,
            action="draft.created",
            artifact=artifact,
            summary="Created Article draft via intent engine",
            metadata={"fields_set": sorted([k for k in ["title", "category", "format", "intent", "duration"] if str(merged.get(k) or "").strip()])},
            dedupe_key=f"draft.created:{artifact.id}",
        )
        if internal_format == "video_explainer" and isinstance(video_spec, dict):
            emit_ledger_event(
                actor=identity,
                action="draft.scaffolded",
                artifact=artifact,
                summary="Generated initial explainer scenes scaffold",
                metadata={
                    "scene_count": len(video_spec.get("scenes") or []) if isinstance(video_spec.get("scenes"), list) else 0,
                    "scaffold_quality": scaffold_quality,
                },
                dedupe_key=f"draft.scaffolded:{artifact.id}",
            )

    intent_telemetry_increment("apply_success")
    payload_response = {
        "status": "DraftReady",
        "action_type": "CreateDraft",
        "artifact_type": "ArticleDraft",
        "artifact_id": str(artifact.id),
        "summary": "Draft created successfully.",
        "next_actions": [{"label": "Open editor", "action": "OpenEditor"}],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
            **_intent_context_pack_audit(),
        },
    }
    _audit_intent_event(
        message="intent.apply",
        identity=identity,
        request_id=request_id,
        artifact_id=str(artifact.id),
        proposal={},
        resolution=payload_response,
    )
    return JsonResponse(payload_response)


def _intent_apply_create_app_intent_draft(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    thread_id = str(payload.get("thread_id") or "").strip()
    workspace = _resolve_workspace_for_identity(identity, str(payload.get("workspace_id") or payload.get("operator_workspace_id") or ""))
    if not workspace:
        return JsonResponse({"error": "workspace context is required for app builder flow"}, status=400)

    raw_prompt = str(payload.get("raw_prompt") or "").strip()
    if not raw_prompt:
        return JsonResponse({"error": "raw_prompt is required"}, status=400)
    extracted = _extract_app_intent_fields(raw_prompt)
    initial_intent = payload.get("initial_intent") if isinstance(payload.get("initial_intent"), dict) else {}
    revision_anchor = payload.get("revision_anchor") if isinstance(payload.get("revision_anchor"), dict) else {}
    current_app_summary = payload.get("current_app_summary") if isinstance(payload.get("current_app_summary"), dict) else {}
    current_app_spec = payload.get("current_app_spec") if isinstance(payload.get("current_app_spec"), dict) else {}
    latest_appspec_ref = payload.get("latest_appspec_ref") if isinstance(payload.get("latest_appspec_ref"), dict) else {}
    merged_intent = {
        "app_kind": str(initial_intent.get("app_kind") or extracted.get("app_kind") or "custom_app"),
        "requested_entities": _normalize_unique_strings(list(initial_intent.get("requested_entities") or extracted.get("requested_entities") or [])),
        "phase_1_scope": _normalize_unique_strings(list(initial_intent.get("phase_1_scope") or extracted.get("phase_1_scope") or [])),
        "requested_visuals": _normalize_unique_strings(list(initial_intent.get("requested_visuals") or extracted.get("requested_visuals") or [])),
        "workspace_scoped": bool(initial_intent.get("workspace_scoped", extracted.get("workspace_scoped", True))),
    }
    if revision_anchor:
        merged_intent["evolution_mode"] = str(initial_intent.get("evolution_mode") or "modify_installed_generated_app")
    draft_title = str(payload.get("title") or current_app_summary.get("title") or extracted.get("title") or "New App").strip() or "New App"
    draft_status = "ready" if merged_intent.get("requested_entities") or revision_anchor else "draft"
    draft_content = {
        "raw_prompt": raw_prompt,
        "initial_intent": merged_intent,
    }
    if revision_anchor:
        draft_content["revision_anchor"] = revision_anchor
    if current_app_summary:
        draft_content["current_app_summary"] = current_app_summary
    if current_app_spec:
        draft_content["current_app_spec"] = current_app_spec
    if latest_appspec_ref:
        draft_content["latest_appspec_ref"] = latest_appspec_ref

    created_by = str(identity.email or identity.subject or "xyn-ui").strip() or "xyn-ui"
    try:
        workspaces_response = _seed_api_request(method="GET", path="/api/v1/workspaces", timeout=20)
        if workspaces_response.status_code < 300:
            workspaces_payload = workspaces_response.json() if workspaces_response.content else []
            workspace_rows = workspaces_payload if isinstance(workspaces_payload, list) else []
            slug_exists = any(str(item.get("slug") or "").strip().lower() == str(workspace.slug or "").strip().lower() for item in workspace_rows if isinstance(item, dict))
            if not slug_exists:
                _seed_api_request(
                    method="POST",
                    path="/api/v1/workspaces",
                    payload={"slug": str(workspace.slug or "development"), "title": str(workspace.name or workspace.slug or "Development")},
                    timeout=20,
                )
    except requests.RequestException:
        # Draft creation below will return explicit failure details if core is unreachable.
        pass
    try:
        draft_response = _seed_api_request(
            method="POST",
            path="/api/v1/drafts",
            workspace_slug=str(workspace.slug or ""),
            payload={
                "type": "app_intent",
                "title": draft_title,
                "status": draft_status,
                "created_by": created_by,
                "content_json": draft_content,
            },
        )
    except requests.RequestException as exc:
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="failed",
            prompt=raw_prompt,
            request_type="intent.apply",
            workspace_id=str(workspace.id),
            summary="Failed to reach xyn-core draft endpoint.",
            error=exc.__class__.__name__,
            thread_id=thread_id,
        )
        return JsonResponse({"error": "failed to create app draft", "details": exc.__class__.__name__}, status=502)

    if draft_response.status_code >= 300:
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="failed",
            prompt=raw_prompt,
            request_type="intent.apply",
            workspace_id=str(workspace.id),
            summary="xyn-core draft creation failed.",
            error=f"status={draft_response.status_code}",
            thread_id=thread_id,
        )
        return JsonResponse(
            {
                "error": "failed to create app draft",
                "status_code": draft_response.status_code,
                "response_text": draft_response.text[:800],
            },
            status=502,
        )
    draft_payload = draft_response.json() if draft_response.content else {}
    draft_id = str(draft_payload.get("id") or "")
    if not draft_id:
        return JsonResponse({"error": "xyn-core draft response missing id"}, status=502)

    try:
        submit_response = _seed_api_request(
            method="POST",
            path=f"/api/v1/drafts/{draft_id}/submit",
            workspace_slug=str(workspace.slug or ""),
            payload={},
        )
    except requests.RequestException as exc:
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="failed",
            prompt=raw_prompt,
            request_type="intent.apply",
            workspace_id=str(workspace.id),
            draft_id=draft_id,
            summary="Failed to submit app draft to xyn-core.",
            error=exc.__class__.__name__,
            thread_id=thread_id,
        )
        return JsonResponse({"error": "draft created but submit failed", "draft_id": draft_id, "details": exc.__class__.__name__}, status=502)
    if submit_response.status_code >= 300:
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="failed",
            prompt=raw_prompt,
            request_type="intent.apply",
            workspace_id=str(workspace.id),
            draft_id=draft_id,
            summary="xyn-core draft submit failed.",
            error=f"status={submit_response.status_code}",
            thread_id=thread_id,
        )
        return JsonResponse(
            {
                "error": "draft created but submit failed",
                "draft_id": draft_id,
                "status_code": submit_response.status_code,
                "response_text": submit_response.text[:800],
            },
            status=502,
        )
    submit_payload = submit_response.json() if submit_response.content else {}
    job_id = str(submit_payload.get("job_id") or "")

    payload_response = {
        "status": "DraftReady",
        "action_type": "CreateDraft",
        "artifact_type": "Workspace",
        "artifact_id": None,
        "summary": "Generated app revision draft created and submitted for processing."
        if revision_anchor
        else "App intent draft created and submitted for processing.",
        "result": {
            "workspace_id": str(workspace.id),
            "draft_id": draft_id,
            "job_id": job_id,
            "seed_api_base_url": _seed_api_base_url(),
            "initial_intent": merged_intent,
            "revision_anchor": revision_anchor or None,
        },
        "next_actions": [
            {
                "label": "Track build",
                "action": "OpenPanel",
                "panel_key": "draft_detail",
                "params": {
                    "workspace_id": str(workspace.id),
                    "draft_id": draft_id,
                    "job_id": job_id,
                },
            },
        ],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
        },
    }
    _audit_intent_event(
        message="intent.apply",
        identity=identity,
        request_id=request_id,
        artifact_id=None,
        proposal={"operation": str(payload.get("__operation") or "create_app_intent_draft"), "revision_anchor": revision_anchor or None},
        resolution=payload_response,
    )
    _log_prompt_activity(
        request_id=request_id,
        identity=identity,
        status="completed",
        prompt=raw_prompt,
        request_type="intent.apply",
        workspace_id=str(workspace.id),
        draft_id=draft_id,
        job_id=job_id,
        summary="App intent draft submitted.",
        thread_id=thread_id,
    )
    return JsonResponse(payload_response)


