@csrf_exempt
def app_builder_artifacts_collection(request: HttpRequest) -> JsonResponse:
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    workspace_ref = str(
        request.GET.get("workspace_id")
        or request.GET.get("workspace_slug")
        or request.GET.get("workspace")
        or request.GET.get("operator_workspace_id")
        or request.headers.get("X-Workspace-Id")
        or ""
    ).strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_ref)
    if not workspace:
        return JsonResponse({"error": "workspace context is required"}, status=400)
    kind = str(request.GET.get("kind") or "").strip()
    limit = str(request.GET.get("limit") or "50").strip()
    path = f"/api/v1/artifacts?limit={quote(limit, safe='')}"
    if kind:
        path += f"&kind={quote(kind, safe='')}"
    try:
        response = _seed_api_request(method="GET", path=path, workspace_slug=str(workspace.slug or ""), timeout=20)
    except requests.RequestException as exc:
        return JsonResponse({"error": "failed to reach xyn-core", "details": exc.__class__.__name__}, status=502)
    content_type = str(response.headers.get("content-type") or "").lower()
    if "application/json" not in content_type:
        return JsonResponse({"error": "unexpected xyn-core response", "response_text": response.text[:800]}, status=502)
    payload = response.json() if response.content else {}
    items = payload.get("items") if isinstance(payload, dict) else []
    normalized = [item for item in items if isinstance(item, dict)]
    return JsonResponse(normalized, safe=False, status=response.status_code)


@csrf_exempt
def app_builder_execution_notes_collection(request: HttpRequest) -> JsonResponse:
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    workspace_ref = str(
        request.GET.get("workspace_id")
        or request.GET.get("workspace_slug")
        or request.GET.get("workspace")
        or request.GET.get("operator_workspace_id")
        or request.headers.get("X-Workspace-Id")
        or ""
    ).strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_ref)
    if not workspace:
        return JsonResponse({"error": "workspace context is required"}, status=400)
    note_ids = [str(item).strip() for item in request.GET.getlist("note_id") if str(item).strip()]
    job_ids = [str(item).strip() for item in request.GET.getlist("job_id") if str(item).strip()]
    related_artifact_ids = [str(item).strip() for item in request.GET.getlist("related_artifact_id") if str(item).strip()]
    if not note_ids and not job_ids and not related_artifact_ids:
        return JsonResponse({"error": "explicit execution-note selectors are required"}, status=400)
    try:
        payload = _list_app_builder_execution_notes(
            workspace_slug=str(workspace.slug or ""),
            note_ids=note_ids,
            job_ids=job_ids,
            related_artifact_ids=related_artifact_ids,
        )
    except requests.RequestException as exc:
        return JsonResponse({"error": "failed to reach xyn-core", "details": exc.__class__.__name__}, status=502)
    except RuntimeError as exc:
        return JsonResponse({"error": str(exc)}, status=502)
    return JsonResponse(payload, safe=False, status=200)


@csrf_exempt
def app_palette_execute(request: HttpRequest) -> JsonResponse:
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    workspace_ref = str(
        request.GET.get("workspace_id")
        or request.GET.get("workspace_slug")
        or request.GET.get("workspace")
        or request.GET.get("operator_workspace_id")
        or request.headers.get("X-Workspace-Id")
        or ""
    ).strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_ref)
    if not workspace:
        return JsonResponse({"error": "workspace context is required"}, status=400)
    prompt = str(payload.get("prompt") or "").strip()
    prompt_key = _normalize_palette_prompt(prompt)
    request_id = str(uuid.uuid4())
    generated_app_slug = _resolve_generated_app_slug(workspace) or "net-inventory"
    runtime_target_record = _workspace_runtime_target(workspace, generated_app_slug)
    generated_artifact_issue = _workspace_generated_artifact_issue(workspace, generated_app_slug)
    capability_manifest = _workspace_installed_capability_manifest(workspace, generated_app_slug)
    if (
        runtime_target_record
        and generated_artifact_issue
        and _looks_like_generated_crud_prompt(prompt)
        and not _match_generated_app_evolution_command(prompt, workspace)
    ):
        result = _generated_app_invalid_contract_response(prompt=prompt, issue=generated_artifact_issue)
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="failed",
            prompt=prompt,
            request_type="palette.execute",
            workspace_id=str(workspace.id),
            summary="Generated app contract is unavailable for the installed artifact.",
            error=str(generated_artifact_issue.get("reason") or "invalid_generated_artifact_contract"),
            trace=[
                _generated_trace_step("user_command", source="palette", prompt=prompt),
                _generated_trace_step("invalid_generated_artifact_contract", **generated_artifact_issue),
            ],
        )
        return result
    if runtime_target_record and capability_manifest:
        try:
            return _generated_app_palette_execution_response(
                identity=identity,
                request_id=request_id,
                workspace=workspace,
                prompt=prompt,
                runtime_target=runtime_target_record["runtime_target"],
                capability_manifest=capability_manifest,
            )
        except RuntimeError as exc:
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="failed",
                prompt=prompt,
                request_type="palette.execute",
                workspace_id=str(workspace.id),
                summary="Generated app runtime request failed.",
                error=str(exc),
                trace=[_generated_trace_step("user_command", source="palette", prompt=prompt), _generated_trace_step("error", error=str(exc))],
            )
            return JsonResponse({"error": "generated app runtime request failed", "details": str(exc)}, status=502)
    if runtime_target_record and prompt_key in _manifest_latent_command_keys(capability_manifest or {}):
        result = _generated_app_disabled_response(prompt=prompt, capability_manifest=capability_manifest or {})
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="completed",
            prompt=prompt,
            request_type="palette.execute",
            workspace_id=str(workspace.id),
            summary="No matching palette command found.",
            trace=[_generated_trace_step("user_command", source="palette", prompt=prompt), _generated_trace_step("result", outcome="latent_disabled")],
        )
        return result
    return _proxy_seed_workspace_request(
        request,
        path="/api/v1/palette/execute",
        method="POST",
        payload=payload,
        timeout=30,
    )


def _intent_apply_patch(
    *,
    identity: UserIdentity,
    artifact_type: str,
    artifact_id: str,
    patch_object: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    if artifact_type == "ArticleDraft":
        artifact = _resolve_article_or_404(artifact_id)
        if not _can_edit_article(identity, artifact):
            return JsonResponse({"error": "forbidden"}, status=403)
        try:
            updated = intent_apply_patch(
                artifact=artifact,
                actor=identity,
                patch_object=patch_object,
                category_resolver=lambda: _intent_category_options(),
            )
        except PatchValidationError as exc:
            intent_telemetry_increment("apply_error")
            return JsonResponse(
                {
                    "status": "ValidationError",
                    "action_type": "ApplyPatch",
                    "artifact_type": "ArticleDraft",
                    "artifact_id": str(artifact.id),
                    "summary": "Patch failed deterministic validation.",
                    "validation_errors": [str(exc)],
                    "audit": {
                        "request_id": request_id,
                        "timestamp": timezone.now().isoformat(),
                        **_intent_context_pack_audit(),
                    },
                },
                status=400,
            )

        latest = ArtifactRevision.objects.filter(artifact=updated).order_by("-revision_number").first()
        current_content = dict((latest.content_json if latest else {}) or {})
        metadata = {
            "title": updated.title,
            "category": _article_category(updated),
            "format": _article_format(updated),
            "summary_hash": hashlib.sha256(str(current_content.get("summary") or "").encode("utf-8")).hexdigest(),
            "body_hash": hashlib.sha256(str(current_content.get("body_markdown") or "").encode("utf-8")).hexdigest(),
        }
        emit_ledger_event(
            actor=identity,
            action="draft.patched",
            artifact=updated,
            summary="Patched Article draft via intent engine",
            metadata=metadata,
            dedupe_key=f"draft.patched:{updated.id}:{hashlib.sha256(json.dumps(metadata, sort_keys=True).encode('utf-8')).hexdigest()}",
        )
        intent_telemetry_increment("apply_success")
        payload_response = {
            "status": "DraftReady",
            "action_type": "ApplyPatch",
            "artifact_type": "ArticleDraft",
            "artifact_id": str(updated.id),
            "summary": "Patch applied successfully.",
            "next_actions": [{"label": "Open editor", "action": "OpenEditor"}],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
                **_intent_context_pack_audit(),
            },
        }
        _audit_intent_event(
            message="intent.apply",
            identity=identity,
            request_id=request_id,
            artifact_id=str(updated.id),
            proposal={"patch_object": patch_object},
            resolution=payload_response,
        )
        return JsonResponse(payload_response)

    artifact = _resolve_context_pack_artifact_or_404(artifact_id)
    if not _can_manage_docs(identity):
        return JsonResponse({"error": "forbidden"}, status=403)
    if str(artifact.source_ref_type or "") != "ContextPack":
        return JsonResponse({"error": "context pack target unavailable"}, status=404)
    pack = ContextPack.objects.filter(id=artifact.source_ref_id).first()
    if not pack:
        return JsonResponse({"error": "context pack target unavailable"}, status=404)
    try:
        updated_pack, hash_info, changes = intent_apply_context_pack_patch(
            pack=pack,
            actor=identity,
            patch_object=patch_object,
        )
    except PatchValidationError as exc:
        intent_telemetry_increment("apply_error")
        return JsonResponse(
            {
                "status": "ValidationError",
                "action_type": "ApplyPatch",
                "artifact_type": "ContextPack",
                "artifact_id": str(artifact.id),
                "summary": "Patch failed deterministic validation.",
                "validation_errors": [str(exc)],
                "audit": {
                    "request_id": request_id,
                    "timestamp": timezone.now().isoformat(),
                    **_intent_context_pack_audit(),
                },
            },
            status=400,
        )

    artifact.title = updated_pack.name
    artifact.summary = f"{updated_pack.purpose} · {updated_pack.scope} · v{updated_pack.version}"
    artifact.scope_json = {
        "purpose": updated_pack.purpose,
        "scope": updated_pack.scope,
        "namespace": updated_pack.namespace,
        "project_key": updated_pack.project_key,
    }
    artifact.save(update_fields=["title", "summary", "scope_json", "updated_at"])

    metadata = {
        "title": updated_pack.name,
        "format": (
            str((updated_pack.applies_to_json or {}).get("content_format") or "json")
            if isinstance(updated_pack.applies_to_json, dict)
            else "json"
        ),
        "changed_fields": [entry.get("field") for entry in changes if isinstance(entry, dict)],
        "before_content_hash": hash_info.get("before_hash"),
        "after_content_hash": hash_info.get("after_hash"),
    }
    emit_ledger_event(
        actor=identity,
        action="contextpack.patched",
        artifact=artifact,
        summary="Patched Context Pack via intent engine",
        metadata=metadata,
        dedupe_key=f"contextpack.patched:{artifact.id}:{hashlib.sha256(json.dumps(metadata, sort_keys=True).encode('utf-8')).hexdigest()}",
    )
    intent_telemetry_increment("apply_success")
    payload_response = {
        "status": "DraftReady",
        "action_type": "ApplyPatch",
        "artifact_type": "ContextPack",
        "artifact_id": str(artifact.id),
        "summary": "Context pack patch applied successfully.",
        "next_actions": [{"label": "Open editor", "action": "OpenEditor"}],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
            **_intent_context_pack_audit(),
        },
    }
    _audit_intent_event(
        message="intent.apply",
        identity=identity,
        request_id=request_id,
        artifact_id=str(artifact.id),
        proposal={"patch_object": patch_object, "artifact_type": "ContextPack"},
        resolution=payload_response,
    )
    return JsonResponse(payload_response)


def _match_deploy_ems_customer_command(message: str) -> Optional[str]:
    text = str(message or "").strip()
    if not text:
        return None
    match = re.search(r"deploy\s+ems(?:-lite)?\s+for\s+customer\s+(.+)$", text, flags=re.IGNORECASE)
    if not match:
        return None
    customer_name = str(match.group(1) or "").strip().strip("\"'")
    return customer_name or None


def _match_create_ems_instance_command(message: str) -> Optional[Tuple[str, str]]:
    text = str(message or "").strip()
    if not text:
        return None
    match = re.search(
        r"create\s+(?:a\s+)?new\s+instance\s+of\s+ems(?:-lite)?\s+for\s+customer\s+(.+?)\s+fqdn\s+(?:should\s+be|is|=)\s*([a-z0-9.-]+)",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return None
    customer_name = str(match.group(1) or "").strip().strip("\"' ,.")
    fqdn = str(match.group(2) or "").strip().lower().strip(".")
    if "." not in fqdn:
        return None
    return (customer_name, fqdn) if customer_name and fqdn else None


def _match_install_xyn_instance_command(message: str) -> Optional[Tuple[str, str, str, bool, str]]:
    text = str(message or "").strip()
    if not text:
        return None
    match = re.search(
        r"install\s+xyn\s+instance\s+for\s+(.+?)\s+fqdn\s+(?:should\s+be|is|=)?\s*([a-z0-9.-]+)",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return None
    customer_name = str(match.group(1) or "").strip().strip("\"' ,.")
    fqdn = str(match.group(2) or "").strip().lower().strip(".")
    if "." not in fqdn:
        return None
    instance_match = re.search(r"\b(?:on|using)\s+instance\s+([a-z0-9._-]+)\b", text, flags=re.IGNORECASE)
    instance_ref = str(instance_match.group(1) or "").strip() if instance_match else "xyn-ec2-demo"
    dns_enabled = not bool(re.search(r"\bdns\s+(off|disabled?)\b", text, flags=re.IGNORECASE))
    dns_mode = "route53" if bool(re.search(r"\broute53\b", text, flags=re.IGNORECASE)) else "manual"
    return (customer_name, fqdn, instance_ref, dns_enabled, dns_mode) if customer_name and fqdn else None


def _match_provision_xyn_remote_command(message: str) -> Optional[Dict[str, Any]]:
    text = str(message or "").strip()
    if not text:
        return None
    if not re.search(r"provision\s+xyn\s+instance", text, flags=re.IGNORECASE):
        return None
    fqdn_match = re.search(r"\bfqdn\s+(?:should\s+be|is|=)?\s*([a-z0-9.-]+)", text, flags=re.IGNORECASE)
    customer_match = re.search(r"\bfor\s+customer\s+(.+?)(?:\s+fqdn|\s+on\s+instance|\s+with\s+ems|$)", text, flags=re.IGNORECASE)
    instance_match = re.search(r"\b(?:on|using)\s+instance\s+([a-z0-9._-]+)\b", text, flags=re.IGNORECASE)
    label_match = re.search(r"\blabel\s+([a-z0-9._-]+)\b", text, flags=re.IGNORECASE)
    include_ems = bool(re.search(r"\bwith\s+ems\b", text, flags=re.IGNORECASE))
    dns_enabled = not bool(re.search(r"\bdns\s+(off|disabled?)\b", text, flags=re.IGNORECASE))
    return {
        "customer_name": str((customer_match.group(1) if customer_match else "Customer") or "").strip().strip("\"' ,."),
        "fqdn": str((fqdn_match.group(1) if fqdn_match else "") or "").strip().lower().strip("."),
        "instance_ref": str((instance_match.group(1) if instance_match else "xyn-ec2-demo") or "").strip(),
        "instance_label": str((label_match.group(1) if label_match else "") or "").strip(),
        "include_ems": include_ems,
        "dns_enabled": dns_enabled,
    }


def _match_ems_panel_command(message: str) -> Optional[Tuple[str, Dict[str, Any]]]:
    text = str(message or "").strip().lower()
    if not text:
        return None
    if "show unregistered devices" in text:
        return ("ems_unregistered_devices", {"state": "unregistered"})
    if "show device statuses" in text or "show device status" in text:
        return ("ems_device_statuses", {})
    match = re.search(r"show\s+registrations\s+in\s+the\s+past\s+(\d+)\s+hours?", text, flags=re.IGNORECASE)
    if match:
        hours = max(1, min(168, int(match.group(1))))
        return ("ems_registrations_time", {"hours": hours})
    return None


def _match_artifact_panel_command(message: str) -> Optional[Tuple[str, Dict[str, Any]]]:
    text = str(message or "").strip()
    if not text:
        return None
    lower = re.sub(r"\s+", " ", text.lower()).strip()
    lower = re.sub(r"^(?:please[,\s]+)+", "", lower)
    lower = re.sub(r"^(?:can|could|would)\s+you\s+", "", lower)
    lower = re.sub(r"^take\s+me\s+to\s+", "go to ", lower)
    lower = re.sub(r"[.!?,:;]+$", "", lower)
    lower = re.sub(r"^show\s+me\s+(?:a\s+)?list\s+of\s+", "list ", lower)
    lower = re.sub(r"^show\s+me\s+", "show ", lower)
    lower = re.sub(r"^(open|show|go to)\s+the\s+", r"\1 ", lower)
    lower = re.sub(r"\s+(?:page|screen|view|panel|tab|hub)\s*$", "", lower)
    lower = re.sub(r"[.!?,:;]+$", "", lower)

    def _artifact_created_day_query(day_offset: int) -> Dict[str, Any]:
        return {
            "entity": "artifacts",
            "filters": [
                {"field": "created_at", "op": "gte", "value": f"day-start:{day_offset}"},
                {"field": "created_at", "op": "lt", "value": f"day-start:{day_offset + 1}"},
            ],
            "sort": [{"field": "created_at", "dir": "desc"}],
            "limit": 50,
            "offset": 0,
        }

    if re.fullmatch(r"(?:list|show|open)\s+artifacts", lower):
        return ("artifact_list", {})
    if re.fullmatch(r"(?:list|show|open)\s+artifacts\s+created\s+today", lower):
        return ("artifact_list", {"query": _artifact_created_day_query(0)})
    if re.fullmatch(r"(?:list|show|open)\s+artifacts\s+created\s+yesterday", lower):
        return ("artifact_list", {"query": _artifact_created_day_query(-1)})
    if re.fullmatch(r"(?:list|show|open)\s+artifacts\s+created\s+two\s+days\s+ago", lower):
        return ("artifact_list", {"query": _artifact_created_day_query(-2)})
    list_match = re.search(r"\blist\s+([a-z0-9_.-]+)\s+artifacts\b", lower)
    if list_match:
        namespace = str(list_match.group(1) or "").strip().lower()
        return ("artifact_list", {"namespace": namespace})
    open_match = re.search(r"\bopen\s+artifact\s+([a-z0-9_.-]+)\b", lower)
    if open_match:
        return ("artifact_detail", {"slug": str(open_match.group(1) or "").strip()})
    raw_match = re.search(r"\bedit\s+artifact\s+([a-z0-9_.-]+)\s+raw\b", lower)
    if raw_match:
        return ("artifact_raw_json", {"slug": str(raw_match.group(1) or "").strip()})
    files_match = re.search(r"\bedit\s+artifact\s+([a-z0-9_.-]+)\s+files\b", lower)
    if files_match:
        return ("artifact_files", {"slug": str(files_match.group(1) or "").strip()})
    return None


def _match_rules_panel_command(message: str) -> Optional[Tuple[str, Dict[str, Any]]]:
    text = str(message or "").strip()
    if not text:
        return None
    lower = re.sub(r"\s+", " ", text.lower()).strip()
    lower = re.sub(r"^(?:please[,\s]+)+", "", lower)
    lower = re.sub(r"^(?:can|could|would)\s+you\s+", "", lower)
    lower = re.sub(r"^take\s+me\s+to\s+", "go to ", lower)
    lower = re.sub(r"[.!?,:;]+$", "", lower)
    lower = re.sub(r"^show\s+me\s+", "show ", lower)
    lower = re.sub(r"^(open|show|go to)\s+the\s+", r"\1 ", lower)
    lower = re.sub(r"\s+(?:page|screen|view|panel|tab|hub)\s*$", "", lower)
    lower = re.sub(r"[.!?,:;]+$", "", lower)

    target_match = re.search(r"(?:show|open|list)\s+(?:rules|policy bundle)\s+for\s+(.+)$", lower)
    if target_match:
        raw_target = str(target_match.group(1) or "").strip().strip("\"' ")
        params: Dict[str, Any] = {"q": raw_target}
        if raw_target.startswith("policy."):
            params["artifact_slug"] = raw_target
        elif raw_target.startswith("app."):
            params["app_slug"] = raw_target
        return ("rules_browser", params)

    if re.fullmatch(r"(?:show|open|list)\s+editable\s+rules", lower):
        return ("rules_browser", {"editable": True})
    if re.fullmatch(r"(?:show|open|list)\s+system\s+rules", lower):
        return ("rules_browser", {"system": True})
    if re.fullmatch(r"(?:show|open|list)\s+policy\s+bundle", lower):
        return ("rules_browser", {"policy_bundle": True})
    if re.fullmatch(r"(?:show|open|list)\s+rules", lower):
        return ("rules_browser", {})
    return None


def _unsupported_artifact_filter_reason(message: str) -> Optional[str]:
    text = str(message or "").strip()
    if not text:
        return None
    lower = re.sub(r"\s+", " ", text.lower()).strip()
    lower = re.sub(r"^(?:please[,\s]+)+", "", lower)
    lower = re.sub(r"^(?:can|could|would)\s+you\s+", "", lower)
    lower = re.sub(r"^take\s+me\s+to\s+", "go to ", lower)
    lower = re.sub(r"[.!?,:;]+$", "", lower)
    lower = re.sub(r"^show\s+me\s+(?:a\s+)?list\s+of\s+", "list ", lower)
    lower = re.sub(r"^show\s+me\s+", "show ", lower)
    lower = re.sub(r"^(open|show|go to)\s+the\s+", r"\1 ", lower)
    lower = re.sub(r"\s+(?:page|screen|view|panel|tab|hub)\s*$", "", lower)
    lower = re.sub(r"[.!?,:;]+$", "", lower)
    if not re.match(r"^(list|show|open)\s+artifacts\b", lower):
        return None
    if _match_artifact_panel_command(message):
        return None
    if re.search(r"\bcreated\b", lower) or re.search(r"\bwith\s+status\b", lower) or re.search(r"\bstatus\s+[a-z0-9_.-]+\b", lower) or re.search(r"\bowned\s+by\b", lower):
        return "Artifact list filters currently support only created today, created yesterday, or created two days ago."
    return None


def _match_core_surface_command(message: str) -> Optional[Tuple[str, Dict[str, Any]]]:
    text = str(message or "").strip()
    if not text:
        return None
    normalized = re.sub(r"\s+", " ", text.lower()).strip()
    normalized = re.sub(r"^(?:please[,\s]+)+", "", normalized)
    normalized = re.sub(r"^(?:can|could|would)\s+you\s+", "", normalized)
    normalized = re.sub(r"^take\s+me\s+to\s+", "go to ", normalized)
    normalized = re.sub(r"[.!?,:;]+$", "", normalized)
    normalized = re.sub(r"^(open|show|go to)\s+the\s+", r"\1 ", normalized)
    normalized = re.sub(r"\s+(?:page|screen|view|panel|tab|hub)\s*$", "", normalized)
    normalized = re.sub(r"[.!?,:;]+$", "", normalized)
    platform_settings_aliases = {
        "platform settings",
        "open platform settings",
        "show platform settings",
        "go to platform settings",
        "configure platform",
    }
    if normalized in platform_settings_aliases:
        return ("platform_settings", {})
    campaign_aliases = {
        "campaigns",
        "show campaigns",
        "open campaigns",
        "list campaigns",
        "go to campaigns",
    }
    if normalized in campaign_aliases:
        return ("campaign_list", {})
    create_campaign_aliases = {
        "new campaign",
        "create campaign",
        "add campaign",
        "start campaign",
    }
    if normalized in create_campaign_aliases:
        return ("campaign_list", {"create": True})
    return None


def _should_invoke_legacy_intake_fallback(message: str, *, has_context_artifact: bool) -> bool:
    if has_context_artifact:
        return True
    prompt = str(message or "").strip().lower()
    if not prompt:
        return False
    if any(token in prompt for token in ["show options", "what categories", "what formats", "available categories", "available formats"]):
        return True
    if re.search(r"\bcontext\s*pack\b", prompt) and re.search(r"\b(add|set|update|rewrite|change|edit|patch)\b", prompt):
        return True
    if re.search(r"\b(create|make|start|new|draft|write|build)\b", prompt) and re.search(r"\b(article|guide|tour|explainer|video)\b", prompt):
        return True
    return False


def _direct_panel_intent_response(
    *,
    request_id: str,
    summary: str,
    panel_key: str,
    params: Optional[Dict[str, Any]] = None,
    prompt_interpretation: Optional[Dict[str, Any]] = None,
    extra_payload: Optional[Dict[str, Any]] = None,
) -> JsonResponse:
    payload: Dict[str, Any] = {
        "status": "IntentResolved",
        "action_type": "ValidateDraft",
        "artifact_type": "Workspace",
        "artifact_id": None,
        "summary": summary,
        "prompt_interpretation": prompt_interpretation or {},
        "next_actions": [
            {
                "label": "Open panel",
                "action": "OpenPanel",
                "panel_key": panel_key,
                "params": params or {},
            }
        ],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
        },
    }
    if isinstance(extra_payload, dict):
        payload.update(extra_payload)
    return JsonResponse(payload)


def _direct_panel_target_for_conversation_action(
    *,
    action_type: str,
    workspace_id: str,
    action_payload: Optional[Dict[str, Any]] = None,
    target: Optional[Dict[str, Any]] = None,
) -> Optional[Tuple[str, Dict[str, Any]]]:
    payload = action_payload if isinstance(action_payload, dict) else {}
    target_object = target if isinstance(target, dict) else {}
    summary_mode = str(payload.get("summary_mode") or "").strip()
    target_id = str(target_object.get("id") or "").strip()

    if action_type == ConversationActionType.LIST_APPLICATION_FACTORIES.value:
        return "composer_detail", {"workspace_id": workspace_id}
    if action_type == ConversationActionType.OPEN_COMPOSER.value:
        params: Dict[str, Any] = {"workspace_id": workspace_id}
        for key in ("factory_key", "application_plan_id", "application_id", "goal_id", "thread_id"):
            value = str(payload.get(key) or "").strip()
            if value:
                params[key] = value
        return "composer_detail", params
    if action_type == ConversationActionType.LIST_THREADS.value:
        return "thread_list", {"workspace_id": workspace_id}
    if action_type == ConversationActionType.SHOW_THREAD_REVIEW.value and target_id:
        return "composer_detail", {"workspace_id": workspace_id, "thread_id": target_id}
    if action_type == ConversationActionType.SHOW_THREAD.value and target_id and not summary_mode:
        return "composer_detail", {"workspace_id": workspace_id, "thread_id": target_id}
    if action_type == ConversationActionType.LIST_GOALS.value and not summary_mode:
        return "composer_detail", {"workspace_id": workspace_id}
    if action_type == ConversationActionType.SHOW_GOAL.value and target_id and not summary_mode:
        return "composer_detail", {"workspace_id": workspace_id, "goal_id": target_id}
    if action_type == ConversationActionType.LIST_CAMPAIGNS.value:
        return "campaign_list", {"workspace_id": workspace_id}
    if action_type == ConversationActionType.CREATE_CAMPAIGN.value:
        return "campaign_list", {"workspace_id": workspace_id, "create": True}
    if action_type == ConversationActionType.SHOW_CAMPAIGN.value and target_id:
        return "campaign_detail", {"workspace_id": workspace_id, "campaign_id": target_id}
    if action_type == ConversationActionType.SHOW_APPLICATION.value and target_id:
        return "composer_detail", {"workspace_id": workspace_id, "application_id": target_id}
    return None


def _direct_panel_prompt_interpretation(
    *,
    intent_type: str,
    action_label: str,
    target_entity_key: str = "",
    target_entity_label: str = "",
    resolution_notes: Optional[List[str]] = None,
) -> Dict[str, Any]:
    interpretation = PromptInterpretation(
        intent_family="navigation",
        intent_type=intent_type,
        target_entity=(
            PromptInterpretationTarget(
                key=target_entity_key or None,
                label=target_entity_label or None,
            )
            if (target_entity_key or target_entity_label)
            else None
        ),
        target_record=None,
        target_work_item=None,
        target_run=None,
        action=PromptInterpretationAction(verb="open", label=action_label),
        fields=[],
        execution_mode=PromptInterpretationExecutionMode.IMMEDIATE_EXECUTION.value,
        confidence=0.95,
        needs_clarification=False,
        capability_state=PromptInterpretationCapabilityState(
            state=PromptInterpretationCapabilityStateValue.ENABLED.value
            if target_entity_key
            else PromptInterpretationCapabilityStateValue.UNKNOWN.value
        ),
        clarification_reason=None,
        clarification_options=[],
        resolution_notes=resolution_notes or [],
        missing_fields=[],
        recognized_spans=[],
    )
    return interpretation.model_dump(mode="json")


def _extract_app_intent_fields(message: str) -> Dict[str, Any]:
    text = str(message or "")
    lower = text.lower()
    requested_entities: List[str] = []
    if "devices" in lower:
        requested_entities.append("devices")
    if "interfaces" in lower:
        requested_entities.append("interfaces")
    if "vlans" in lower or "vlan" in lower:
        requested_entities.append("vlans")
    if "ip addresses" in lower or "ip_address" in lower or "ip address" in lower:
        requested_entities.append("ip_addresses")
    if "locations" in lower or "location" in lower:
        requested_entities.append("locations")
    if "racks" in lower or "rack" in lower:
        requested_entities.append("racks")

    phase_1_scope: List[str] = []
    if re.search(r"start\s+with\s+devices?\s+and\s+locations?", lower):
        phase_1_scope = ["devices", "locations"]
    elif "devices" in lower and ("locations" in lower or "location" in lower):
        phase_1_scope = ["devices", "locations"]

    requested_visuals: List[str] = []
    if re.search(r"devices?\s+by\s+status", lower):
        requested_visuals.append("devices_by_status_chart")
    if re.search(r"interfaces?\s+by\s+status", lower):
        requested_visuals.append("interfaces_by_status_chart")

    app_kind = "network_inventory" if ("network inventory" in lower or "devices" in lower) else "custom_app"
    workspace_scoped = "workspace" in lower
    title = "Network Inventory App" if app_kind == "network_inventory" else "New App"
    return {
        "title": title,
        "app_kind": app_kind,
        "requested_entities": requested_entities,
        "phase_1_scope": phase_1_scope,
        "requested_visuals": requested_visuals,
        "workspace_scoped": workspace_scoped,
        "raw_prompt": text,
    }


def _normalize_unique_strings(values: List[Any]) -> List[str]:
    result: List[str] = []
    seen: set[str] = set()
    for value in values:
        token = str(value or "").strip()
        if not token or token in seen:
            continue
        seen.add(token)
        result.append(token)
    return result


def _infer_entities_from_app_spec(app_spec: Dict[str, Any]) -> List[str]:
    entities = app_spec.get("entities") if isinstance(app_spec.get("entities"), list) else []
    normalized = _normalize_unique_strings(list(entities))
    if normalized:
        return normalized
    inferred: List[str] = []
    reports = [str(item or "").strip() for item in (app_spec.get("reports") or []) if str(item or "").strip()]
    requires_primitives = [str(item or "").strip() for item in (app_spec.get("requires_primitives") or []) if str(item or "").strip()]
    services = app_spec.get("services") if isinstance(app_spec.get("services"), list) else []
    service_names = [str(item.get("name") or "").strip() for item in services if isinstance(item, dict)]
    if "net-inventory-api" in service_names:
        inferred.append("devices")
    if "location" in requires_primitives:
        inferred.append("locations")
    if any("interfaces" in report for report in reports):
        inferred.append("interfaces")
    return _normalize_unique_strings(inferred)


def _installed_generated_app_contexts(workspace: Workspace) -> List[Dict[str, Any]]:
    rows = (
        WorkspaceArtifactBinding.objects.filter(
            workspace=workspace,
            enabled=True,
            installed_state="installed",
            artifact__slug__startswith="app.",
            artifact__type__slug="application",
        )
        .select_related("artifact", "artifact__type")
        .order_by("-updated_at", "-created_at")
    )
    contexts: List[Dict[str, Any]] = []
    for binding in rows:
        artifact = binding.artifact
        if not artifact:
            continue
        slug = str(artifact.slug or "").strip()
        if not slug.startswith("app."):
            continue
        app_slug = slug[len("app.") :].strip()
        if not app_slug:
            continue
        manifest = _load_artifact_manifest(artifact)
        content = manifest.get("content") if isinstance(manifest.get("content"), dict) else {}
        current_app_spec = content.get("app_spec") if isinstance(content.get("app_spec"), dict) else {}
        runtime_config = content.get("runtime_config") if isinstance(content.get("runtime_config"), dict) else {}
        runtime_target_record = _workspace_runtime_target(workspace, app_slug)
        runtime_instance = runtime_target_record.get("instance") if isinstance(runtime_target_record, dict) else None
        latest_appspec_ref = {
            "artifact_slug": slug,
            "artifact_id": str(artifact.id),
            "artifact_version": str(artifact.package_version or ""),
            "source_build_job_id": str(runtime_config.get("source_job_id") or ""),
            "app_spec_artifact_id": str(runtime_config.get("app_spec_artifact_id") or ""),
        }
        current_app_summary = {
            "app_slug": str(current_app_spec.get("app_slug") or app_slug or "").strip(),
            "title": str(current_app_spec.get("title") or artifact.title or slug).strip(),
            "entities": _infer_entities_from_app_spec(current_app_spec),
            "reports": _normalize_unique_strings(list(current_app_spec.get("reports") or [])),
            "requires_primitives": _normalize_unique_strings(list(current_app_spec.get("requires_primitives") or [])),
        }
        if isinstance(runtime_target_record, dict):
            runtime_target = runtime_target_record.get("runtime_target") if isinstance(runtime_target_record.get("runtime_target"), dict) else {}
            current_app_summary["runtime_owner"] = str(runtime_target.get("runtime_owner") or "")
            current_app_summary["runtime_base_url"] = str(runtime_target.get("runtime_base_url") or "")
        contexts.append(
            {
                "binding": binding,
                "artifact": artifact,
                "artifact_slug": slug,
                "app_slug": app_slug,
                "package_version": str(artifact.package_version or ""),
                "runtime_instance_id": str(getattr(runtime_instance, "id", "") or ""),
                "current_app_spec": current_app_spec,
                "current_runtime_config": runtime_config,
                "current_app_summary": current_app_summary,
                "latest_appspec_ref": latest_appspec_ref,
            }
        )
    return contexts


def _resolve_generated_app_slug(workspace: Workspace, *, preferred_app_slug: str = "") -> Optional[str]:
    preferred = str(preferred_app_slug or "").strip()
    if preferred:
        artifact_slug = f"app.{preferred}"
        if _workspace_has_installed_artifact_slug(workspace, artifact_slug) or _workspace_runtime_target(workspace, preferred):
            return preferred
    contexts = _installed_generated_app_contexts(workspace)
    if not contexts:
        return None
    if len(contexts) == 1:
        return str(contexts[0].get("app_slug") or "").strip() or None
    active_contexts = [row for row in contexts if str(row.get("runtime_instance_id") or "").strip()]
    if len(active_contexts) == 1:
        return str(active_contexts[0].get("app_slug") or "").strip() or None
    legacy_default = next(
        (str(row.get("app_slug") or "").strip() for row in contexts if str(row.get("app_slug") or "").strip() == "net-inventory"),
        "",
    )
    if legacy_default:
        return legacy_default
    return str(contexts[0].get("app_slug") or "").strip() or None


def _looks_like_generated_app_evolution_request(message: str) -> bool:
    text = str(message or "").strip()
    if not text:
        return False
    lower = text.lower()
    if _match_app_builder_command(text):
        return False
    if re.match(r"^\s*(show|list|open|create)\s+devices?\b", lower):
        return False
    if re.match(r"^\s*(show|list)\s+locations?\b", lower):
        return False
    if re.match(r"^\s*show\s+devices?\s+by\s+status\b", lower):
        return False
    evolution_verb = re.search(r"\b(add|include|update|extend|modify|change|remove|support|enhance)\b", lower)
    evolution_target = re.search(
        r"\b(this app|current app|application|interfaces?|vlans?|racks?|locations?|devices?|chart|report|status)\b",
        lower,
    )
    return bool(evolution_verb and evolution_target)


def _match_generated_app_evolution_command(message: str, workspace: Workspace) -> Optional[Dict[str, Any]]:
    if not _looks_like_generated_app_evolution_request(message):
        return None
    contexts = _installed_generated_app_contexts(workspace)
    if len(contexts) != 1:
        return None
    context = contexts[0]
    current_app_spec = context.get("current_app_spec") if isinstance(context.get("current_app_spec"), dict) else {}
    if not current_app_spec:
        return None
    fields = _extract_app_intent_fields(message)
    current_app_summary = context.get("current_app_summary") if isinstance(context.get("current_app_summary"), dict) else {}
    current_entities = current_app_summary.get("entities") if isinstance(current_app_summary.get("entities"), list) else []
    current_reports = current_app_summary.get("reports") if isinstance(current_app_summary.get("reports"), list) else []
    merged_intent = {
        "app_kind": str(fields.get("app_kind") or "custom_app"),
        "requested_entities": _normalize_unique_strings(list(current_entities) + list(fields.get("requested_entities") or [])),
        "phase_1_scope": _normalize_unique_strings(list(fields.get("phase_1_scope") or [])),
        "requested_visuals": _normalize_unique_strings(list(fields.get("requested_visuals") or [])),
        "workspace_scoped": True,
        "evolution_mode": "modify_installed_generated_app",
        "current_entities": _normalize_unique_strings(list(current_entities)),
        "current_reports": _normalize_unique_strings(list(current_reports)),
    }
    revision_anchor = {
        "anchor_type": "installed_generated_artifact",
        "workspace_id": str(workspace.id),
        "workspace_slug": str(workspace.slug or ""),
        "artifact_id": str(context.get("artifact").id if context.get("artifact") else ""),
        "artifact_slug": str(context.get("artifact_slug") or ""),
        "artifact_version": str(context.get("package_version") or ""),
        "app_slug": str(context.get("app_slug") or ""),
        "workspace_app_instance_id": str(context.get("runtime_instance_id") or ""),
    }
    latest_appspec_ref = context.get("latest_appspec_ref") if isinstance(context.get("latest_appspec_ref"), dict) else {}
    return {
        "operation": "evolve_app_intent_draft",
        "title": str(current_app_summary.get("title") or context.get("artifact").title or "Generated App").strip() or "Generated App",
        "initial_intent": merged_intent,
        "raw_prompt": str(fields.get("raw_prompt") or message),
        "revision_anchor": revision_anchor,
        "current_app_summary": current_app_summary,
        "current_app_spec": current_app_spec,
        "latest_appspec_ref": latest_appspec_ref,
    }


def _match_app_builder_command(message: str) -> Optional[Dict[str, Any]]:
    text = str(message or "").strip()
    if not text:
        return None
    lower = text.lower()
    starts_like_app_build = bool(
        re.match(
            r"^\s*(build|create|generate)\s+(?:a|an|the)?\s*(?:new\s+)?(app|application)\b",
            lower,
            flags=re.IGNORECASE,
        )
    )
    has_network_inventory_signals = (
        ("network inventory" in lower)
        or ("devices" in lower and ("workspace" in lower or "locations" in lower or "location" in lower))
    )
    if not starts_like_app_build and not has_network_inventory_signals:
        return None
    fields = _extract_app_intent_fields(text)
    return {
        "operation": "create_app_intent_draft",
        "title": fields.get("title") or "New App",
        "initial_intent": {
            "app_kind": fields.get("app_kind") or "custom_app",
            "requested_entities": fields.get("requested_entities") or [],
            "phase_1_scope": fields.get("phase_1_scope") or [],
            "requested_visuals": fields.get("requested_visuals") or [],
            "workspace_scoped": bool(fields.get("workspace_scoped")),
        },
        "raw_prompt": fields.get("raw_prompt") or text,
    }


def _resolve_workspace_for_identity(identity: UserIdentity, workspace_id: str) -> Optional[Workspace]:
    requested = str(workspace_id or "").strip()
    if requested:
        requested_uuid: Optional[uuid.UUID] = None
        try:
            requested_uuid = uuid.UUID(requested)
        except (TypeError, ValueError, AttributeError):
            requested_uuid = None
        if requested_uuid is not None:
            membership = WorkspaceMembership.objects.select_related("workspace").filter(
                user_identity=identity,
                workspace_id=requested_uuid,
            ).first()
            if membership:
                return membership.workspace
        membership = WorkspaceMembership.objects.select_related("workspace").filter(
            user_identity=identity,
            workspace__slug=requested,
        ).first()
        if membership:
            return membership.workspace
        if _is_platform_admin(identity):
            if requested_uuid is not None:
                workspace = Workspace.objects.filter(id=requested_uuid).first()
                if workspace:
                    return workspace
            return Workspace.objects.filter(slug=requested).first()
        return None
    fallback = WorkspaceMembership.objects.select_related("workspace").filter(user_identity=identity).order_by("workspace__name").first()
    return fallback.workspace if fallback else None


def _seed_api_base_url() -> str:
    return str(os.environ.get("XYN_CORE_BASE_URL") or "http://xyn-core:8000").strip().rstrip("/")


def _seed_api_request(
    *,
    method: str,
    path: str,
    workspace_id: str = "",
    workspace_slug: str = "",
    payload: Optional[Dict[str, Any]] = None,
    timeout: int = 20,
) -> requests.Response:
    base_url = _seed_api_base_url()
    url = f"{base_url}{path}"
    params: Dict[str, str] = {}
    if workspace_id:
        params["workspace_id"] = workspace_id
    if workspace_slug:
        params["workspace_slug"] = workspace_slug
    return requests.request(
        method=method.upper(),
        url=url,
        params=params or None,
        json=payload,
        timeout=timeout,
    )


def _proxy_seed_workspace_request(
    request: HttpRequest,
    *,
    workspace_hint: str = "",
    path: str,
    method: str,
    payload: Optional[Dict[str, Any]] = None,
    timeout: int = 20,
) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    workspace_ref = str(
        workspace_hint
        or request.GET.get("workspace_id")
        or request.GET.get("workspace")
        or request.GET.get("operator_workspace_id")
        or request.headers.get("X-Workspace-Id")
        or ""
    ).strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_ref)
    if not workspace:
        return JsonResponse({"error": "workspace context is required"}, status=400)
    try:
        response = _seed_api_request(
            method=method,
            path=path,
            workspace_slug=str(workspace.slug or ""),
            payload=payload,
            timeout=timeout,
        )
    except requests.RequestException as exc:
        return JsonResponse({"error": "failed to reach xyn-core", "details": exc.__class__.__name__}, status=502)
    content_type = str(response.headers.get("content-type") or "").lower()
    if "application/json" not in content_type:
        return JsonResponse(
            {"error": "unexpected xyn-core response", "status_code": response.status_code, "response_text": response.text[:800]},
            status=502,
        )
    try:
        payload_json = response.json() if response.content else {}
    except ValueError:
        return JsonResponse({"error": "invalid xyn-core json response"}, status=502)
    if response.status_code >= 400:
        status_code = response.status_code if 400 <= response.status_code <= 599 else 502
        return JsonResponse(payload_json if isinstance(payload_json, dict) else {"error": "xyn-core request failed"}, status=status_code, safe=isinstance(payload_json, dict))
    return JsonResponse(payload_json, safe=not isinstance(payload_json, list), status=response.status_code)


RUNTIME_ACTIVE_STATUSES = {"queued", "running"}
RUNTIME_TERMINAL_STATUSES = {"completed", "failed", "blocked", "cancelled"}


class RuntimeStreamEnvelope(TypedDict):
    event_id: str
    event_type: str
    created_at: str
    workspace_id: Optional[str]
    thread_id: Optional[str]
    run_id: Optional[str]
    work_item_id: Optional[str]
    worker_type: Optional[str]
    status: Optional[str]
    title: str
    message: str
    payload: Dict[str, Any]


def _parse_iso_datetime(value: Any) -> Optional[dt.datetime]:
    if not value:
        return None
    if isinstance(value, dt.datetime):
        return value if value.tzinfo else value.replace(tzinfo=dt.timezone.utc)
    parsed = parse_datetime(str(value))
    if parsed is None:
        return None
    return parsed if parsed.tzinfo else parsed.replace(tzinfo=dt.timezone.utc)


def _runtime_elapsed_seconds(run_payload: Dict[str, Any], *, now: Optional[dt.datetime] = None) -> Optional[int]:
    started_at = _parse_iso_datetime(run_payload.get("started_at"))
    if started_at is None:
        return None
    completed_at = _parse_iso_datetime(run_payload.get("completed_at")) or now or timezone.now()
    return max(0, int((completed_at - started_at).total_seconds()))


def _runtime_heartbeat_freshness(run_payload: Dict[str, Any], *, now: Optional[dt.datetime] = None, stale_after_seconds: int = 30) -> str:
    heartbeat_at = _parse_iso_datetime(run_payload.get("heartbeat_at"))
    if heartbeat_at is None:
        return "missing"
    current = now or timezone.now()
    return "fresh" if (current - heartbeat_at).total_seconds() <= stale_after_seconds else "stale"


def _runtime_run_belongs_to_workspace(run_payload: Dict[str, Any], workspace: Workspace) -> bool:
    prompt_payload = run_payload.get("prompt_payload") if isinstance(run_payload.get("prompt_payload"), dict) else {}
    target = prompt_payload.get("target") if isinstance(prompt_payload.get("target"), dict) else {}
    workspace_id = str(target.get("workspace_id") or "").strip()
    return workspace_id == str(workspace.id)


def _runtime_run_agent_selection_payload(metadata: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    selection = metadata.get("ai_agent_selection") if isinstance(metadata.get("ai_agent_selection"), dict) else {}
    if not selection:
        return None
    purpose = str(selection.get("purpose") or "").strip().lower()
    if not purpose:
        return None
    return {
        "purpose": purpose,
        "routed_agent_id": str(selection.get("routed_agent_id") or "").strip() or None,
        "routed_agent_name": str(selection.get("routed_agent_name") or "").strip() or None,
        "routed_resolution_source": str(selection.get("routed_resolution_source") or "").strip() or None,
        "routed_resolution_label": str(selection.get("routed_resolution_label") or "").strip() or None,
        "effective_agent_id": str(selection.get("effective_agent_id") or "").strip() or None,
        "effective_agent_name": str(selection.get("effective_agent_name") or "").strip() or None,
        "effective_resolution_source": str(selection.get("effective_resolution_source") or "").strip() or None,
        "effective_resolution_label": str(selection.get("effective_resolution_label") or "").strip() or None,
        "override_agent_id": str(selection.get("override_agent_id") or "").strip() or None,
        "override_applied": bool(selection.get("override_applied")),
    }


def _runtime_run_summary_payload(run_payload: Dict[str, Any], *, now: Optional[dt.datetime] = None) -> Dict[str, Any]:
    prompt_payload = run_payload.get("prompt_payload") if isinstance(run_payload.get("prompt_payload"), dict) else {}
    target = prompt_payload.get("target") if isinstance(prompt_payload.get("target"), dict) else {}
    context = prompt_payload.get("context") if isinstance(prompt_payload.get("context"), dict) else {}
    metadata = context.get("metadata") if isinstance(context.get("metadata"), dict) else {}
    return {
        "id": str(run_payload.get("run_id") or run_payload.get("id") or ""),
        "run_id": str(run_payload.get("run_id") or run_payload.get("id") or ""),
        "work_item_id": run_payload.get("work_item_id"),
        "thread_id": str(metadata.get("thread_id") or "") or None,
        "worker_type": run_payload.get("worker_type"),
        "worker_id": run_payload.get("worker_id"),
        "status": str(run_payload.get("status") or ""),
        "summary": run_payload.get("summary"),
        "created_at": run_payload.get("created_at"),
        "started_at": run_payload.get("started_at"),
        "completed_at": run_payload.get("completed_at"),
        "heartbeat_at": run_payload.get("heartbeat_at"),
        "queued_at": run_payload.get("queued_at"),
        "elapsed_time_seconds": _runtime_elapsed_seconds(run_payload, now=now),
        "heartbeat_freshness": _runtime_heartbeat_freshness(run_payload, now=now),
        "target": {
            "repo": target.get("repo"),
            "branch": target.get("branch"),
            "workspace_id": target.get("workspace_id"),
            "artifact_id": target.get("artifact_id"),
        },
        "failure_reason": run_payload.get("failure_reason"),
        "escalation_reason": run_payload.get("escalation_reason"),
        "agent_selection": _runtime_run_agent_selection_payload(metadata),
    }


def _runtime_run_detail_payload(
    run_payload: Dict[str, Any],
    *,
    steps: List[Dict[str, Any]],
    artifacts: List[Dict[str, Any]],
    now: Optional[dt.datetime] = None,
) -> Dict[str, Any]:
    def _step_sort_key(step: Dict[str, Any]) -> Tuple[int, str, str]:
        raw_sequence = step.get("sequence_no")
        try:
            sequence_no = int(raw_sequence)
        except (TypeError, ValueError):
            sequence_no = 10_000
        return (
            sequence_no,
            str(step.get("started_at") or ""),
            str(step.get("step_key") or step.get("name") or ""),
        )

    prompt_payload = run_payload.get("prompt_payload") if isinstance(run_payload.get("prompt_payload"), dict) else {}
    target = prompt_payload.get("target") if isinstance(prompt_payload.get("target"), dict) else {}
    prompt = prompt_payload.get("prompt") if isinstance(prompt_payload.get("prompt"), dict) else {}
    policy = run_payload.get("execution_policy") if isinstance(run_payload.get("execution_policy"), dict) else {}
    return {
        **_runtime_run_summary_payload(run_payload, now=now),
        "prompt": {"title": prompt.get("title"), "body": prompt.get("body")},
        "policy": {
            "auto_continue": bool(policy.get("auto_continue")),
            "max_retries": int(policy.get("max_retries") or 0),
            "require_human_review_on_failure": bool(policy.get("require_human_review_on_failure")),
            "timeout_seconds": policy.get("timeout_seconds"),
        },
        "target": {
            "repo": target.get("repo"),
            "branch": target.get("branch"),
            "workspace_id": target.get("workspace_id"),
            "artifact_id": target.get("artifact_id"),
        },
        "steps": [
            {
                "id": str(step.get("step_id") or step.get("id") or ""),
                "step_key": step.get("step_key") or step.get("name"),
                "label": step.get("label") or step.get("name"),
                "status": step.get("status"),
                "summary": step.get("summary"),
                "sequence_no": step.get("sequence_no"),
                "started_at": step.get("started_at"),
                "completed_at": step.get("completed_at"),
            }
            for step in sorted(steps, key=_step_sort_key)
        ],
        "artifacts": [
            {
                "id": str(artifact.get("artifact_id") or artifact.get("id") or ""),
                "artifact_type": artifact.get("artifact_type") or artifact.get("kind"),
                "label": artifact.get("label") or artifact.get("name"),
                "uri": artifact.get("uri"),
                "created_at": artifact.get("created_at"),
                "metadata": artifact.get("metadata") or {},
            }
            for artifact in artifacts
        ],
    }


def _runtime_activity_item_from_event(event_payload: Dict[str, Any]) -> Dict[str, Any]:
    envelope = _runtime_stream_envelope_from_event(event_payload)
    payload = envelope["payload"] if isinstance(envelope.get("payload"), dict) else {}
    message_type = "system_runtime"
    options: List[str] = []
    if envelope["event_type"] == "run.blocked":
        message_type = "escalation"
        options = ["continue run", "summarize run", "show artifacts"]
    elif envelope["event_type"] == "run.failed":
        message_type = "escalation"
        options = ["retry run", "show logs", "show artifacts"]
    elif envelope["event_type"] == "run.completed":
        message_type = "execution_summary"
    return {
        "id": f"runtime-event:{envelope['event_id']}",
        "event_type": envelope["event_type"],
        "status": "succeeded" if envelope["event_type"] == "run.completed" else "failed" if envelope["event_type"] in {"run.failed", "run.blocked"} else "running",
        "summary": envelope["message"] or envelope["title"],
        "created_at": envelope["created_at"],
        "actor_id": None,
        "agent_slug": envelope.get("worker_type") or "codex_local",
        "provider": "",
        "model_name": "",
        "artifact_id": envelope.get("run_id") or None,
        "artifact_type": "runtime_run",
        "artifact_title": str(payload.get("repo") or ""),
        "request_type": "runtime.run",
        "prompt": "",
        "workspace_id": envelope.get("workspace_id"),
        "thread_id": envelope.get("thread_id"),
        "draft_id": None,
        "job_id": None,
        "error": str(payload.get("failure_reason") or payload.get("escalation_reason") or ""),
        "trace": [],
        "structured_operation": {
            "run_id": envelope.get("run_id"),
            "worker_type": envelope.get("worker_type"),
            "step_key": payload.get("step_key"),
            "artifact_type": payload.get("artifact_type"),
        },
        "conversation_message": {
            "message_type": message_type,
            "title": envelope["title"],
            "body": envelope["message"],
            "status": envelope.get("status"),
            "reason": str(payload.get("failure_reason") or payload.get("escalation_reason") or "") or None,
            "options": options,
            "refs": {
                "run_id": envelope.get("run_id"),
                "work_item_id": envelope.get("work_item_id"),
                "thread_id": envelope.get("thread_id"),
                "step_key": payload.get("step_key"),
                "artifact_type": payload.get("artifact_type"),
                "artifact_uri": payload.get("uri"),
            },
        },
        "source": "runtime_event",
    }


def _conversation_message_from_prompt_activity(meta: Dict[str, Any], *, status: str, summary: str) -> Optional[Dict[str, Any]]:
    interpretation = meta.get("prompt_interpretation") if isinstance(meta.get("prompt_interpretation"), dict) else {}
    action = meta.get("conversation_action") if isinstance(meta.get("conversation_action"), dict) else {}
    if not interpretation and not action:
        return None
    refs = {
        "run_id": (
            str(((meta.get("structured_operation") or {}) if isinstance(meta.get("structured_operation"), dict) else {}).get("run_id") or "")
            or str((((interpretation.get("target_run") or {}) if isinstance(interpretation.get("target_run"), dict) else {}).get("id") or ""))
            or None
        ),
        "work_item_id": (
            str(((meta.get("structured_operation") or {}) if isinstance(meta.get("structured_operation"), dict) else {}).get("work_item_id") or "")
            or str((((interpretation.get("target_work_item") or {}) if isinstance(interpretation.get("target_work_item"), dict) else {}).get("reference") or ""))
            or None
        ),
        "thread_id": str(meta.get("thread_id") or "").strip() or None,
    }
    if str(status or "").strip().lower() == "failed":
        return {
            "message_type": "escalation",
            "title": summary or "Execution blocked",
            "body": str(meta.get("error") or summary or ""),
            "status": "failed",
            "reason": str(meta.get("error") or "") or None,
            "options": (
                [str(option.get("label") or option.get("action") or "").strip() for option in interpretation.get("clarification_options", []) if isinstance(option, dict)]
                if interpretation.get("needs_clarification")
                else ["retry", "show logs", "show artifacts"] if refs.get("run_id") else ["modify prompt", "retry"]
            ),
            "refs": refs,
        }
    return {
        "message_type": "execution_summary",
        "title": summary or "Execution complete",
        "body": summary or "",
        "status": status,
        "reason": None,
        "options": [],
        "refs": refs,
    }


def _runtime_stream_envelope_from_event(event_payload: Dict[str, Any]) -> RuntimeStreamEnvelope:
    event_name = str(event_payload.get("event_name") or "")
    data = event_payload.get("data") if isinstance(event_payload.get("data"), dict) else {}
    run_id = str(event_payload.get("run_id") or data.get("run_id") or "") or None
    created_at = str(event_payload.get("occurred_at") or timezone.now().isoformat())
    failure_reason = str(data.get("failure_reason") or "").strip()
    escalation_reason = str(data.get("escalation_reason") or "").strip()
    label = str(data.get("label") or data.get("step_key") or "").strip()
    if event_name == "run.started":
        status = "running"
        title = f"Run started · {run_id or 'run'}"
        message = title
    elif event_name == "run.step.completed":
        status = "running"
        title = f"Run step completed: {label or 'step'}"
        message = title
    elif event_name == "run.step.started":
        status = "running"
        title = f"Run step started: {label or 'step'}"
        message = title
    elif event_name == "run.completed":
        status = "succeeded"
        title = f"Run completed · {run_id or 'run'}"
        message = title
    elif event_name == "run.blocked":
        status = "failed"
        title = "Run blocked"
        message = f"Run blocked: {escalation_reason or failure_reason or 'review required'}"
    elif event_name == "run.failed":
        status = "failed"
        title = "Run failed"
        message = f"Run failed: {failure_reason or 'unexpected_error'}"
    elif event_name == "run.artifact.created":
        status = "running"
        title = "Run artifact created"
        message = f"Run artifact created: {data.get('artifact_type') or 'artifact'}"
    elif event_name == "run.heartbeat":
        status = "running"
        title = "Run heartbeat"
        message = f"Heartbeat received for {run_id or 'run'}"
    else:
        status = str(data.get("status") or "").strip() or None
        title = event_name or "Runtime event"
        message = title
    return {
        "event_id": str(event_payload.get("event_id") or event_payload.get("id") or ""),
        "event_type": event_name,
        "created_at": created_at,
        "workspace_id": str(data.get("workspace_id") or "") or None,
        "thread_id": str(data.get("thread_id") or "") or None,
        "run_id": run_id,
        "work_item_id": str(data.get("work_item_id") or "") or None,
        "worker_type": str(data.get("worker_type") or "") or None,
        "status": status,
        "title": title,
        "message": message,
        "payload": dict(data),
    }


def _list_runtime_activity_entries(workspace: Workspace, *, limit: int, thread_id: str = "") -> List[Dict[str, Any]]:
    try:
        response = _seed_api_request(
            method="GET",
            path="/api/v1/events",
            workspace_slug="",
            payload=None,
            timeout=15,
        )
    except requests.RequestException:
        return []
    if response.status_code >= 400:
        return []
    try:
        payload = response.json() if response.content else {}
    except ValueError:
        return []
    items = payload.get("items") if isinstance(payload, dict) else []
    if not isinstance(items, list):
        return []
    activity_items: List[Dict[str, Any]] = []
    for event_payload in items:
        if not isinstance(event_payload, dict):
            continue
        event_name = str(event_payload.get("event_name") or "")
        if not event_name.startswith("run."):
            continue
        data = event_payload.get("data") if isinstance(event_payload.get("data"), dict) else {}
        if str(data.get("workspace_id") or "") != str(workspace.id):
            continue
        if thread_id and str(data.get("thread_id") or "") != thread_id:
            continue
        activity_items.append(_runtime_activity_item_from_event(event_payload))
        if len(activity_items) >= limit:
            break
    return activity_items


def _coordination_activity_item_from_event(event: CoordinationEvent) -> Dict[str, Any]:
    payload = event.payload_json if isinstance(event.payload_json, dict) else {}
    summary = str(payload.get("reason") or payload.get("status") or event.event_type.replace("_", " ")).strip()
    refs = {
        "thread_id": str(event.thread_id),
        "work_item_id": str(event.work_item.work_item_id or event.work_item_id) if event.work_item_id else None,
        "run_id": str(event.run_id) if event.run_id else None,
    }
    if event.event_type in {"thread_paused", "thread_completed"}:
        message_type = "execution_summary"
        status = "failed" if event.event_type == "thread_paused" else "succeeded"
    else:
        message_type = "system_runtime"
        status = "running"
    return {
        "id": f"coordination-event:{event.id}",
        "event_type": event.event_type,
        "status": status,
        "summary": summary or event.event_type.replace("_", " "),
        "created_at": event.created_at,
        "actor_id": None,
        "agent_slug": "xco",
        "provider": "",
        "model_name": "",
        "artifact_id": str(event.thread_id),
        "artifact_type": "coordination_thread",
        "artifact_title": str(event.thread.title or ""),
        "request_type": "xco.event",
        "prompt": "",
        "workspace_id": str(event.thread.workspace_id),
        "thread_id": str(event.thread.source_conversation_id or "") or None,
        "draft_id": None,
        "job_id": None,
        "error": "",
        "trace": [],
        "structured_operation": {
            "thread_id": str(event.thread_id),
            "work_item_id": refs["work_item_id"],
            "run_id": refs["run_id"],
        },
        "conversation_message": {
            "message_type": message_type,
            "title": str(event.thread.title or "Thread"),
            "body": summary or event.event_type.replace("_", " "),
            "status": status,
            "reason": str(payload.get("reason") or "") or None,
            "options": [],
            "refs": refs,
        },
        "source": "coordination_event",
    }


def _runtime_stream_query(workspace: Workspace, *, last_event_id: str = "", since: str = "") -> Dict[str, str]:
    params = {
        "workspace_id": str(workspace.id),
        "runtime_only": "true",
    }
    if last_event_id:
        params["last_event_id"] = last_event_id
    if since:
        params["since"] = since
    return params


def _seed_runtime_stream_request(*, workspace: Workspace, last_event_id: str = "", since: str = ""):
    base_url = _seed_api_base_url()
    response = requests.get(
        f"{base_url}/api/v1/events/stream",
        params=_runtime_stream_query(workspace, last_event_id=last_event_id, since=since),
        timeout=(5, 65),
        stream=True,
        headers={"Accept": "text/event-stream"},
    )
    response.raise_for_status()
    return response


def _iter_sse_messages(response) -> Any:
    event_name = ""
    event_id = ""
    data_lines: List[str] = []
    for raw_line in response.iter_lines(decode_unicode=True):
        if raw_line is None:
            continue
        line = str(raw_line)
        if not line:
            if data_lines:
                payload_text = "\n".join(data_lines)
                try:
                    payload = json.loads(payload_text)
                except ValueError:
                    payload = {}
                if isinstance(payload, dict):
                    if event_id and "id" not in payload:
                        payload["id"] = event_id
                    yield {"event": event_name or payload.get("event_name") or "message", "id": event_id, "data": payload}
            event_name = ""
            event_id = ""
            data_lines = []
            continue
        if line.startswith(":"):
            continue
        if line.startswith("event:"):
            event_name = line.split(":", 1)[1].strip()
            continue
        if line.startswith("id:"):
            event_id = line.split(":", 1)[1].strip()
            continue
        if line.startswith("data:"):
            data_lines.append(line.split(":", 1)[1].lstrip())


def _serialize_runtime_stream_sse(envelope: RuntimeStreamEnvelope) -> str:
    return (
        f"id: {envelope['event_id']}\n"
        f"event: {envelope['event_type']}\n"
        f"data: {json.dumps(envelope, default=str)}\n\n"
    )

def _normalize_palette_prompt(prompt: str) -> str:
    key = re.sub(r"\s+", " ", str(prompt or "").strip().lower())
    if key.startswith("create location"):
        return "create location"
    if key.startswith("create device"):
        return "create device"
    return key


def _looks_like_generated_crud_prompt(prompt: str) -> bool:
    text = str(prompt or "").strip().lower()
    if not text:
        return False
    return bool(
        re.search(
            r"\b(show|list|create|add|update|change|rename|delete|remove)\b.*\b(device|devices|location|locations|interface|interfaces)\b",
            text,
        )
    )


def _should_use_legacy_intake_fallback(prompt: str, *, context_artifact: Optional[Artifact]) -> bool:
    if context_artifact is not None:
        return True
    text = re.sub(r"\s+", " ", str(prompt or "").strip().lower())
    if not text:
        return False
    if re.search(r"\b(create|make|start|new)\s+draft\b", text):
        return True
    if re.search(r"^(show options|what categories|what formats|available categories|available formats)\b", text):
        return True
    if "context pack" in text and re.search(r"\b(add|set|update|rewrite|change|edit|patch)\b", text):
        return True
    return bool(
        re.search(
            r"\b(create|make|start|new|draft|write|build)\b.*\b(article|guide|tour|explainer|video)\b",
            text,
        )
    )


def _workspace_has_installed_artifact_slug(workspace: Workspace, artifact_slug: str) -> bool:
    return WorkspaceArtifactBinding.objects.filter(
        workspace=workspace,
        enabled=True,
        installed_state="installed",
        artifact__slug=artifact_slug,
    ).exists()


def _workspace_runtime_instance(workspace: Workspace, app_slug: str) -> Optional[WorkspaceAppInstance]:
    return (
        WorkspaceAppInstance.objects.filter(workspace=workspace, app_slug=app_slug, status="active")
        .exclude(dns_config_json={})
        .order_by("-updated_at", "-created_at")
        .first()
    )


def _workspace_runtime_target(workspace: Workspace, app_slug: str) -> Optional[Dict[str, Any]]:
    instance = _workspace_runtime_instance(workspace, app_slug)
    if not instance or not isinstance(instance.dns_config_json, dict):
        return None
    runtime_target = instance.dns_config_json.get("runtime_target")
    if not isinstance(runtime_target, dict):
        return None
    if str(runtime_target.get("runtime_owner") or "").strip().lower() != "sibling":
        return None
    base_url = str(runtime_target.get("runtime_base_url") or "").strip().rstrip("/")
    if not base_url:
        return None
    return {
        "instance": instance,
        "runtime_target": runtime_target,
        "runtime_base_url": base_url,
    }


def _installed_generated_artifact(workspace: Workspace, app_slug: str) -> Optional[Artifact]:
    artifact_slug = f"app.{app_slug}"
    binding = (
        WorkspaceArtifactBinding.objects.filter(
            workspace=workspace,
            enabled=True,
            installed_state="installed",
            artifact__slug=artifact_slug,
        )
        .select_related("artifact", "artifact__type")
        .order_by("-updated_at", "-created_at")
        .first()
    )
    return binding.artifact if binding and binding.artifact else None


def _generated_artifact_contract_issue(artifact: Optional[Artifact], resolved: Optional[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
    if not artifact:
        return None
    artifact_slug = str(getattr(artifact, "slug", "") or "").strip()
    if not artifact_slug.startswith("app."):
        return None
    manifest = resolved if isinstance(resolved, dict) else {}
    if str(manifest.get("schema_version") or "").strip() != "xyn.capability_manifest.v1":
        return {
            "status": "invalid",
            "reason": "missing_capability_manifest_v1",
            "artifact_slug": artifact_slug,
            "artifact_id": str(artifact.id),
        }
    entities = manifest.get("entities") if isinstance(manifest.get("entities"), list) else []
    if not entities:
        return {
            "status": "invalid",
            "reason": "missing_entity_contracts",
            "artifact_slug": artifact_slug,
            "artifact_id": str(artifact.id),
        }
    return None


def _workspace_generated_artifact_state(workspace: Workspace, app_slug: str) -> Dict[str, Any]:
    artifact = _installed_generated_artifact(workspace, app_slug)
    if not artifact:
        return {"artifact": None, "manifest": None, "issue": None}
    manifest = _load_artifact_manifest(artifact)
    resolved = _resolved_capability_manifest(manifest)
    return {
        "artifact": artifact,
        "manifest": resolved or None,
        "issue": _generated_artifact_contract_issue(artifact, resolved),
    }


def _workspace_installed_capability_manifest(workspace: Workspace, app_slug: str) -> Optional[Dict[str, Any]]:
    state = _workspace_generated_artifact_state(workspace, app_slug)
    if state.get("issue"):
        return None
    manifest = state.get("manifest")
    return manifest if isinstance(manifest, dict) else None


def _workspace_generated_artifact_issue(workspace: Workspace, app_slug: str) -> Optional[Dict[str, Any]]:
    state = _workspace_generated_artifact_state(workspace, app_slug)
    issue = state.get("issue")
    return copy.deepcopy(issue) if isinstance(issue, dict) else None


def _manifest_command_entry(manifest: Dict[str, Any], prompt: str) -> Optional[Dict[str, Any]]:
    command_key = _normalize_palette_prompt(prompt)
    commands = manifest.get("commands") if isinstance(manifest.get("commands"), list) else []
    for command in commands:
        if not isinstance(command, dict):
            continue
        entry_key = _normalize_palette_prompt(str(command.get("key") or command.get("prompt") or ""))
        if entry_key == command_key:
            return command
    return None


def _manifest_latent_command_keys(manifest: Dict[str, Any]) -> set[str]:
    diagnostics = manifest.get("diagnostics") if isinstance(manifest.get("diagnostics"), dict) else {}
    rows = diagnostics.get("latent_commands") if isinstance(diagnostics.get("latent_commands"), list) else []
    keys: set[str] = set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        key = _normalize_palette_prompt(str(row.get("key") or row.get("prompt") or ""))
        if key:
            keys.add(key)
    return keys


def _manifest_entity_contracts(manifest: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    rows = manifest.get("entities") if isinstance(manifest.get("entities"), list) else []
    return {
        str(row.get("key") or "").strip(): row
        for row in rows
        if isinstance(row, dict) and str(row.get("key") or "").strip()
    }


def _entity_operation_declared(contract: Dict[str, Any], operation: str) -> bool:
    operations = contract.get("operations") if isinstance(contract.get("operations"), dict) else {}
    spec = operations.get(operation) if isinstance(operations.get(operation), dict) else {}
    return bool(spec.get("declared"))


def _entity_field_map(contract: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    rows = contract.get("fields") if isinstance(contract.get("fields"), list) else []
    return {
        str(row.get("name") or "").strip(): row
        for row in rows
        if isinstance(row, dict) and str(row.get("name") or "").strip()
    }


def _entity_title_field(contract: Dict[str, Any]) -> str:
    presentation = contract.get("presentation") if isinstance(contract.get("presentation"), dict) else {}
    return str(presentation.get("title_field") or "").strip()


def _entity_required_create_fields(contract: Dict[str, Any]) -> List[str]:
    validation = contract.get("validation") if isinstance(contract.get("validation"), dict) else {}
    return [
        str(field).strip()
        for field in (validation.get("required_on_create") if isinstance(validation.get("required_on_create"), list) else [])
        if str(field).strip() and str(field).strip() != "workspace_id"
    ]


def _entity_allowed_update_fields(contract: Dict[str, Any]) -> List[str]:
    validation = contract.get("validation") if isinstance(contract.get("validation"), dict) else {}
    return [str(field).strip() for field in (validation.get("allowed_on_update") if isinstance(validation.get("allowed_on_update"), list) else []) if str(field).strip()]


def _should_use_direct_generated_target_reference(target_reference: str) -> bool:
    token = str(target_reference or "").strip()
    if not token:
        return False
    if re.match(r"^[0-9a-fA-F-]{32,36}$", token):
        return True
    return bool(re.search(r"[-._]|\\d", token))


def _entity_table_columns(contract: Dict[str, Any], *, detail: bool) -> List[str]:
    presentation = contract.get("presentation") if isinstance(contract.get("presentation"), dict) else {}
    preferred = presentation.get("default_detail_fields" if detail else "default_list_fields")
    preferred_rows = preferred if isinstance(preferred, list) else []
    columns: List[str] = []
    field_names = set(_entity_field_map(contract))
    if "id" in field_names:
        columns.append("id")
    for item in preferred_rows:
        token = str(item or "").strip()
        if token and token in field_names and token not in columns:
            columns.append(token)
    return columns or ["id", _entity_title_field(contract) or "name"]


def _entity_field_aliases(contract: Dict[str, Any]) -> Dict[str, str]:
    aliases: Dict[str, str] = {}
    for name in _entity_field_map(contract):
        aliases[name.casefold()] = name
        if name.endswith("_id"):
            aliases[name[:-3].casefold()] = name
    for name in _entity_allowed_update_fields(contract):
        aliases.setdefault(name.casefold(), name)
        if name.endswith("_id"):
            aliases.setdefault(name[:-3].casefold(), name)
    title_field = _entity_title_field(contract)
    if title_field:
        aliases["title"] = title_field
    return aliases


def _generated_structured_missing_response(
    *,
    operation: str,
    entity_label: str,
    missing_fields: List[str],
    example: str,
    target_required: bool = False,
) -> Dict[str, Any]:
    lines = [f"To {operation} {entity_label}, provide:"]
    if target_required:
        lines.append("- record reference")
    for field in missing_fields:
        lines.append(f"- {field}")
    lines.append(f"Example: {example}")
    return {
        "kind": "text",
        "columns": [],
        "rows": [],
        "text": "\n".join(lines),
        "meta": {
            "operation": operation,
            "entity": entity_label,
            "missing_fields": missing_fields,
            "target_required": target_required,
        },
    }


def _parse_generated_create_fields(contract: Dict[str, Any], remainder: str) -> Tuple[Dict[str, Any], List[str]]:
    rest = str(remainder or "").strip()
    lowered = rest.lower()
    for prefix in ("named ", "called "):
        if lowered.startswith(prefix):
            rest = rest[len(prefix) :].strip()
            lowered = rest.lower()
            break
    title_field = _entity_title_field(contract) or "name"
    field_map = _entity_field_map(contract)
    fields: Dict[str, Any] = {}
    geo_fields = {
        key: key
        for key in ("city", "region", "country")
        if key in field_map and bool((field_map.get(key) or {}).get("writable"))
    }
    relation_fields = [
        name
        for name, field in field_map.items()
        if (
            isinstance(field.get("relation"), dict)
            and bool(field.get("writable"))
            and str(((field.get("relation") if isinstance(field.get("relation"), dict) else {}) or {}).get("target_entity") or "").strip()
            != str(contract.get("key") or "").strip()
        )
    ]
    relation_field = relation_fields[0] if len(relation_fields) == 1 else ""
    for relation_token in (" in ", " at "):
        if relation_token in rest.lower():
            split = re.split(rf"\s+{relation_token.strip()}\s+", rest, maxsplit=1, flags=re.IGNORECASE)
            if len(split) == 2:
                rest, suffix_ref = split[0].strip(), split[1].strip()
                if suffix_ref and geo_fields.get("city"):
                    tokens = [token.strip(", ") for token in suffix_ref.split() if token.strip(", ")]
                    if geo_fields.get("country") and geo_fields.get("region") and len(tokens) >= 3 and len(tokens[-1]) >= 2 and len(tokens[-2]) <= 3:
                        fields[geo_fields["country"]] = tokens[-1]
                        fields[geo_fields["region"]] = tokens[-2]
                        fields[geo_fields["city"]] = " ".join(tokens[:-2]).strip()
                    else:
                        fields[geo_fields["city"]] = suffix_ref
                elif relation_field and suffix_ref:
                    fields[relation_field] = suffix_ref
                break
    if rest:
        fields[title_field] = rest
    missing = [field for field in _entity_required_create_fields(contract) if not str(fields.get(field) or "").strip()]
    return fields, missing


def _parse_generated_update_fields(contract: Dict[str, Any], remainder: str) -> Tuple[str, Dict[str, Any], List[str], bool]:
    rest = str(remainder or "").strip()
    if not rest:
        return "", {}, [], True
    rename_match = re.match(r"^(?P<target>\S+)\s+to\s+(?P<value>.+)$", rest, flags=re.IGNORECASE)
    if rename_match:
        title_field = _entity_title_field(contract) or "name"
        return (
            str(rename_match.group("target") or "").strip(),
            {title_field: str(rename_match.group("value") or "").strip()},
            [],
            False,
        )
    if rest.lower().startswith("set "):
        rest = rest[4:].strip()
    parts = rest.split(None, 2)
    if len(parts) < 2:
        return str(parts[0] or "").strip() if parts else "", {}, [], True
    target_reference = str(parts[0] or "").strip()
    field_alias = str(parts[1] or "").strip().casefold()
    value = str(parts[2] or "").strip() if len(parts) > 2 else ""
    aliases = _entity_field_aliases(contract)
    field_name = aliases.get(field_alias)
    allowed = set(_entity_allowed_update_fields(contract))
    if not field_name or field_name not in allowed:
        return target_reference, {}, [f"one of: {', '.join(sorted(allowed))}"], False
    if not value:
        return target_reference, {}, [field_name], False
    return target_reference, {field_name: value}, [], False


def _resolve_generated_entity_operation(prompt: str, capability_manifest: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    raw = str(prompt or "").strip()
    if not raw:
        return None
    normalized_source = re.sub(
        r"^\s*(please\s+|i\s+(?:want|need|would\s+like)\s+to\s+|can\s+you\s+|could\s+you\s+)",
        "",
        raw,
        flags=re.IGNORECASE,
    ).strip()
    entities = _manifest_entity_contracts(capability_manifest)
    explicit_entity_operation_requested = False
    for entity_key, contract in entities.items():
        singular = str(contract.get("singular_label") or entity_key.rstrip("s")).strip()
        plural = str(contract.get("plural_label") or entity_key).strip()
        singular_pattern = re.escape(singular)
        plural_pattern = re.escape(plural)
        if _entity_operation_declared(contract, "list") and re.match(rf"^\s*(show|list)\s+{plural_pattern}\s*$", normalized_source, flags=re.IGNORECASE):
            return {"operation": "list", "entity_key": entity_key, "contract": contract, "command_key": f"show {plural}"}
        create_match = re.match(rf"^\s*(create|add)\s+(?:a|an)?\s*{singular_pattern}\b(?P<rest>.*)$", normalized_source, flags=re.IGNORECASE)
        if create_match:
            explicit_entity_operation_requested = True
            if _entity_operation_declared(contract, "create"):
                fields, missing = _parse_generated_create_fields(contract, str(create_match.group("rest") or ""))
                example = f"create {singular} named demo-{singular}"
                return {
                    "operation": "create",
                    "entity_key": entity_key,
                    "contract": contract,
                    "command_key": f"create {singular}",
                    "fields": fields,
                    "missing_fields": missing,
                    "example": example,
                }
        delete_match = re.match(rf"^\s*(delete|remove)\s+{singular_pattern}\s+(?P<target>.+?)\s*$", normalized_source, flags=re.IGNORECASE)
        if delete_match:
            explicit_entity_operation_requested = True
            if _entity_operation_declared(contract, "delete"):
                return {
                    "operation": "delete",
                    "entity_key": entity_key,
                    "contract": contract,
                    "command_key": f"delete {singular}",
                    "target_reference": str(delete_match.group("target") or "").strip(),
                    "direct_target_reference": _should_use_direct_generated_target_reference(str(delete_match.group("target") or "").strip()),
                }
        rename_match = re.match(rf"^\s*rename\s+{singular_pattern}\s+(?P<target>\S+)\s+to\s+(?P<value>.+?)\s*$", normalized_source, flags=re.IGNORECASE)
        if rename_match:
            explicit_entity_operation_requested = True
            if _entity_operation_declared(contract, "update"):
                title_field = _entity_title_field(contract) or "name"
                return {
                    "operation": "update",
                    "entity_key": entity_key,
                    "contract": contract,
                    "command_key": f"update {singular}",
                    "target_reference": str(rename_match.group("target") or "").strip(),
                    "field_mutations": {title_field: str(rename_match.group("value") or "").strip()},
                    "direct_target_reference": True,
                    "example": f"rename {singular} old-name to new-name",
                }
        update_match = re.match(rf"^\s*(update|change)\s+{singular_pattern}\b(?P<rest>.*)$", normalized_source, flags=re.IGNORECASE)
        if update_match:
            explicit_entity_operation_requested = True
            if _entity_operation_declared(contract, "update"):
                target_reference, mutations, missing, target_required = _parse_generated_update_fields(contract, str(update_match.group("rest") or ""))
                return {
                    "operation": "update",
                    "entity_key": entity_key,
                    "contract": contract,
                    "command_key": f"update {singular}",
                    "target_reference": target_reference,
                    "field_mutations": mutations,
                    "missing_fields": missing,
                    "target_required": target_required or not target_reference,
                    "direct_target_reference": _should_use_direct_generated_target_reference(target_reference),
                    "example": f"update {singular} demo-{singular} status offline",
                }
    if explicit_entity_operation_requested:
        return None
    target_change_match = re.match(r"^\s*(change|update)\s+(?P<target>\S+)\s+to\s+(?P<value>.+?)\s*$", normalized_source, flags=re.IGNORECASE)
    if target_change_match:
        target_reference = str(target_change_match.group("target") or "").strip()
        value = str(target_change_match.group("value") or "").strip()
        candidates = [
            (entity_key, contract)
            for entity_key, contract in entities.items()
            if _entity_operation_declared(contract, "update") and "status" in set(_entity_allowed_update_fields(contract))
        ]
        if len(candidates) == 1:
            entity_key, contract = candidates[0]
            singular = str(contract.get("singular_label") or entity_key.rstrip("s")).strip()
            return {
                "operation": "update",
                "entity_key": entity_key,
                "contract": contract,
                "command_key": f"update {singular}",
                "target_reference": target_reference,
                "field_mutations": {"status": value},
                "example": f"update {singular} {target_reference} status {value}",
            }
    return None


def _resolve_generated_entity_operation_with_runtime(
    *,
    prompt: str,
    capability_manifest: Dict[str, Any],
    runtime_base_url: str,
    workspace: Workspace,
) -> Optional[Dict[str, Any]]:
    structured = _resolve_generated_entity_operation(prompt, capability_manifest)
    if structured:
        return structured
    raw = str(prompt or "").strip()
    if not raw:
        return None
    normalized_source = re.sub(
        r"^\s*(please\s+|i\s+(?:want|need|would\s+like)\s+to\s+|can\s+you\s+|could\s+you\s+)",
        "",
        raw,
        flags=re.IGNORECASE,
    ).strip()
    entities = _manifest_entity_contracts(capability_manifest)
    target_change_match = re.match(r"^\s*(change|update)\s+(?P<target>\S+)\s+to\s+(?P<value>.+?)\s*$", normalized_source, flags=re.IGNORECASE)
    if target_change_match:
        target_reference = str(target_change_match.group("target") or "").strip()
        value = str(target_change_match.group("value") or "").strip()
        update_candidates = [
            (entity_key, contract)
            for entity_key, contract in entities.items()
            if _entity_operation_declared(contract, "update") and "status" in set(_entity_allowed_update_fields(contract))
        ]
        if len(update_candidates) > 1:
            for entity_key, contract in update_candidates:
                resolution = _resolve_generated_entity_reference(
                    contract=contract,
                    target_reference=target_reference,
                    runtime_base_url=runtime_base_url,
                    workspace=workspace,
                )
                if resolution.get("status") == "resolved":
                    singular = str(contract.get("singular_label") or entity_key.rstrip("s")).strip()
                    return {
                        "operation": "update",
                        "entity_key": entity_key,
                        "contract": contract,
                        "command_key": f"update {singular}",
                        "target_reference": target_reference,
                        "field_mutations": {"status": value},
                        "example": f"update {singular} {target_reference} status {value}",
                    }
    rename_match = re.match(r"^\s*rename\s+(?P<target>\S+)\s+to\s+(?P<value>.+?)\s*$", normalized_source, flags=re.IGNORECASE)
    if rename_match:
        target_reference = str(rename_match.group("target") or "").strip()
        value = str(rename_match.group("value") or "").strip()
        update_candidates = [
            (entity_key, contract)
            for entity_key, contract in entities.items()
            if _entity_operation_declared(contract, "update")
            and (_entity_title_field(contract) or "name") in set(_entity_allowed_update_fields(contract))
        ]
        if len(update_candidates) <= 1:
            return None
        for entity_key, contract in update_candidates:
            title_field = _entity_title_field(contract) or "name"
            resolution = _resolve_generated_entity_reference(
                contract=contract,
                target_reference=target_reference,
                runtime_base_url=runtime_base_url,
                workspace=workspace,
            )
            if resolution.get("status") == "resolved":
                singular = str(contract.get("singular_label") or entity_key.rstrip("s")).strip()
                return {
                    "operation": "update",
                    "entity_key": entity_key,
                    "contract": contract,
                    "command_key": f"update {singular}",
                    "target_reference": target_reference,
                    "field_mutations": {title_field: value},
                    "example": f"rename {singular} old-name to new-name",
                }
    bare_delete_match = re.match(r"^\s*(delete|remove)\s+(?P<target>.+?)\s*$", normalized_source, flags=re.IGNORECASE)
    if bare_delete_match:
        target_reference = str(bare_delete_match.group("target") or "").strip()
        delete_candidates = [
            (entity_key, contract)
            for entity_key, contract in entities.items()
            if _entity_operation_declared(contract, "delete")
        ]
        if len(delete_candidates) <= 1:
            return None
        for entity_key, contract in delete_candidates:
            resolution = _resolve_generated_entity_reference(
                contract=contract,
                target_reference=target_reference,
                runtime_base_url=runtime_base_url,
                workspace=workspace,
            )
            if resolution.get("status") == "resolved":
                singular = str(contract.get("singular_label") or entity_key.rstrip("s")).strip()
                return {
                    "operation": "delete",
                    "entity_key": entity_key,
                    "contract": contract,
                    "command_key": f"delete {singular}",
                    "target_reference": target_reference,
                }
    return None


def _generated_entity_operation_path(contract: Dict[str, Any], operation: str, *, target_reference: str = "") -> str:
    operations = contract.get("operations") if isinstance(contract.get("operations"), dict) else {}
    spec = operations.get(operation) if isinstance(operations.get(operation), dict) else {}
    path = str(spec.get("path") or "").strip()
    if operation in {"update", "delete", "get"} and "{id}" in path:
        return path.replace("{id}", quote(str(target_reference or "").strip(), safe=""))
    return path


def _normalized_generated_operation(structured: Dict[str, Any]) -> Dict[str, Any]:
    payload: Dict[str, Any] = {
        "operation": str(structured.get("operation") or "").strip(),
        "entity_key": str(structured.get("entity_key") or "").strip(),
        "command_key": str(structured.get("command_key") or "").strip(),
    }
    if str(structured.get("target_reference") or "").strip():
        payload["target_reference"] = str(structured.get("target_reference") or "").strip()
    if isinstance(structured.get("fields"), dict) and structured.get("fields"):
        payload["fields"] = structured.get("fields")
    if isinstance(structured.get("field_mutations"), dict) and structured.get("field_mutations"):
        payload["field_mutations"] = structured.get("field_mutations")
    if structured.get("direct_target_reference"):
        payload["direct_target_reference"] = True
    return payload


def _generated_trace_step(step: str, **kwargs: Any) -> Dict[str, Any]:
    row: Dict[str, Any] = {"step": step}
    for key, value in kwargs.items():
        if value is None:
            continue
        row[key] = value
    return row


def _list_generated_entity_records(
    *,
    contract: Dict[str, Any],
    runtime_base_url: str,
    workspace: Workspace,
) -> List[Dict[str, Any]]:
    response = _runtime_target_request(
        base_url=runtime_base_url,
        method="GET",
        path=str(contract.get("collection_path") or "").strip() or _generated_entity_operation_path(contract, "list"),
        query={"workspace_id": str(workspace.id)},
        timeout=20,
    )
    content_type = str(response.headers.get("content-type") or "").lower()
    if "application/json" not in content_type:
        raise RuntimeError(f"generated-app runtime returned non-json content ({response.status_code})")
    body = response.json() if response.content else {}
    if response.status_code >= 400:
        detail = body.get("detail") if isinstance(body, dict) else ""
        raise RuntimeError(f"generated-app runtime request failed ({response.status_code}): {detail or body}")
    items = body.get("items") if isinstance(body, dict) and isinstance(body.get("items"), list) else body
    return [item for item in items if isinstance(item, dict)] if isinstance(items, list) else []


def _record_identity_values(contract: Dict[str, Any], record: Dict[str, Any]) -> List[str]:
    values: List[str] = []
    if str(record.get("id") or "").strip():
        values.append(str(record.get("id") or "").strip())
    for name, field in _entity_field_map(contract).items():
        if not bool(field.get("identity")):
            continue
        value = record.get(name)
        if value is None:
            continue
        token = str(value).strip()
        if token and token not in values:
            values.append(token)
    return values


def _resolve_generated_entity_reference(
    *,
    contract: Dict[str, Any],
    target_reference: str,
    runtime_base_url: str,
    workspace: Workspace,
) -> Dict[str, Any]:
    reference = str(target_reference or "").strip()
    if not reference:
        return {"status": "missing"}
    records = _list_generated_entity_records(contract=contract, runtime_base_url=runtime_base_url, workspace=workspace)
    lowered_reference = reference.casefold()
    title_field = _entity_title_field(contract)
    title_exact_matches = []
    if title_field:
        title_exact_matches = [
            record
            for record in records
            if str(record.get(title_field) or "").strip().casefold() == lowered_reference
        ]
    if len(title_exact_matches) == 1:
        return {"status": "resolved", "record": title_exact_matches[0], "match_type": "title_exact"}
    if len(title_exact_matches) > 1:
        return {"status": "ambiguous", "matches": title_exact_matches, "match_type": "title_exact"}
    exact_matches = [
        record
        for record in records
        if any(candidate.casefold() == lowered_reference for candidate in _record_identity_values(contract, record))
    ]
    if len(exact_matches) == 1:
        return {"status": "resolved", "record": exact_matches[0], "match_type": "exact"}
    if len(exact_matches) > 1:
        return {"status": "ambiguous", "matches": exact_matches, "match_type": "exact"}
    title_partial_matches = []
    if title_field:
        title_partial_matches = [
            record
            for record in records
            if lowered_reference in str(record.get(title_field) or "").strip().casefold()
        ]
    if len(title_partial_matches) == 1:
        return {"status": "resolved", "record": title_partial_matches[0], "match_type": "title_partial"}
    if len(title_partial_matches) > 1:
        return {"status": "ambiguous", "matches": title_partial_matches, "match_type": "title_partial"}
    partial_matches = [
        record
        for record in records
        if any(lowered_reference in candidate.casefold() for candidate in _record_identity_values(contract, record))
    ]
    if len(partial_matches) == 1:
        return {"status": "resolved", "record": partial_matches[0], "match_type": "partial"}
    if len(partial_matches) > 1:
        return {"status": "ambiguous", "matches": partial_matches, "match_type": "partial"}
    return {"status": "not_found", "reference": reference}


def _generated_disambiguation_response(
    *,
    contract: Dict[str, Any],
    operation: str,
    target_reference: str,
    matches: List[Dict[str, Any]],
) -> Dict[str, Any]:
    singular = str(contract.get("singular_label") or contract.get("key") or "record").strip() or "record"
    title_field = _entity_title_field(contract) or "name"
    labels = [str(row.get(title_field) or row.get("id") or "").strip() for row in matches if isinstance(row, dict)]
    verb = {
        "delete": "deleted",
        "update": "updated",
        "get": "shown",
        "linked": "linked",
    }.get(operation, f"{operation}d")
    lines = [f"Multiple matches found for {singular} \"{target_reference}\":"] + [f"- {label}" for label in labels if label]
    lines.append(f"Which {singular} should be {verb}?")
    return {
        "kind": "text",
        "columns": [],
        "rows": [],
        "text": "\n".join(lines),
        "meta": {
            "disambiguation": {
                "operation": operation,
                "entity_key": str(contract.get("key") or "").strip(),
                "target_reference": target_reference,
                "matches": labels,
            }
        },
    }


def _resolve_generated_relation_fields(
    *,
    contract: Dict[str, Any],
    payload_fields: Dict[str, Any],
    capability_manifest: Dict[str, Any],
    runtime_base_url: str,
    workspace: Workspace,
    trace: List[Dict[str, Any]],
) -> Tuple[Optional[Dict[str, Any]], Dict[str, Any]]:
    resolved_fields = dict(payload_fields)
    entities = _manifest_entity_contracts(capability_manifest)
    for field_name, field in _entity_field_map(contract).items():
        relation = field.get("relation") if isinstance(field.get("relation"), dict) else {}
        if not relation or field_name not in resolved_fields:
            continue
        raw_value = resolved_fields.get(field_name)
        if raw_value is None:
            continue
        token = str(raw_value).strip()
        if not token or re.match(r"^[0-9a-fA-F-]{32,36}$", token):
            continue
        target_contract = entities.get(str(relation.get("target_entity") or "").strip())
        if not target_contract:
            continue
        resolution = _resolve_generated_entity_reference(
            contract=target_contract,
            target_reference=token,
            runtime_base_url=runtime_base_url,
            workspace=workspace,
        )
        trace.append(
            _generated_trace_step(
                "relationship_resolution",
                source_entity=str(contract.get("key") or "").strip(),
                field=field_name,
                target_entity=str(target_contract.get("key") or "").strip(),
                input=token,
                status=str(resolution.get("status") or ""),
            )
        )
        if resolution.get("status") == "resolved":
            resolved_fields[field_name] = str(((resolution.get("record") or {}).get("id")) or token)
            continue
        if resolution.get("status") == "ambiguous":
            return (
                _generated_disambiguation_response(
                    contract=target_contract,
                    operation="linked",
                    target_reference=token,
                    matches=resolution.get("matches") if isinstance(resolution.get("matches"), list) else [],
                ),
                resolved_fields,
            )
        return (
            {
                "kind": "text",
                "columns": [],
                "rows": [],
                "text": f'No matching {str(target_contract.get("singular_label") or target_contract.get("key") or "record")} found for "{token}".',
                "meta": {
                    "relation_resolution_error": {
                        "field": field_name,
                        "target_entity": str(target_contract.get("key") or "").strip(),
                        "target_reference": token,
                    }
                },
            },
            resolved_fields,
        )
    return None, resolved_fields


def _generated_entity_result(
    *,
    contract: Dict[str, Any],
    operation: str,
    payload: Any,
    target_reference: str = "",
) -> Dict[str, Any]:
    singular = str(contract.get("singular_label") or contract.get("key") or "record").strip() or "record"
    plural = str(contract.get("plural_label") or singular + "s").strip() or (singular + "s")
    if operation == "list":
        if isinstance(payload, list):
            items = [row for row in payload if isinstance(row, dict)]
        elif isinstance(payload, dict) and isinstance(payload.get("items"), list):
            items = [row for row in payload.get("items") if isinstance(row, dict)]
        else:
            items = []
        return {
            "kind": "table",
            "columns": _entity_table_columns(contract, detail=False),
            "rows": items,
            "text": f"Found {len(items)} {plural}.",
        }
    if operation == "delete":
        item = payload.get("item") if isinstance(payload, dict) and isinstance(payload.get("item"), dict) else {}
        display = str(item.get(_entity_title_field(contract) or "name") or target_reference or "record").strip()
        return {
            "kind": "table",
            "columns": _entity_table_columns(contract, detail=True),
            "rows": [item] if item else [],
            "text": f"Deleted 1 {singular}: {display}",
        }
    item = payload if isinstance(payload, dict) else {}
    display = str(item.get(_entity_title_field(contract) or "name") or target_reference or singular).strip()
    return {
        "kind": "table",
        "columns": _entity_table_columns(contract, detail=True),
        "rows": [item] if item else [],
        "text": {
            "create": f"Created 1 {singular}: {display}",
            "update": f"Updated 1 {singular}: {display}",
            "get": f"Found 1 {singular}: {display}",
        }.get(operation, f"Completed {operation} for {singular}: {display}"),
    }


def _execute_generated_entity_operation(
    *,
    structured: Dict[str, Any],
    capability_manifest: Dict[str, Any],
    runtime_base_url: str,
    workspace: Workspace,
    trace: Optional[List[Dict[str, Any]]] = None,
) -> Dict[str, Any]:
    contract = structured.get("contract") if isinstance(structured.get("contract"), dict) else {}
    operation = str(structured.get("operation") or "").strip()
    target_reference = str(structured.get("target_reference") or "").strip()
    active_trace = trace if isinstance(trace, list) else []
    resolved_target_reference = target_reference
    if operation in {"get", "update", "delete"} and not bool(structured.get("direct_target_reference")):
        resolution = _resolve_generated_entity_reference(
            contract=contract,
            target_reference=target_reference,
            runtime_base_url=runtime_base_url,
            workspace=workspace,
        )
        active_trace.append(
            _generated_trace_step(
                "target_resolution",
                entity_key=str(contract.get("key") or "").strip(),
                target_reference=target_reference,
                status=str(resolution.get("status") or ""),
                match_type=str(resolution.get("match_type") or ""),
            )
        )
        if resolution.get("status") == "ambiguous":
            return _generated_disambiguation_response(
                contract=contract,
                operation=operation,
                target_reference=target_reference,
                matches=resolution.get("matches") if isinstance(resolution.get("matches"), list) else [],
            )
        if resolution.get("status") == "not_found":
            singular = str(contract.get("singular_label") or contract.get("key") or "record").strip() or "record"
            return {
                "kind": "text",
                "columns": [],
                "rows": [],
                "text": f'No matching {singular} found for "{target_reference}".',
                "meta": {"target_reference": target_reference, "entity_key": str(contract.get("key") or "").strip()},
            }
        if resolution.get("status") == "resolved":
            resolved_target_reference = str(((resolution.get("record") or {}).get("id")) or target_reference)
    payload_fields = structured.get("fields") if isinstance(structured.get("fields"), dict) else {}
    mutation_fields = structured.get("field_mutations") if isinstance(structured.get("field_mutations"), dict) else {}
    relation_error = None
    if operation == "create":
        relation_error, payload_fields = _resolve_generated_relation_fields(
            contract=contract,
            payload_fields=payload_fields,
            capability_manifest=capability_manifest,
            runtime_base_url=runtime_base_url,
            workspace=workspace,
            trace=active_trace,
        )
    elif operation == "update":
        relation_error, mutation_fields = _resolve_generated_relation_fields(
            contract=contract,
            payload_fields=mutation_fields,
            capability_manifest=capability_manifest,
            runtime_base_url=runtime_base_url,
            workspace=workspace,
            trace=active_trace,
        )
    if relation_error:
        return relation_error
    path = _generated_entity_operation_path(contract, operation, target_reference=resolved_target_reference)
    query = {"workspace_id": str(workspace.id)} if operation in {"list", "get", "update", "delete"} else None
    payload = None
    if operation == "create":
        payload = {"workspace_id": str(workspace.id), **payload_fields}
    elif operation == "update":
        payload = mutation_fields
    active_trace.append(
        _generated_trace_step(
            "runtime_execution",
            entity_key=str(contract.get("key") or "").strip(),
            operation=operation,
            method=str((((contract.get("operations") or {}).get(operation) or {}).get("method")) or "GET").upper(),
            path=path,
            query=query or {},
            payload=payload or {},
        )
    )
    response = _runtime_target_request(
        base_url=runtime_base_url,
        method=str((((contract.get("operations") or {}).get(operation) or {}).get("method")) or "GET"),
        path=path,
        query=query,
        payload=payload,
        timeout=20,
    )
    content_type = str(response.headers.get("content-type") or "").lower()
    if "application/json" not in content_type:
        raise RuntimeError(f"generated-app runtime returned non-json content ({response.status_code})")
    body = response.json() if response.content else {}
    if response.status_code >= 400:
        detail = body.get("detail") if isinstance(body, dict) else ""
        raise RuntimeError(f"generated-app runtime request failed ({response.status_code}): {detail or body}")
    result = _generated_entity_result(contract=contract, operation=operation, payload=body, target_reference=resolved_target_reference)
    active_trace.append(
        _generated_trace_step(
            "result",
            entity_key=str(contract.get("key") or "").strip(),
            operation=operation,
            kind=str(result.get("kind") or ""),
            text=str(result.get("text") or ""),
        )
    )
    return result


def _run_generated_entity_operation(
    *,
    prompt: str,
    structured: Dict[str, Any],
    capability_manifest: Dict[str, Any],
    runtime_base_url: str,
    workspace: Workspace,
    source: str,
) -> Tuple[Dict[str, Any], List[Dict[str, Any]], Dict[str, Any]]:
    contract = structured.get("contract") if isinstance(structured.get("contract"), dict) else {}
    normalized = _normalized_generated_operation(structured)
    trace = [
        _generated_trace_step("user_command", source=source, prompt=str(prompt or "").strip()),
        _generated_trace_step("parsed_intent", structured_operation=normalized),
        _generated_trace_step(
            "entity_contract_consulted",
            entity_key=str(contract.get("key") or "").strip(),
            operation=str(structured.get("operation") or "").strip(),
            declared_operations=sorted(
                name
                for name, spec in ((contract.get("operations") if isinstance(contract.get("operations"), dict) else {}) or {}).items()
                if isinstance(spec, dict) and bool(spec.get("declared"))
            ),
            title_field=_entity_title_field(contract),
        ),
    ]
    missing_fields = structured.get("missing_fields") if isinstance(structured.get("missing_fields"), list) else []
    if structured.get("operation") == "create" and missing_fields:
        singular = str((contract.get("singular_label")) or structured.get("entity_key") or "record")
        result = _generated_structured_missing_response(
            operation="create",
            entity_label=singular,
            missing_fields=[str(field) for field in missing_fields],
            example=str(structured.get("example") or f"create {singular} named demo-{singular}"),
        )
        trace.append(_generated_trace_step("result", outcome="missing_fields", missing_fields=[str(field) for field in missing_fields]))
        return result, trace, normalized
    if structured.get("operation") == "update" and (
        bool(structured.get("target_required")) or missing_fields or not isinstance(structured.get("field_mutations"), dict) or not structured.get("field_mutations")
    ):
        singular = str((contract.get("singular_label")) or structured.get("entity_key") or "record")
        result = _generated_structured_missing_response(
            operation="update",
            entity_label=singular,
            missing_fields=[str(field) for field in missing_fields],
            example=str(structured.get("example") or f"update {singular} demo-{singular} status offline"),
            target_required=bool(structured.get("target_required")),
        )
        trace.append(_generated_trace_step("result", outcome="missing_fields", missing_fields=[str(field) for field in missing_fields]))
        return result, trace, normalized
    result = _execute_generated_entity_operation(
        structured=structured,
        capability_manifest=capability_manifest,
        runtime_base_url=runtime_base_url,
        workspace=workspace,
        trace=trace,
    )
    return result, trace, normalized


def _seed_context_pack_meta(workspace_slug: str) -> Dict[str, Any]:
    try:
        response = _seed_api_request(
            method="GET",
            path="/api/v1/context-packs/bindings",
            workspace_slug=workspace_slug,
            timeout=20,
        )
    except requests.RequestException:
        return {}
    content_type = str(response.headers.get("content-type") or "").lower()
    if response.status_code >= 400 or "application/json" not in content_type:
        return {}
    payload = response.json() if response.content else {}
    if not isinstance(payload, dict):
        return {}
    bindings = payload.get("bindings") if isinstance(payload.get("bindings"), list) else []
    warnings = payload.get("warnings") if isinstance(payload.get("warnings"), list) else []
    return {
        "context_pack_artifact_ids": [str(item.get("artifact_id") or "") for item in bindings if isinstance(item, dict)],
        "context_pack_slugs": [str(item.get("slug") or "") for item in bindings if isinstance(item, dict)],
        "context_warnings": [str(item) for item in warnings],
    }


def _runtime_target_request(
    *,
    base_url: str,
    method: str,
    path: str,
    query: Optional[Dict[str, Any]] = None,
    payload: Optional[Dict[str, Any]] = None,
    timeout: int = 20,
) -> requests.Response:
    return requests.request(
        method=method.upper(),
        url=f"{base_url.rstrip('/')}{path}",
        params=query or None,
        json=payload,
        timeout=timeout,
    )


def _generated_app_create_device_name() -> str:
    return f"demo-device-{uuid.uuid4().hex[:8]}"


def _generated_app_create_location_name() -> str:
    return f"demo-location-{uuid.uuid4().hex[:8]}"


def _parse_generated_location_create_prompt(prompt: str) -> tuple[Dict[str, Any], List[str]]:
    raw = str(prompt or "").strip()
    remainder = raw[len("create location"):].strip() if raw.lower().startswith("create location") else raw
    if remainder.lower().startswith("named "):
        remainder = remainder[6:].strip()
    if not remainder:
        return {}, ["name", "city"]
    name_part = remainder
    location_part = ""
    split_match = re.split(r"\s+in\s+", remainder, maxsplit=1, flags=re.IGNORECASE)
    if len(split_match) == 2:
        name_part, location_part = split_match[0].strip(), split_match[1].strip()
    payload: Dict[str, Any] = {"name": name_part, "kind": "site"}
    if location_part:
        tokens = [token.strip(", ") for token in location_part.split() if token.strip(", ")]
        if len(tokens) >= 3 and len(tokens[-1]) >= 2 and len(tokens[-2]) <= 3:
            payload["country"] = tokens[-1]
            payload["region"] = tokens[-2]
            payload["city"] = " ".join(tokens[:-2]).strip()
        else:
            payload["city"] = location_part.strip()
    missing: List[str] = []
    if not str(payload.get("name") or "").strip():
        missing.append("name")
    if not str(payload.get("city") or "").strip():
        missing.append("city")
    return payload, missing


def _parse_generated_device_create_prompt(prompt: str) -> tuple[Dict[str, Any], List[str]]:
    raw = str(prompt or "").strip()
    remainder = raw[len("create device"):].strip() if raw.lower().startswith("create device") else raw
    if remainder.lower().startswith("named "):
        remainder = remainder[6:].strip()
    payload: Dict[str, Any] = {
        "name": remainder,
        "kind": "router",
        "status": "online",
    }
    missing = [] if str(payload.get("name") or "").strip() else ["name"]
    return payload, missing


def _generated_missing_fields_response(
    *,
    command_key: str,
    missing_fields: List[str],
    example: str,
) -> Dict[str, Any]:
    return {
        "kind": "text",
        "columns": [],
        "rows": [],
        "text": f"To {command_key}, provide: {', '.join(missing_fields)}. Example: {example}",
        "meta": {
            "command_key": command_key,
            "missing_fields": missing_fields,
        },
    }


def _resolve_generated_handler_value(value: Any, *, workspace: Workspace) -> Any:
    if isinstance(value, str):
        token = value.strip()
        if token == "$workspace_id":
            return str(workspace.id)
        if token == "$workspace_slug":
            return str(workspace.slug or "")
        if token == "$generated.device_name":
            return _generated_app_create_device_name()
        if token == "$generated.location_name":
            return _generated_app_create_location_name()
    return value


def _execute_generated_runtime_command(
    *,
    command: Dict[str, Any],
    runtime_base_url: str,
    prompt: str,
    workspace: Workspace,
) -> Dict[str, Any]:
    command_key = _normalize_palette_prompt(prompt)
    workspace_id = str(workspace.id)
    handler = command.get("handler") if isinstance(command.get("handler"), dict) else {}
    method = str(handler.get("method") or "GET").upper()
    path = str(handler.get("path") or "/").strip() or "/"
    query_map = handler.get("query_map") if isinstance(handler.get("query_map"), dict) else {}
    body_map = handler.get("body_map") if isinstance(handler.get("body_map"), dict) else {}
    adapter = handler.get("response_adapter") if isinstance(handler.get("response_adapter"), dict) else {}
    resolved_query = {key: _resolve_generated_handler_value(value, workspace=workspace) for key, value in query_map.items()}
    resolved_body = {key: _resolve_generated_handler_value(value, workspace=workspace) for key, value in body_map.items()}
    created_name = ""
    if command_key == "create device":
        payload, missing_fields = _parse_generated_device_create_prompt(prompt)
        if missing_fields:
            return _generated_missing_fields_response(
                command_key=command_key,
                missing_fields=missing_fields,
                example="create device named edge-router-1",
            )
        created_name = str(payload.get("name") or "unknown")
        resolved_body.update(payload)
        resolved_body["workspace_id"] = workspace_id
    elif command_key == "create location":
        payload, missing_fields = _parse_generated_location_create_prompt(prompt)
        if missing_fields:
            return _generated_missing_fields_response(
                command_key=command_key,
                missing_fields=missing_fields,
                example="create location named sibling-location-2 in Austin TX USA",
            )
        created_name = str(payload.get("name") or "unknown")
        resolved_body.update(payload)
        resolved_body["workspace_id"] = workspace_id
    response = _runtime_target_request(
        base_url=runtime_base_url,
        method=method,
        path=path,
        query=resolved_query or None,
        payload=resolved_body or None,
        timeout=20,
    )
    if command_key == "create device" and response.status_code < 400:
        list_response = _runtime_target_request(
            base_url=runtime_base_url,
            method="GET",
            path="/devices",
            query={"workspace_id": workspace_id},
            timeout=20,
        )
        if list_response.status_code < 400:
            response = list_response
    elif command_key == "create location" and response.status_code < 400:
        list_response = _runtime_target_request(
            base_url=runtime_base_url,
            method="GET",
            path="/locations",
            query={"workspace_id": workspace_id},
            timeout=20,
        )
        if list_response.status_code < 400:
            response = list_response
    content_type = str(response.headers.get("content-type") or "").lower()
    if "application/json" not in content_type:
        raise RuntimeError(f"generated-app runtime returned non-json content ({response.status_code})")
    payload = response.json() if response.content else {}
    if response.status_code >= 400:
        raise RuntimeError(f"generated-app runtime request failed ({response.status_code})")
    adapter_kind = str(adapter.get("kind") or "table").strip().lower()
    if adapter_kind == "bar_chart":
        report = payload if isinstance(payload, dict) else {}
        labels = report.get("labels") if isinstance(report.get("labels"), list) else []
        values = report.get("values") if isinstance(report.get("values"), list) else []
        return {
            "kind": "bar_chart",
            "columns": [],
            "rows": [],
            "labels": labels,
            "values": values,
            "title": str(adapter.get("title") or command.get("name") or "Report"),
            "text": (
                f"Generated status chart for {sum(int(value or 0) for value in values)} "
                f"{'interfaces' if 'interface' in command_key else 'devices'}."
            ),
        }
    rows = payload if isinstance(payload, list) else (payload.get("items") if isinstance(payload, dict) and isinstance(payload.get("items"), list) else [])
    columns = adapter.get("columns") if isinstance(adapter.get("columns"), list) else []
    text = str(adapter.get("text_template") or "{{count}} rows").replace("{{count}}", str(len(rows)))
    if created_name and command_key.startswith("create "):
        text = f"Created 1 {command_key.split(' ', 1)[1]}: {created_name}"
    elif command_key.startswith("show "):
        label = "interfaces" if "interface" in command_key else ("locations" if "location" in command_key else "devices")
        text = f"Found {len(rows)} {label}."
    return {
        "kind": "table",
        "columns": columns,
        "rows": rows,
        "text": text,
    }


def _generated_app_disabled_response(*, prompt: str, capability_manifest: Dict[str, Any]) -> JsonResponse:
    command_key = _normalize_palette_prompt(prompt)
    return JsonResponse(
        {
            "kind": "text",
            "columns": [],
            "rows": [],
            "text": "No matching palette command found.",
            "meta": {
                "command_key": command_key,
                "capability_diagnostics": {
                    "source": "installed-capability-manifest",
                    "enabled_command_keys": sorted(
                        _normalize_palette_prompt(str(item.get("key") or item.get("prompt") or ""))
                        for item in (capability_manifest.get("commands") if isinstance(capability_manifest.get("commands"), list) else [])
                        if isinstance(item, dict)
                    ),
                    "latent_command_keys": sorted(_manifest_latent_command_keys(capability_manifest)),
                },
            },
        },
        status=200,
    )


def _generated_app_invalid_contract_response(*, prompt: str, issue: Dict[str, Any]) -> JsonResponse:
    return JsonResponse(
        {
            "kind": "text",
            "columns": [],
            "rows": [],
            "text": "Generated app contract is unavailable for this installed artifact. Rebuild or reinstall the app.",
            "meta": {
                "command_key": _normalize_palette_prompt(prompt),
                "generated_artifact_contract_status": issue,
            },
        },
        status=200,
    )


def _generated_app_palette_execution_response(
    *,
    identity: UserIdentity,
    request_id: str,
    workspace: Workspace,
    prompt: str,
    runtime_target: Dict[str, Any],
    capability_manifest: Dict[str, Any],
) -> JsonResponse:
    structured = _resolve_generated_entity_operation(prompt, capability_manifest)
    if structured:
        result, trace, normalized = _run_generated_entity_operation(
            prompt=prompt,
            structured=structured,
            capability_manifest=capability_manifest,
            runtime_base_url=str(runtime_target.get("runtime_base_url") or ""),
            workspace=workspace,
            source="palette",
        )
        existing_meta = result.get("meta") if isinstance(result.get("meta"), dict) else {}
        result["meta"] = {
            "base_url": str(runtime_target.get("runtime_base_url") or ""),
            "public_app_url": str(runtime_target.get("public_app_url") or ""),
            "runtime_owner": str(runtime_target.get("runtime_owner") or "sibling"),
            "app_slug": str(runtime_target.get("app_slug") or "net-inventory"),
            "compose_project": str(runtime_target.get("compose_project") or ""),
            "command_key": str(structured.get("command_key") or _normalize_palette_prompt(prompt)),
            **existing_meta,
        }
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="completed",
            prompt=prompt,
            request_type="palette.execute",
            workspace_id=str(workspace.id),
            summary=str(result.get("text") or ""),
            trace=trace,
            structured_operation=normalized,
        )
        return JsonResponse(result, status=200)
    command = _manifest_command_entry(capability_manifest, prompt)
    if not command:
        result = _generated_app_disabled_response(prompt=prompt, capability_manifest=capability_manifest)
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="completed",
            prompt=prompt,
            request_type="palette.execute",
            workspace_id=str(workspace.id),
            summary="No matching palette command found.",
            trace=[_generated_trace_step("user_command", source="palette", prompt=prompt), _generated_trace_step("result", outcome="disabled")],
        )
        return result
    handler = command.get("handler") if isinstance(command.get("handler"), dict) else {}
    entity_key = str(handler.get("entity_key") or "").strip()
    entity_operation = str(handler.get("entity_operation") or "").strip()
    if entity_key and entity_operation:
        entity_contract = _manifest_entity_contracts(capability_manifest).get(entity_key)
        if not entity_contract or not _entity_operation_declared(entity_contract, entity_operation):
            result = _generated_app_disabled_response(prompt=prompt, capability_manifest=capability_manifest)
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="completed",
                prompt=prompt,
                request_type="palette.execute",
                workspace_id=str(workspace.id),
                summary="No matching palette command found.",
                trace=[_generated_trace_step("user_command", source="palette", prompt=prompt), _generated_trace_step("result", outcome="disabled")],
            )
            return result
    result = _execute_generated_runtime_command(
        command=command,
        runtime_base_url=str(runtime_target.get("runtime_base_url") or ""),
        prompt=prompt,
        workspace=workspace,
    )
    existing_meta = result.get("meta") if isinstance(result.get("meta"), dict) else {}
    meta = {
        "base_url": str(runtime_target.get("runtime_base_url") or ""),
        "public_app_url": str(runtime_target.get("public_app_url") or ""),
        "runtime_owner": str(runtime_target.get("runtime_owner") or "sibling"),
        "app_slug": str(runtime_target.get("app_slug") or "net-inventory"),
        "compose_project": str(runtime_target.get("compose_project") or ""),
        "command_key": _normalize_palette_prompt(prompt),
        **existing_meta,
    }
    result["meta"] = meta
    _log_prompt_activity(
        request_id=request_id,
        identity=identity,
        status="completed",
        prompt=prompt,
        request_type="palette.execute",
        workspace_id=str(workspace.id),
        summary=str(result.get("text") or ""),
        trace=[_generated_trace_step("user_command", source="palette", prompt=prompt), _generated_trace_step("result", outcome="legacy_command")],
    )
    return JsonResponse(result, status=200)


def _seed_json_download(
    *,
    workspace_slug: str,
    artifact_id: str,
    timeout: int = 20,
) -> Dict[str, Any]:
    response = _seed_api_request(
        method="GET",
        path=f"/api/v1/artifacts/{artifact_id}/download",
        workspace_slug=workspace_slug,
        timeout=timeout,
    )
    content_type = str(response.headers.get("content-type") or "").lower()
    if response.status_code >= 400:
        raise RuntimeError(f"xyn-core execution-note download failed ({response.status_code})")
    if "application/json" not in content_type:
        raise RuntimeError("xyn-core execution-note download returned non-json content")
    payload = response.json() if response.content else {}
    if not isinstance(payload, dict):
        raise RuntimeError("xyn-core execution-note payload was not a JSON object")
    return payload


def _sort_execution_notes(items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    reason_priority = {
        "related_artifact_ids": 1,
        "generated_artifact_chain": 2,
        "job_id": 3,
        "note_id": 4,
    }

    by_time = sorted(items, key=lambda item: str(item.get("updated_at") or item.get("timestamp") or ""), reverse=True)
    return sorted(by_time, key=lambda item: reason_priority.get(str(item.get("match_reason") or ""), 99))


def _list_app_builder_execution_notes(
    *,
    workspace_slug: str,
    note_ids: List[str],
    job_ids: List[str],
    related_artifact_ids: List[str],
) -> List[Dict[str, Any]]:
    if not note_ids and not job_ids and not related_artifact_ids:
        return []
    response = _seed_api_request(
        method="GET",
        path="/api/v1/artifacts?kind=execution-note&limit=100",
        workspace_slug=workspace_slug,
        payload=None,
        timeout=20,
    )
    content_type = str(response.headers.get("content-type") or "").lower()
    if response.status_code >= 400 or "application/json" not in content_type:
        raise RuntimeError("Failed to list execution-note artifacts from xyn-core")
    payload = response.json() if response.content else {}
    rows = payload.get("items") if isinstance(payload, dict) else []
    artifacts = [row for row in rows if isinstance(row, dict) and str(row.get("kind") or "") == "execution-note"]
    note_id_set = {str(item).strip() for item in note_ids if str(item).strip()}
    job_id_set = {str(item).strip() for item in job_ids if str(item).strip()}
    related_artifact_id_set = {str(item).strip() for item in related_artifact_ids if str(item).strip()}
    matches: List[Dict[str, Any]] = []
    for row in artifacts:
        artifact_id = str(row.get("id") or "").strip()
        metadata = row.get("metadata") if isinstance(row.get("metadata"), dict) else {}
        related = {str(item).strip() for item in (metadata.get("related_artifact_ids") or []) if str(item).strip()}
        app_spec_artifact_id = str(metadata.get("app_spec_artifact_id") or "").strip()
        job_id = str(metadata.get("job_id") or "").strip()
        match_reason = ""
        match_values: List[str] = []
        if related_artifact_id_set and related.intersection(related_artifact_id_set):
            match_reason = "related_artifact_ids"
            match_values = sorted(related.intersection(related_artifact_id_set))
        elif app_spec_artifact_id and related_artifact_id_set and app_spec_artifact_id in related_artifact_id_set:
            match_reason = "generated_artifact_chain"
            match_values = [app_spec_artifact_id]
        elif job_id and job_id in job_id_set:
            match_reason = "job_id"
            match_values = [job_id]
        elif artifact_id and artifact_id in note_id_set:
            match_reason = "note_id"
            match_values = [artifact_id]
        if not match_reason:
            continue
        note_payload = _seed_json_download(workspace_slug=workspace_slug, artifact_id=artifact_id, timeout=20)
        matches.append(
            {
                "id": artifact_id,
                "workspace_id": note_payload.get("workspace_id") or row.get("workspace_id"),
                "related_artifact_ids": list(note_payload.get("related_artifact_ids") or []),
                "prompt_or_request": str(note_payload.get("prompt_or_request") or metadata.get("prompt_or_request") or ""),
                "findings": list(note_payload.get("findings") or []),
                "root_cause": str(note_payload.get("root_cause") or ""),
                "proposed_fix": str(note_payload.get("proposed_fix") or ""),
                "implementation_summary": str(note_payload.get("implementation_summary") or ""),
                "validation_summary": list(note_payload.get("validation_summary") or []),
                "debt_recorded": list(note_payload.get("debt_recorded") or []),
                "status": str(note_payload.get("status") or metadata.get("status") or ""),
                "timestamp": str(note_payload.get("timestamp") or row.get("created_at") or ""),
                "updated_at": str(note_payload.get("updated_at") or row.get("created_at") or ""),
                "match_reason": match_reason,
                "match_values": match_values,
                "metadata": metadata,
            }
        )
    return _sort_execution_notes(matches)


def _build_workspace_slug_from_name(name: str) -> str:
    base = slugify(name)[:96] or "workspace"
    return base


def _next_workspace_slug(base_slug: str) -> str:
    base = str(base_slug or "").strip().lower() or "workspace"
    candidate = base[:120]
    if not Workspace.objects.filter(slug=candidate).exists():
        return candidate
    for idx in range(2, 2000):
        suffix = f"-{idx}"
        next_candidate = f"{base[: max(1, 120 - len(suffix))]}{suffix}"
        if not Workspace.objects.filter(slug=next_candidate).exists():
            return next_candidate
    return f"{base[:110]}-{uuid.uuid4().hex[:8]}"


def _find_or_create_customer_workspace(
    *,
    operator_workspace: Workspace,
    customer_name: str,
) -> Tuple[Workspace, bool]:
    normalized = str(customer_name or "").strip()
    existing = (
        Workspace.objects.filter(parent_workspace=operator_workspace)
        .filter(models.Q(org_name__iexact=normalized) | models.Q(name__iexact=normalized))
        .order_by("-updated_at", "-created_at")
        .first()
    )
    if existing:
        _ensure_default_workspace_artifact_bindings(existing)
        return existing, False
    next_slug = _next_workspace_slug(_build_workspace_slug_from_name(normalized))
    created = Workspace.objects.create(
        slug=next_slug,
        name=normalized,
        org_name=normalized,
        description=f"Customer workspace for {normalized}",
        kind="customer",
        lifecycle_stage="prospect",
        auth_mode="oidc",
        oidc_enabled=False,
        parent_workspace=operator_workspace,
        metadata_json={},
    )
    _ensure_default_workspace_artifact_bindings(created)
    return created, True


def _ensure_runtime_artifact(
    *,
    workspace: Workspace,
    slug: str,
    title: str,
    manifest_ref: str,
    summary: str,
) -> Artifact:
    module_type, _ = ArtifactType.objects.get_or_create(
        slug="module",
        defaults={"name": "Module", "description": "Kernel-loadable module artifact."},
    )
    artifact = Artifact.objects.filter(slug=slug).order_by("-updated_at", "-created_at").first()
    if artifact is None:
        artifact = Artifact.objects.create(
            workspace=workspace,
            type=module_type,
            title=title,
            slug=slug,
            status="published",
            visibility="team",
            summary=summary,
            scope_json={"slug": slug, "manifest_ref": manifest_ref, "summary": summary},
            provenance_json={"source_system": "seed-kernel", "source_id": slug},
        )
        return artifact
    scope = dict(artifact.scope_json or {})
    scope_changed = False
    if str(scope.get("slug") or "").strip() != slug:
        scope["slug"] = slug
        scope_changed = True
    if str(scope.get("manifest_ref") or "").strip() != manifest_ref:
        scope["manifest_ref"] = manifest_ref
        scope_changed = True
    update_fields: List[str] = []
    if str(artifact.title or "").strip() != title:
        artifact.title = title
        update_fields.append("title")
    if str(artifact.summary or "").strip() != summary:
        artifact.summary = summary
        update_fields.append("summary")
    if scope_changed:
        artifact.scope_json = scope
        update_fields.append("scope_json")
    if update_fields:
        update_fields.append("updated_at")
        artifact.save(update_fields=update_fields)
    return artifact


def _intent_apply_provision_xyn_remote(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    customer_name = str(payload.get("customer_name") or "").strip() or "Customer"
    fqdn = str(payload.get("fqdn") or "").strip().lower().strip(".")
    target_environment = str(payload.get("target_environment") or "local").strip().lower() or "local"
    tls_mode = str(payload.get("tls_mode") or "letsencrypt").strip().lower() or "letsencrypt"
    instance_ref_payload = payload.get("instance_ref")
    instance_ref = ""
    if isinstance(instance_ref_payload, dict):
        instance_ref = str(instance_ref_payload.get("artifact_id") or "").strip()
    elif isinstance(instance_ref_payload, str):
        instance_ref = str(instance_ref_payload).strip()
    if not instance_ref:
        instance_ref = "xyn-ec2-demo"
    dns_payload = payload.get("dns") if isinstance(payload.get("dns"), dict) else {}
    dns_enabled = bool(dns_payload.get("enabled", bool(fqdn)))
    dns_ttl = int(dns_payload.get("ttl") or 60)
    dry_run = bool(payload.get("dry_run", False))
    include_ems = bool(payload.get("include_ems", False))
    instance_label = str(payload.get("instance_label") or "").strip()

    if target_environment not in {"local", "k8s"}:
        return JsonResponse({"error": "target_environment must be local or k8s"}, status=400)
    if tls_mode not in {"letsencrypt", "provided"}:
        return JsonResponse({"error": "tls_mode must be letsencrypt or provided"}, status=400)
    if dns_ttl < 30 or dns_ttl > 86400:
        return JsonResponse({"error": "dns.ttl must be between 30 and 86400"}, status=400)

    operator_workspace_id = str(payload.get("operator_workspace_id") or "").strip()
    operator_workspace = _resolve_workspace_for_identity(identity, operator_workspace_id)
    if not operator_workspace:
        return JsonResponse({"error": "operator workspace not found or forbidden"}, status=403)

    workspace, workspace_created = _find_or_create_customer_workspace(
        operator_workspace=operator_workspace,
        customer_name=customer_name,
    )
    WorkspaceMembership.objects.get_or_create(
        workspace=workspace,
        user_identity=identity,
        defaults={"role": "admin", "termination_authority": True},
    )

    runtime_artifact = _ensure_runtime_artifact(
        workspace=operator_workspace,
        slug="core.xyn-runtime",
        title="Xyn Runtime",
        manifest_ref="registry/modules/xyn-runtime.artifact.manifest.json",
        summary="Meta-artifact orchestrator for self-deploying Xyn runtime.",
    )
    xyn_api_artifact = _ensure_runtime_artifact(
        workspace=operator_workspace,
        slug="xyn-api",
        title="xyn-api",
        manifest_ref="registry/modules/xyn-api.artifact.manifest.json",
        summary="Deployable Xyn API runtime artifact.",
    )
    xyn_ui_artifact = _ensure_runtime_artifact(
        workspace=operator_workspace,
        slug="xyn-ui",
        title="xyn-ui",
        manifest_ref="registry/modules/xyn-ui.artifact.manifest.json",
        summary="Deployable Xyn UI runtime artifact.",
    )
    ems_artifact = Artifact.objects.filter(slug="ems").order_by("-updated_at", "-created_at").first() if include_ems else None

    for artifact in [runtime_artifact, xyn_api_artifact, xyn_ui_artifact, ems_artifact]:
        if artifact is None:
            continue
        binding, _ = WorkspaceArtifactBinding.objects.get_or_create(
            workspace=workspace,
            artifact=artifact,
            defaults={"enabled": True, "installed_state": "installed", "config_ref": None},
        )
        update_fields: List[str] = []
        if not binding.enabled:
            binding.enabled = True
            update_fields.append("enabled")
        if str(binding.installed_state or "").strip().lower() != "installed":
            binding.installed_state = "installed"
            update_fields.append("installed_state")
        if update_fields:
            update_fields.append("updated_at")
            binding.save(update_fields=update_fields)

    deployment_target = "local" if target_environment == "local" else "aws"
    app_instance, app_instance_created = WorkspaceAppInstance.objects.get_or_create(
        workspace=workspace,
        app_slug="xyn-runtime",
        fqdn=fqdn or "pending-fqdn.local",
        defaults={
            "artifact": runtime_artifact,
            "customer_name": customer_name,
            "deployment_target": deployment_target,
            "status": "active",
            "dns_config_json": {"enabled": dns_enabled, "ttl": dns_ttl, "mode": "route53" if dns_enabled else "manual"},
        },
    )
    if app_instance.artifact_id != runtime_artifact.id:
        app_instance.artifact = runtime_artifact
        app_instance.save(update_fields=["artifact", "updated_at"])

    instance_artifact = _resolve_instance_artifact_for_dns(instance_ref)
    if not instance_artifact:
        return JsonResponse({"error": f"instance artifact '{instance_ref}' not found"}, status=404)
    instance_payload = _extract_instance_payload_from_artifact(instance_artifact)
    if not instance_payload:
        return JsonResponse({"error": f"instance artifact '{instance_artifact.slug}' has no xyn.instance.v1 payload"}, status=400)
    instance_errors = _validate_instance_v1_payload(instance_payload)
    if instance_errors:
        return JsonResponse({"error": "instance artifact validation failed", "details": instance_errors}, status=400)

    try:
        ssh_resolved = _resolve_instance_ssh_from_payload(instance_payload)
    except ValueError as exc:
        if not dry_run:
            return JsonResponse({"error": str(exc)}, status=400)
        ssh_resolved = {
            "host": str((instance_payload.get("network") or {}).get("public_hostname") or (instance_payload.get("network") or {}).get("public_ipv4") or ""),
            "user": "ubuntu",
            "port": 22,
            "resolved": {"private_key": "dry-run", "strict_host_key_checking": False, "known_hosts": ""},
        }

    release_spec_payload = {
        "schema_version": "xyn.release_spec.v1",
        "name": str(payload.get("release_spec_name") or f"xyn-runtime-{customer_name.lower().replace(' ', '-')}"[:120]),
        "instance_ref": {"artifact_id": str(instance_artifact.id)},
        "parameters": {
            "instance_label": instance_label,
            "fqdn": fqdn,
            "scheme": "https" if fqdn else "http",
            "ui_port": payload.get("ui_port"),
            "api_port": payload.get("api_port"),
            "dns": {"enabled": dns_enabled, "ttl": dns_ttl},
        },
        "components": [
            {
                "slug": "xyn-api",
                "enabled": True,
                "image_ref": str(payload.get("xyn_api_image_ref") or "ghcr.io/xyence/xyn-api:latest"),
                "env": payload.get("xyn_api_env") if isinstance(payload.get("xyn_api_env"), dict) else {},
            },
            {
                "slug": "xyn-ui",
                "enabled": True,
                "image_ref": str(payload.get("xyn_ui_image_ref") or "ghcr.io/xyence/xyn-ui:latest"),
                "env": payload.get("xyn_ui_env") if isinstance(payload.get("xyn_ui_env"), dict) else {},
            },
            {
                "slug": "ems",
                "enabled": bool(include_ems),
                "image_ref": str(payload.get("ems_image_ref") or "ghcr.io/xyence/ems:latest"),
                "env": payload.get("ems_env") if isinstance(payload.get("ems_env"), dict) else {},
            },
        ],
    }
    release_spec_payload["parameters"] = {
        key: value
        for key, value in (release_spec_payload.get("parameters") or {}).items()
        if value is not None and value != ""
    }
    release_spec_errors = _validate_release_spec_v1_payload(release_spec_payload)
    if release_spec_errors:
        return JsonResponse({"error": "release_spec validation failed", "details": release_spec_errors}, status=400)

    release_spec_type = _ensure_release_spec_artifact_type()
    deployment_type = _ensure_deployment_artifact_type()
    _ensure_target_artifact_type()
    release_spec_artifact = _create_immutable_artifact_record(
        workspace=workspace,
        artifact_type=release_spec_type,
        title=f"ReleaseSpec {release_spec_payload.get('name')}",
        slug_prefix="release-spec",
        schema_version="xyn.release_spec.v1",
        content=release_spec_payload,
        summary=f"Remote deployment spec for instance {instance_artifact.slug}",
        identity=identity,
    )

    release_spec_for_driver = json.loads(json.dumps(release_spec_payload))
    release_spec_for_driver["parameters"]["_prepared_ssh"] = ssh_resolved

    run = Run.objects.create(
        entity_type="module",
        entity_id=runtime_artifact.id,
        status="running",
        summary=f"Provision remote Xyn runtime for {customer_name}",
        started_at=timezone.now(),
        metadata_json={"operation": "deploy_release_spec", "status": "running"},
    )

    driver = SshDockerComposeInstanceDriver(dry_run=dry_run)
    started_at = timezone.now()
    driver_result: Dict[str, Any] = {}
    health_result: Dict[str, Any] = {}
    deployment_status = "running"
    errors: List[Dict[str, str]] = []
    prepared = None
    try:
        prepared = driver.prepare(
            instance={
                **instance_payload,
                "access": {
                    **(instance_payload.get("access") if isinstance(instance_payload.get("access"), dict) else {}),
                    "ssh": {**(instance_payload.get("access", {}).get("ssh") if isinstance(instance_payload.get("access", {}).get("ssh"), dict) else {}), **ssh_resolved},
                },
            },
            release_spec=release_spec_for_driver,
        )
        release_spec_for_driver["parameters"]["_prepared_ssh"] = prepared.ssh
        release_spec_for_driver["parameters"]["_prepared_ui_port"] = prepared.ui_port
        release_spec_for_driver["parameters"]["_prepared_api_port"] = prepared.api_port
        apply_result = driver.apply(prepared)
        health = driver.check_health(apply_result, release_spec_for_driver)
        driver_result = {
            "status": apply_result.status,
            "stdout": apply_result.stdout,
            "stderr": apply_result.stderr,
            "details": apply_result.details,
        }
        health_result = {"status": health.status, "checks": health.checks}
        deployment_status = "pending" if apply_result.status == "pending" else ("succeeded" if health.status in {"succeeded", "pending"} else "failed")
    except Exception as exc:
        deployment_status = "failed"
        errors.append({"code": "driver_failed", "message": str(exc)})
        driver_result = {"status": "failed", "stdout": "", "stderr": str(exc), "details": {}}
        health_result = {"status": "failed", "checks": {}}

    network = instance_payload.get("network") if isinstance(instance_payload.get("network"), dict) else {}
    ui_port = int((prepared.ui_port if prepared else release_spec_for_driver.get("parameters", {}).get("ui_port") or 0) or 80)
    api_port = int((prepared.api_port if prepared else release_spec_for_driver.get("parameters", {}).get("api_port") or 0) or 8000)
    urls = compute_base_urls(
        fqdn=fqdn,
        scheme=str(release_spec_for_driver.get("parameters", {}).get("scheme") or "https"),
        public_hostname=str((network or {}).get("public_hostname") or ""),
        public_ipv4=str((network or {}).get("public_ipv4") or ""),
        ui_port=ui_port,
        api_port=api_port,
    )

    dns_action: Dict[str, Any] = {"enabled": dns_enabled, "status": "skipped", "mode": "manual"}
    if fqdn and dns_enabled:
        try:
            record_type, record_value = _resolve_dns_record_from_instance(instance_payload)
            target_ref = str(payload.get("target_ref") or "").strip()
            target_payload = payload.get("dns_provider") if isinstance(payload.get("dns_provider"), dict) else {}
            if target_ref:
                target_artifact = _resolve_target_artifact(target_ref)
                if target_artifact:
                    target_content = _extract_latest_content(target_artifact)
                    if isinstance(target_content.get("dns_provider"), dict):
                        target_payload = target_content.get("dns_provider") or target_payload
            if dry_run:
                dns_action = {
                    "enabled": True,
                    "status": "pending",
                    "mode": "route53",
                    "fqdn": fqdn,
                    "record_type": record_type,
                    "record_value": record_value,
                    "hosted_zone_id": str(target_payload.get("hosted_zone_id") or ""),
                }
            else:
                hosted_zone_id = str(target_payload.get("hosted_zone_id") or "").strip()
                credentials_ref = target_payload.get("credentials_ref") if isinstance(target_payload.get("credentials_ref"), dict) else {}
                context_pack_id = str((credentials_ref or {}).get("context_pack_id") or "").strip()
                if not hosted_zone_id or not context_pack_id:
                    raise ValueError("target dns_provider.hosted_zone_id and credentials_ref.context_pack_id are required")
                resolved_credentials = _resolve_context_pack_credentials(context_pack_id)
                provider = Route53DnsProvider(
                    hosted_zone_id=hosted_zone_id,
                    region=str(target_payload.get("region") or resolved_credentials.get("region") or "").strip() or None,
                    aws_access_key_id=resolved_credentials.get("aws_access_key_id") or None,
                    aws_secret_access_key=resolved_credentials.get("aws_secret_access_key") or None,
                    aws_session_token=resolved_credentials.get("aws_session_token") or None,
                )
                provider_result = provider.upsert_record(
                    fqdn=fqdn,
                    record_type=record_type,
                    value=record_value,
                    ttl=dns_ttl,
                )
                dns_action = {
                    "enabled": True,
                    "status": "succeeded",
                    "mode": "route53",
                    "fqdn": fqdn,
                    "record_type": record_type,
                    "record_value": record_value,
                    "ttl": dns_ttl,
                    "hosted_zone_id": hosted_zone_id,
                    "change_id": provider_result.get("change_id"),
                }
        except Exception as exc:
            dns_action = {"enabled": True, "status": "failed", "mode": "route53", "error": str(exc)}

    ended_at = timezone.now()
    deployment_payload = {
        "schema_version": "xyn.deployment.v1",
        "status": deployment_status,
        "started_at": started_at.isoformat(),
        "ended_at": ended_at.isoformat(),
        "release_spec_ref": {"artifact_id": str(release_spec_artifact.id), "slug": release_spec_artifact.slug},
        "instance_ref": {"artifact_id": str(instance_artifact.id), "slug": instance_artifact.slug},
        "outputs": {
            **urls,
            "ui_port": ui_port,
            "api_port": api_port,
            "health": health_result,
            "dns": dns_action,
        },
        "driver_state": {
            "compose_project": prepared.compose_project if prepared else "",
            "remote_workdir": prepared.remote_workdir if prepared else "",
            "compose_file": prepared.compose_file_path if prepared else "",
            "dry_run": dry_run,
        },
        "logs": {
            "stdout": str((driver_result or {}).get("stdout") or ""),
            "stderr": str((driver_result or {}).get("stderr") or ""),
        },
        "errors": errors,
    }
    app_instance.fqdn = fqdn or str(urls.get("base_url") or "")
    app_instance.status = "error" if deployment_status == "failed" else "active"
    app_instance.deployment_target = deployment_target
    app_instance.dns_config_json = {"enabled": dns_enabled, "ttl": dns_ttl, "result": dns_action}
    app_instance.save(update_fields=["fqdn", "status", "deployment_target", "dns_config_json", "updated_at"])
    deployment_errors = _validate_deployment_v1_payload(deployment_payload)
    if deployment_errors:
        return JsonResponse({"error": "deployment payload validation failed", "details": deployment_errors}, status=500)
    deployment_artifact = _create_immutable_artifact_record(
        workspace=workspace,
        artifact_type=deployment_type,
        title=f"Deployment {release_spec_payload.get('name')}",
        slug_prefix="deployment",
        schema_version="xyn.deployment.v1",
        content=deployment_payload,
        summary=f"Deployment execution for {release_spec_payload.get('name')}",
        identity=identity,
    )

    run.status = "failed" if deployment_status == "failed" else ("running" if deployment_status == "pending" else "succeeded")
    run.finished_at = ended_at if run.status != "running" else None
    run.log_text = (
        f"Deployment status: {deployment_status}\\n"
        f"Instance: {instance_artifact.slug}\\n"
        f"Base URL: {urls.get('base_url')}\\n"
        f"Compose project: {(prepared.compose_project if prepared else '')}\\n"
    )
    run.metadata_json = {
        "operation": "deploy_release_spec",
        "status": deployment_status,
        "release_spec_artifact_id": str(release_spec_artifact.id),
        "deployment_artifact_id": str(deployment_artifact.id),
        "outputs": deployment_payload.get("outputs") or {},
    }
    run.save(update_fields=["status", "finished_at", "log_text", "metadata_json", "updated_at"])
    _write_run_artifact(run, "release_spec.json", release_spec_payload, "deployment_plan")
    _write_run_artifact(run, "deployment_result.json", deployment_payload, "deployment_result")
    if prepared:
        _write_run_artifact(run, "compose.yaml", prepared.compose_yaml, "deployment_result")
    _write_run_summary(run)

    response_payload = {
        "status": "DraftReady",
        "action_type": "CreateDraft",
        "artifact_type": "Workspace",
        "artifact_id": str(deployment_artifact.id),
        "summary": f"Provisioned remote Xyn instance ({deployment_status}).",
        "result": {
            "workspace": {"id": str(workspace.id), "created": workspace_created},
            "instance": {"id": str(instance_artifact.id), "slug": instance_artifact.slug},
            "app_instance": {"id": str(app_instance.id), "created": app_instance_created, "fqdn": app_instance.fqdn},
            "release_spec": {"id": str(release_spec_artifact.id), "slug": release_spec_artifact.slug},
            "deployment": {"id": str(deployment_artifact.id), "slug": deployment_artifact.slug, "status": deployment_status},
            "run": {"id": str(run.id), "status": run.status},
            "base_url": urls.get("base_url"),
            "ui_url": urls.get("ui_url"),
            "api_url": urls.get("api_url"),
            "dns": dns_action,
            "driver_state": deployment_payload.get("driver_state"),
        },
        "next_actions": [
            {"label": "Open deployment details", "action": "OpenPanel", "panel_key": "artifact_detail", "params": {"slug": deployment_artifact.slug}},
            {"label": "Open deployment run", "action": "OpenPanel", "panel_key": "run_detail", "params": {"run_id": str(run.id)}},
            {"label": "Open Workbench", "action": "OpenPath", "path": f"/w/{workspace.id}/workbench"},
        ],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
        },
    }
    _audit_intent_event(
        message="intent.apply.deploy_release_spec",
        identity=identity,
        request_id=request_id,
        artifact_id=str(deployment_artifact.id),
        proposal={"operation": "deploy_release_spec", "instance_ref": instance_ref, "fqdn": fqdn},
        resolution=response_payload,
    )
    return JsonResponse(response_payload)


def _intent_apply_install_xyn_instance(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    # Canonical path now routes through instance-driver based remote deployment.
    return _intent_apply_provision_xyn_remote(
        identity=identity,
        payload=payload,
        request_id=request_id,
    )


def _intent_apply_deploy_ems_customer(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    customer_name = str(payload.get("customer_name") or "").strip()
    if not customer_name:
        return JsonResponse({"error": "customer_name is required"}, status=400)
    operator_workspace_id = str(payload.get("operator_workspace_id") or "").strip()
    operator_workspace = _resolve_workspace_for_identity(identity, operator_workspace_id)
    if not operator_workspace:
        return JsonResponse({"error": "operator workspace not found or forbidden"}, status=403)

    metadata = payload.get("metadata")
    if metadata is not None and not isinstance(metadata, dict):
        return JsonResponse({"error": "metadata must be an object"}, status=400)
    next_slug = _next_workspace_slug(_build_workspace_slug_from_name(customer_name))
    child_workspace = Workspace.objects.create(
        slug=next_slug,
        name=customer_name,
        org_name=customer_name,
        description=f"Customer workspace for {customer_name}",
        kind="customer",
        lifecycle_stage="prospect",
        auth_mode="oidc",
        oidc_enabled=False,
        parent_workspace=operator_workspace,
        metadata_json=metadata or {},
    )
    WorkspaceMembership.objects.get_or_create(
        workspace=child_workspace,
        user_identity=identity,
        defaults={"role": "admin", "termination_authority": True},
    )
    _ensure_default_workspace_artifact_bindings(child_workspace)

    ems_artifact = Artifact.objects.filter(slug="ems").order_by("-updated_at", "-created_at").first()
    if ems_artifact:
        WorkspaceArtifactBinding.objects.get_or_create(
            workspace=child_workspace,
            artifact=ems_artifact,
            defaults={"enabled": True, "installed_state": "installed"},
        )

    open_ems_path = f"/w/{child_workspace.id}/apps/ems"
    open_installed_path = f"/w/{child_workspace.id}/build/artifacts"
    open_security_path = f"/w/{child_workspace.id}/admin/platform-settings?tab=security"
    response_payload = {
        "status": "DraftReady",
        "action_type": "CreateDraft",
        "artifact_type": "Workspace",
        "artifact_id": None,
        "summary": f'Provisioned EMS workspace for "{customer_name}".',
        "next_actions": [
            {"label": "Open EMS", "action": "OpenPath", "path": open_ems_path},
            {"label": "Open Installed", "action": "OpenPath", "path": open_installed_path},
            {"label": "Open Auth Settings", "action": "OpenPath", "path": open_security_path},
        ],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
        },
    }
    _audit_intent_event(
        message="intent.apply.deploy_ems_customer",
        identity=identity,
        request_id=request_id,
        artifact_id=None,
        proposal={"operation": "deploy_ems_customer", "customer_name": customer_name},
        resolution=response_payload,
    )
    return JsonResponse(response_payload)


def _intent_apply_create_ems_instance(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    customer_name = str(payload.get("customer_name") or "").strip()
    fqdn = str(payload.get("fqdn") or "").strip().lower().strip(".")
    if not customer_name:
        return JsonResponse({"error": "customer_name is required"}, status=400)
    if not fqdn or "." not in fqdn:
        return JsonResponse({"error": "fqdn is required"}, status=400)

    operator_workspace_id = str(payload.get("operator_workspace_id") or "").strip()
    operator_workspace = _resolve_workspace_for_identity(identity, operator_workspace_id)
    if not operator_workspace:
        return JsonResponse({"error": "operator workspace not found or forbidden"}, status=403)

    workspace, workspace_created = _find_or_create_customer_workspace(
        operator_workspace=operator_workspace,
        customer_name=customer_name,
    )
    WorkspaceMembership.objects.get_or_create(
        workspace=workspace,
        user_identity=identity,
        defaults={"role": "admin", "termination_authority": True},
    )

    ems_artifact = Artifact.objects.filter(slug="ems").order_by("-updated_at", "-created_at").first()
    binding_created = False
    if ems_artifact:
        binding, binding_created = WorkspaceArtifactBinding.objects.get_or_create(
            workspace=workspace,
            artifact=ems_artifact,
            defaults={"enabled": True, "installed_state": "installed"},
        )
        needs_update = False
        if not binding.enabled:
            binding.enabled = True
            needs_update = True
        if str(binding.installed_state or "").strip().lower() != "installed":
            binding.installed_state = "installed"
            needs_update = True
        if needs_update:
            binding.save(update_fields=["enabled", "installed_state", "updated_at"])

    instance, instance_created = WorkspaceAppInstance.objects.get_or_create(
        workspace=workspace,
        app_slug="ems",
        fqdn=fqdn,
        defaults={
            "artifact": ems_artifact,
            "customer_name": customer_name,
            "deployment_target": "local",
            "status": "active",
            "dns_config_json": {
                "mode": "stub",
                "provider": "local-demo",
                "fqdn": fqdn,
                "desired_record_type": "A",
                "apply_external_changes": False,
            },
        },
    )
    if not instance_created:
        update_fields: List[str] = []
        if ems_artifact and instance.artifact_id != ems_artifact.id:
            instance.artifact = ems_artifact
            update_fields.append("artifact")
        if instance.deployment_target != "local":
            instance.deployment_target = "local"
            update_fields.append("deployment_target")
        if instance.customer_name != customer_name:
            instance.customer_name = customer_name
            update_fields.append("customer_name")
        if not isinstance(instance.dns_config_json, dict):
            instance.dns_config_json = {}
        desired_dns = {
            "mode": "stub",
            "provider": "local-demo",
            "fqdn": fqdn,
            "desired_record_type": "A",
            "apply_external_changes": False,
        }
        if instance.dns_config_json != desired_dns:
            instance.dns_config_json = desired_dns
            update_fields.append("dns_config_json")
        if instance.status != "active":
            instance.status = "active"
            update_fields.append("status")
        if update_fields:
            update_fields.append("updated_at")
            instance.save(update_fields=update_fields)

    open_path = f"/w/{workspace.id}/apps/ems"
    response_payload = {
        "status": "DraftReady",
        "action_type": "CreateDraft",
        "artifact_type": "Workspace",
        "artifact_id": str(ems_artifact.id) if ems_artifact else None,
        "summary": f'EMS instance ready for "{customer_name}" at {fqdn}.',
        "result": {
            "workspace": {"id": str(workspace.id), "created": workspace_created},
            "app": {"slug": "ems", "installed": bool(ems_artifact), "binding_created": binding_created},
            "instance": {"id": str(instance.id), "created": instance_created, "fqdn": fqdn, "deployment_target": "local"},
            "app_url": open_path,
            "dns": instance.dns_config_json or {},
        },
        "next_actions": [
            {"label": "Open EMS", "action": "OpenPath", "path": open_path},
            {"label": "Open Installed", "action": "OpenPath", "path": f"/w/{workspace.id}/build/artifacts"},
        ],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
        },
    }
    _audit_intent_event(
        message="intent.apply.create_ems_instance",
        identity=identity,
        request_id=request_id,
        artifact_id=str(ems_artifact.id) if ems_artifact else None,
        proposal={"operation": "create_ems_instance", "customer_name": customer_name, "fqdn": fqdn},
        resolution=response_payload,
    )
    return JsonResponse(response_payload)


def _intent_apply_open_ems_panel(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    panel_key = str(payload.get("panel_key") or "").strip()
    params = payload.get("params") if isinstance(payload.get("params"), dict) else {}
    operator_workspace_id = str(payload.get("operator_workspace_id") or "").strip()
    workspace = _resolve_workspace_for_identity(identity, operator_workspace_id)
    if not workspace:
        return JsonResponse({"error": "workspace not found or forbidden"}, status=403)
    if panel_key not in {"ems_unregistered_devices", "ems_registrations_time", "ems_device_statuses"}:
        return JsonResponse({"error": "unsupported panel_key"}, status=400)

    result_payload = {
        "status": "DraftReady",
        "action_type": "CreateDraft",
        "artifact_type": "Workspace",
        "artifact_id": None,
        "summary": "EMS panel ready.",
        "result": {
            "panel": {
                "key": panel_key,
                "params": params,
                "workspace_id": str(workspace.id),
            }
        },
        "next_actions": [
            {
                "label": "Open panel",
                "action": "OpenPanel",
                "panel_key": panel_key,
                "params": params,
            }
        ],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
        },
    }
    _audit_intent_event(
        message="intent.apply.open_ems_panel",
        identity=identity,
        request_id=request_id,
        artifact_id=None,
        proposal={"operation": "open_ems_panel", "panel_key": panel_key, "params": params},
        resolution=result_payload,
    )
    return JsonResponse(result_payload)


def _intent_apply_open_artifact_panel(
    *,
    identity: UserIdentity,
    payload: Dict[str, Any],
    request_id: str,
) -> JsonResponse:
    panel_key = str(payload.get("panel_key") or "").strip()
    params = payload.get("params") if isinstance(payload.get("params"), dict) else {}
    valid_panel_keys = {"artifact_list", "artifact_detail", "artifact_raw_json", "artifact_files", "rules_browser"}
    if panel_key not in valid_panel_keys:
        return JsonResponse({"error": "unsupported panel_key"}, status=400)

    slug = str(params.get("slug") or "").strip()
    if panel_key in {"artifact_detail", "artifact_raw_json", "artifact_files"} and not slug:
        return JsonResponse({"error": "slug is required"}, status=400)
    if slug and _resolve_artifact_by_slug(slug) is None:
        return JsonResponse({"error": "artifact not found"}, status=404)

    result_payload = {
        "status": "DraftReady",
        "action_type": "CreateDraft",
        "artifact_type": "Workspace",
        "artifact_id": None,
        "summary": "Artifact panel ready.",
        "result": {
            "panel": {
                "key": panel_key,
                "params": params,
            }
        },
        "next_actions": [
            {
                "label": "Open panel",
                "action": "OpenPanel",
                "panel_key": panel_key,
                "params": params,
            }
        ],
        "audit": {
            "request_id": request_id,
            "timestamp": timezone.now().isoformat(),
        },
    }
    _audit_intent_event(
        message="intent.apply.open_artifact_panel",
        identity=identity,
        request_id=request_id,
        artifact_id=None,
        proposal={"operation": "open_artifact_panel", "panel_key": panel_key, "params": params},
        resolution=result_payload,
    )
    return JsonResponse(result_payload)


@csrf_exempt
def xyn_intent_resolve(request: HttpRequest) -> JsonResponse:
    if not _intent_engine_enabled():
        return JsonResponse({"error": "intent engine disabled"}, status=404)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    message = str(payload.get("message") or "").strip()
    preview_mode = bool(payload.get("preview"))
    if not message:
        return JsonResponse({"error": "message is required"}, status=400)

    context_payload = payload.get("context") if isinstance(payload.get("context"), dict) else {}
    context_workspace_id = str(context_payload.get("workspace_id") or "").strip()
    context_artifact_id = str(context_payload.get("artifact_id") or "").strip()
    context_artifact_type = str(context_payload.get("artifact_type") or "").strip()
    context_thread_id = str(context_payload.get("thread_id") or "").strip()
    request_id = str(uuid.uuid4())
    if not preview_mode:
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="queued",
            prompt=message,
            request_type="intent.resolve",
            workspace_id=context_workspace_id,
            summary="Prompt accepted for intent resolution.",
            thread_id=context_thread_id,
        )

    # Preserved legacy non-Epic-D branch: app-builder prompts still create draft
    # payloads directly and are intentionally outside the v1 Epic D families.
    app_builder_request = _match_app_builder_command(message)
    if app_builder_request:
        operator_workspace = _resolve_workspace_for_identity(identity, context_workspace_id)
        if not operator_workspace:
            return JsonResponse({"error": "workspace context is required for app builder flow"}, status=400)
        response_payload = {
            "status": "DraftReady",
            "action_type": "CreateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": "Will create and submit an app intent draft.",
            "draft_payload": {
                "__operation": str(app_builder_request.get("operation") or "create_app_intent_draft"),
                "workspace_id": str(operator_workspace.id),
                "title": str(app_builder_request.get("title") or "New App"),
                "raw_prompt": str(app_builder_request.get("raw_prompt") or message),
                "initial_intent": app_builder_request.get("initial_intent") if isinstance(app_builder_request.get("initial_intent"), dict) else {},
                "thread_id": context_thread_id or None,
            },
            "next_actions": [{"label": "Create app intent draft", "action": "CreateDraft"}],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=None,
                proposal={"action_type": "CreateDraft", "artifact_type": "Workspace", "operation": "create_app_intent_draft", "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="completed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=str(operator_workspace.id),
                summary=response_payload["summary"],
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)

    operator_workspace = _resolve_workspace_for_identity(identity, context_workspace_id)
    generated_workspace = operator_workspace if isinstance(operator_workspace, Workspace) else None
    generated_runtime_target = _workspace_runtime_target(generated_workspace, "net-inventory") if generated_workspace else None
    generated_artifact_issue = _workspace_generated_artifact_issue(generated_workspace, "net-inventory") if generated_workspace else None
    if (
        generated_workspace
        and generated_runtime_target
        and generated_artifact_issue
        and _looks_like_generated_crud_prompt(message)
        and not _match_generated_app_evolution_command(message, generated_workspace)
    ):
        response_payload = {
            "status": "ValidationError",
            "action_type": "CreateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": "Generated app contract is unavailable for the installed artifact.",
            "validation_errors": ["Generated app contract is unavailable for this installed artifact. Rebuild or reinstall the app."],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="failed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=str(operator_workspace.id),
                summary=response_payload["summary"],
                error=str(generated_artifact_issue.get("reason") or "invalid_generated_artifact_contract"),
                trace=[
                    _generated_trace_step("user_command", source="agent", prompt=message),
                    _generated_trace_step("invalid_generated_artifact_contract", **generated_artifact_issue),
                ],
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload, status=409)
    core_surface_request = _match_core_surface_command(message)
    if core_surface_request:
        panel_key, params = core_surface_request
        if panel_key == "campaign_list":
            action_label = "Open campaigns"
            summary = "Will open campaigns."
        else:
            action_label = "Open platform settings"
            summary = "Will open platform settings."
        prompt_interpretation = _direct_panel_prompt_interpretation(
            intent_type="open_view",
            action_label=action_label,
            resolution_notes=["resolved as a direct platform surface navigation action"],
        )
        response_payload = {
            "status": "IntentResolved",
            "action_type": "ValidateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": summary,
            "prompt_interpretation": prompt_interpretation,
            "next_actions": [
                {"label": "Open panel", "action": "OpenPanel", "panel_key": panel_key, "params": params},
            ],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=None,
                proposal={"operation": "open_core_surface", "panel_key": panel_key, "params": params, "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="completed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=context_workspace_id,
                summary=response_payload["summary"],
                prompt_interpretation=prompt_interpretation,
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)
    rules_panel_request = _match_rules_panel_command(message)
    if rules_panel_request:
        panel_key, params = rules_panel_request
        prompt_interpretation = _direct_panel_prompt_interpretation(
            intent_type="open_rules_panel",
            action_label="Open rules browser",
            resolution_notes=["resolved as a direct policy bundle and rules navigation action"],
        )
        response_payload = {
            "status": "IntentResolved",
            "action_type": "ValidateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": "Will open rules browser.",
            "prompt_interpretation": prompt_interpretation,
            "next_actions": [
                {"label": "Open panel", "action": "OpenPanel", "panel_key": panel_key, "params": params},
            ],
            "audit": {
                "request_id": str(uuid.uuid4()),
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=None,
                proposal={"operation": "open_rules_panel", "panel_key": panel_key, "params": params, "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="completed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=context_workspace_id,
                summary=response_payload["summary"],
                prompt_interpretation=prompt_interpretation,
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)

    artifact_panel_request = _match_artifact_panel_command(message)
    if artifact_panel_request:
        panel_key, params = artifact_panel_request
        prompt_interpretation = _direct_panel_prompt_interpretation(
            intent_type="open_artifact_panel",
            action_label="Open artifact view",
            target_entity_key="artifacts" if panel_key == "artifact_list" else "",
            target_entity_label="Artifacts" if panel_key == "artifact_list" else "",
            resolution_notes=["resolved as a direct artifact navigation action"],
        )
        response_payload = {
            "status": "IntentResolved",
            "action_type": "ValidateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": "Will open artifact panel.",
            "prompt_interpretation": prompt_interpretation,
            "next_actions": [
                {"label": "Open panel", "action": "OpenPanel", "panel_key": panel_key, "params": params},
            ],
            "audit": {
                "request_id": str(uuid.uuid4()),
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=None,
                proposal={"operation": "open_artifact_panel", "panel_key": panel_key, "params": params, "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="completed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=context_workspace_id,
                summary=response_payload["summary"],
                prompt_interpretation=prompt_interpretation,
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)
    artifact_filter_unsupported_reason = _unsupported_artifact_filter_reason(message)
    if artifact_filter_unsupported_reason:
        prompt_interpretation = _direct_panel_prompt_interpretation(
            intent_type="unsupported_artifact_filter",
            action_label="Open artifact view",
            target_entity_key="artifacts",
            target_entity_label="Artifacts",
            resolution_notes=[artifact_filter_unsupported_reason],
        )
        response_payload = {
            "status": "UnsupportedIntent",
            "action_type": "ValidateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": artifact_filter_unsupported_reason,
            "prompt_interpretation": prompt_interpretation,
            "next_actions": [],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=None,
                proposal={"operation": "unsupported_artifact_filter", "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="failed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=context_workspace_id,
                summary=response_payload["summary"],
                error=artifact_filter_unsupported_reason,
                prompt_interpretation=prompt_interpretation,
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)
    worker_mention = _parse_worker_mention(message)
    resolved_message = str(worker_mention.get("clean_message") or message).strip() or message
    epic_d_engine = _intent_engine(identity=identity, workspace=operator_workspace)
    epic_d_intent = epic_d_engine.resolve_intent(
        user_message=resolved_message,
        context=ResolutionContext(
            artifact=None,
            workspace_id=str(operator_workspace.id) if operator_workspace else context_workspace_id,
            user_identity_id=str(identity.id),
            worker_mention_token=str(worker_mention.get("mention_token") or ""),
            requested_worker_type=str(worker_mention.get("worker_type") or ""),
            requested_worker_id=str(worker_mention.get("worker_id") or ""),
            requested_worker_status=str(worker_mention.get("status") or ""),
            requested_worker_capabilities=worker_mention.get("capabilities") if isinstance(worker_mention.get("capabilities"), list) else [],
            worker_mention_error=str(worker_mention.get("error") or ""),
            conversation_context=(
                _conversation_execution_context(identity, str(operator_workspace.id), context_thread_id)
                if operator_workspace
                else None
            ),
        ),
    )
    epic_d_payload = epic_d_intent.model_dump(mode="json")
    generated_app_evolution = _match_generated_app_evolution_command(message, generated_workspace) if generated_workspace else None
    prompt_interpretation = _prompt_interpretation_from_intent(
        message=message,
        intent_payload=epic_d_payload,
        resolution_status="IntentClarificationRequired" if epic_d_intent.needs_clarification else "IntentResolved",
        summary=str((epic_d_intent.resolution_notes or [""])[0] or ""),
    )
    conversation_action = _conversation_action_from_intent(
        source_message_id=request_id,
        intent_payload=epic_d_payload,
        prompt_interpretation=prompt_interpretation,
        thread_id=context_thread_id,
    )
    epic_d_trace = [{"step": "intent_resolved", "intent": epic_d_payload}]
    # Epic D is authoritative only for the supported v1 families:
    # development_work, app_operation, and run_supervision. Everything below this
    # branch that does not return here is preserved legacy routing.
    if (
        (epic_d_intent.needs_clarification and not generated_app_evolution)
        or str(epic_d_intent.intent_type or "") != "unsupported_intent"
    ):
        if str(epic_d_intent.intent_family or "") == "app_operation" and str(epic_d_intent.intent_type or "") in {
            "create_record",
            "update_record",
            "delete_record",
            "list_records",
            "get_record",
        }:
            if not operator_workspace:
                response_payload = {
                    "status": "UnsupportedIntent",
                    "summary": "Workspace context is required for generated app operations.",
                    "intent": epic_d_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": conversation_action,
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
                if not preview_mode:
                    _audit_intent_event(
                        message="intent.resolve",
                        identity=identity,
                        request_id=request_id,
                        artifact_id=None,
                        proposal={"epic_d_intent": epic_d_payload, "prompt": message},
                        resolution=response_payload,
                    )
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=message,
                        request_type="intent.resolve",
                        workspace_id=context_workspace_id,
                        summary=response_payload["summary"],
                        error="missing workspace context",
                        trace=epic_d_trace,
                        structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=context_thread_id,
                    )
                return JsonResponse(response_payload, status=400)
            response_payload = {
                "status": "DraftReady",
                "action_type": "CreateDraft",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": f"Will execute generated app {epic_d_payload.get('intent_type')} intent.",
                "draft_payload": {
                    "__operation": "execute_generated_app_crud",
                    "workspace_id": str(operator_workspace.id),
                    "raw_prompt": message,
                    "structured_operation": epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                    "thread_id": context_thread_id or None,
                },
                "intent": epic_d_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": conversation_action,
                "next_actions": [{"label": "Execute generated app command", "action": "CreateDraft"}],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
            if not preview_mode:
                _audit_intent_event(
                    message="intent.resolve",
                    identity=identity,
                    request_id=request_id,
                    artifact_id=None,
                    proposal={"epic_d_intent": epic_d_payload, "prompt": message},
                    resolution=response_payload,
                )
                _log_prompt_activity(
                    request_id=request_id,
                    identity=identity,
                    status="completed",
                    prompt=message,
                    request_type="intent.resolve",
                    workspace_id=str(operator_workspace.id),
                    summary=response_payload["summary"],
                    trace=epic_d_trace,
                    structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                    prompt_interpretation=prompt_interpretation,
                    conversation_action=conversation_action,
                    thread_id=context_thread_id,
                )
            return JsonResponse(response_payload)
        reuse_existing_work_item = (
            str(epic_d_intent.intent_family or "") == "development_work"
            and str(epic_d_intent.intent_type or "") == "create_and_dispatch_run"
            and not bool(str(context_thread_id or "").strip())
            and bool(
                str(
                    (
                        (epic_d_payload.get("resolved_subject") or {})
                        if isinstance(epic_d_payload.get("resolved_subject"), dict)
                        else {}
                    ).get("work_item_id")
                    or ""
                ).strip()
            )
            and not bool(
                str(
                    (
                        (epic_d_payload.get("resolved_subject") or {})
                        if isinstance(epic_d_payload.get("resolved_subject"), dict)
                        else {}
                    ).get("id")
                    or ""
                ).strip()
            )
        )
        if conversation_action and not reuse_existing_work_item:
            direct_panel_target = _direct_panel_target_for_conversation_action(
                action_type=str(conversation_action.get("action_type") or "").strip(),
                workspace_id=str(operator_workspace.id) if operator_workspace else context_workspace_id,
                action_payload=((conversation_action.get("payload") or {}) if isinstance(conversation_action.get("payload"), dict) else {}).get("action_payload"),
                target=(conversation_action.get("target_object") if isinstance(conversation_action.get("target_object"), dict) else {}),
            )
            if direct_panel_target:
                panel_key, params = direct_panel_target
                response_payload = {
                    "status": "IntentResolved",
                    "action_type": "ValidateDraft",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": str((epic_d_intent.resolution_notes or ["Intent resolved."])[0] or "Intent resolved."),
                    "intent": epic_d_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": conversation_action,
                    "next_actions": [{"label": "Open panel", "action": "OpenPanel", "panel_key": panel_key, "params": params}],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
                if not preview_mode:
                    _audit_intent_event(
                        message="intent.resolve",
                        identity=identity,
                        request_id=request_id,
                        artifact_id=None,
                        proposal={"epic_d_intent": epic_d_payload, "prompt": message},
                        resolution=response_payload,
                    )
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="completed",
                        prompt=message,
                        request_type="intent.resolve",
                        workspace_id=str(operator_workspace.id) if operator_workspace else context_workspace_id,
                        summary=response_payload["summary"],
                        trace=epic_d_trace,
                        structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=context_thread_id,
                    )
                return JsonResponse(response_payload)
            response_payload = {
                "status": "DraftReady",
                "action_type": "CreateDraft",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": (
                    str((epic_d_intent.resolution_notes or ["Ready to execute conversation action."])[0])
                    or "Ready to execute conversation action."
                ),
                "draft_payload": {
                    "__operation": "execute_conversation_action",
                    "workspace_id": str(operator_workspace.id) if operator_workspace else context_workspace_id,
                    "raw_prompt": message,
                    "intent": epic_d_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": conversation_action,
                    "thread_id": context_thread_id or None,
                },
                "intent": epic_d_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": conversation_action,
                "next_actions": [{"label": "Execute conversation action", "action": "CreateDraft"}],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
            if not preview_mode:
                _audit_intent_event(
                    message="intent.resolve",
                    identity=identity,
                    request_id=request_id,
                    artifact_id=None,
                    proposal={"epic_d_intent": epic_d_payload, "prompt": message},
                    resolution=response_payload,
                )
                _log_prompt_activity(
                    request_id=request_id,
                    identity=identity,
                    status="completed",
                    prompt=message,
                    request_type="intent.resolve",
                    workspace_id=str(operator_workspace.id) if operator_workspace else context_workspace_id,
                    summary=response_payload["summary"],
                    trace=epic_d_trace,
                    structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                    prompt_interpretation=prompt_interpretation,
                    conversation_action=conversation_action,
                    thread_id=context_thread_id,
                )
            return JsonResponse(response_payload)
        response_payload = {
            "status": "IntentClarificationRequired" if epic_d_intent.needs_clarification else "IntentResolved",
            "summary": (
                str((epic_d_intent.resolution_notes or ["clarification required"])[0])
                if epic_d_intent.needs_clarification
                else str((epic_d_intent.resolution_notes or ["Intent resolved."])[0])
            ),
            "intent": epic_d_payload,
            "prompt_interpretation": prompt_interpretation,
            "conversation_action": conversation_action,
            "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
        }
        if str(epic_d_intent.intent_type or "") == "unsupported_declared_entity":
            response_payload["status"] = "UnsupportedIntent"
            response_payload["summary"] = str((epic_d_intent.resolution_notes or ["Requested entity is not declared in the installed capability manifest."])[0])
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=None,
                proposal={"epic_d_intent": epic_d_payload, "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="failed" if response_payload["status"] in {"UnsupportedIntent"} else "completed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=str(operator_workspace.id) if operator_workspace else context_workspace_id,
                summary=str(response_payload.get("summary") or ""),
                error=str(epic_d_intent.clarification_reason or "") if epic_d_intent.needs_clarification else "",
                trace=epic_d_trace,
                structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                prompt_interpretation=prompt_interpretation,
                conversation_action=conversation_action,
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)

    # Preserved legacy generated-app and draft-routing behavior below this point.
    # These flows intentionally remain outside Epic D until they are migrated.
    generated_capability_manifest = _workspace_installed_capability_manifest(generated_workspace, "net-inventory") if generated_workspace else None
    if (
        generated_workspace
        and generated_runtime_target
        and generated_artifact_issue
        and _looks_like_generated_crud_prompt(message)
        and not _match_generated_app_evolution_command(message, generated_workspace)
    ):
        response_payload = {
            "status": "ValidationError",
            "action_type": "CreateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": "Generated app contract is unavailable for the installed artifact.",
            "validation_errors": ["Generated app contract is unavailable for this installed artifact. Rebuild or reinstall the app."],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="failed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=str(operator_workspace.id),
                summary=response_payload["summary"],
                error=str(generated_artifact_issue.get("reason") or "invalid_generated_artifact_contract"),
                trace=[
                    _generated_trace_step("user_command", source="agent", prompt=message),
                    _generated_trace_step("invalid_generated_artifact_contract", **generated_artifact_issue),
                ],
            )
        return JsonResponse(response_payload, status=409)
    generated_structured = (
        _resolve_generated_entity_operation_with_runtime(
            prompt=message,
            capability_manifest=generated_capability_manifest,
            runtime_base_url=str(generated_runtime_target.get("runtime_base_url") or ""),
            workspace=generated_workspace,
        )
        if generated_workspace and generated_runtime_target and generated_capability_manifest
        else None
    )
    if generated_workspace and generated_runtime_target and generated_capability_manifest and generated_structured:
        generated_artifact = _installed_generated_artifact(generated_workspace, "net-inventory")
        normalized = _normalized_generated_operation(generated_structured)
        contract = generated_structured.get("contract") if isinstance(generated_structured.get("contract"), dict) else {}
        trace = [
            _generated_trace_step("user_command", source="agent", prompt=message),
            _generated_trace_step("parsed_intent", structured_operation=normalized),
            _generated_trace_step(
                "entity_contract_consulted",
                entity_key=str(contract.get("key") or "").strip(),
                operation=str(generated_structured.get("operation") or "").strip(),
                declared_operations=sorted(
                    name
                    for name, spec in ((contract.get("operations") if isinstance(contract.get("operations"), dict) else {}) or {}).items()
                    if isinstance(spec, dict) and bool(spec.get("declared"))
                ),
                title_field=_entity_title_field(contract),
            ),
        ]
        response_payload = {
            "status": "DraftReady",
            "action_type": "CreateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": f'Will execute generated app {normalized.get("operation") or "operation"} for {normalized.get("entity_key") or "entity"}.',
            "draft_payload": {
                "__operation": "execute_generated_app_crud",
                "workspace_id": str(generated_workspace.id),
                "raw_prompt": message,
                "structured_operation": normalized,
            },
            "next_actions": [{"label": "Execute generated app command", "action": "CreateDraft"}],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=str(generated_artifact.id) if generated_artifact else None,
                proposal={"action_type": "CreateDraft", "artifact_type": "Workspace", "operation": "execute_generated_app_crud", "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="completed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=str(generated_workspace.id),
                summary=response_payload["summary"],
                trace=trace,
                structured_operation=normalized,
            )
        return JsonResponse(response_payload)

    if generated_app_evolution:
        response_payload = {
            "status": "DraftReady",
            "action_type": "CreateDraft",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": "Will create and submit a revision draft for the installed generated app.",
            "draft_payload": {
                "__operation": "evolve_app_intent_draft",
                "workspace_id": str(generated_workspace.id),
                "title": str(generated_app_evolution.get("title") or "Generated App"),
                "raw_prompt": str(generated_app_evolution.get("raw_prompt") or message),
                "initial_intent": generated_app_evolution.get("initial_intent") if isinstance(generated_app_evolution.get("initial_intent"), dict) else {},
                "revision_anchor": generated_app_evolution.get("revision_anchor") if isinstance(generated_app_evolution.get("revision_anchor"), dict) else {},
                "current_app_summary": generated_app_evolution.get("current_app_summary") if isinstance(generated_app_evolution.get("current_app_summary"), dict) else {},
                "current_app_spec": generated_app_evolution.get("current_app_spec") if isinstance(generated_app_evolution.get("current_app_spec"), dict) else {},
                "latest_appspec_ref": generated_app_evolution.get("latest_appspec_ref") if isinstance(generated_app_evolution.get("latest_appspec_ref"), dict) else {},
            },
            "next_actions": [{"label": "Create revision draft", "action": "CreateDraft"}],
            "audit": {
                "request_id": request_id,
                "timestamp": timezone.now().isoformat(),
            },
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=str((generated_app_evolution.get("revision_anchor") or {}).get("artifact_id") or ""),
                proposal={
                    "action_type": "CreateDraft",
                    "artifact_type": "Workspace",
                    "operation": "evolve_app_intent_draft",
                    "prompt": message,
                    "revision_anchor": generated_app_evolution.get("revision_anchor") if isinstance(generated_app_evolution.get("revision_anchor"), dict) else {},
                },
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="completed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=str(generated_workspace.id),
                summary=response_payload["summary"],
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)

    remote_provision_request = _match_provision_xyn_remote_command(message)
    if remote_provision_request:
        operator_workspace = _resolve_workspace_for_identity(identity, context_workspace_id)
        if not operator_workspace:
            return JsonResponse({"error": "workspace context is required for remote provisioning flow"}, status=400)
        return JsonResponse(
            {
                "status": "DraftReady",
                "action_type": "CreateDraft",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": "Will provision a remote Xyn instance via SSH + docker compose.",
                "draft_payload": {
                    "__operation": "deploy_release_spec",
                    "customer_name": str(remote_provision_request.get("customer_name") or "Customer"),
                    "fqdn": str(remote_provision_request.get("fqdn") or ""),
                    "operator_workspace_id": str(operator_workspace.id),
                    "target_environment": "local",
                    "instance_ref": {"artifact_id": str(remote_provision_request.get("instance_ref") or "xyn-ec2-demo")},
                    "instance_label": str(remote_provision_request.get("instance_label") or ""),
                    "dns": {"enabled": bool(remote_provision_request.get("dns_enabled", True)), "ttl": 60},
                    "include_ems": bool(remote_provision_request.get("include_ems", False)),
                    "dry_run": False,
                    "tls_mode": "letsencrypt",
                },
                "next_actions": [
                    {"label": "Provision Xyn instance (remote)", "action": "CreateDraft"},
                ],
                "audit": {
                    "request_id": str(uuid.uuid4()),
                    "timestamp": timezone.now().isoformat(),
                },
            }
        )

    xyn_instance_request = _match_install_xyn_instance_command(message)
    if xyn_instance_request:
        customer_name, fqdn, instance_ref, dns_enabled, dns_mode = xyn_instance_request
        operator_workspace = _resolve_workspace_for_identity(identity, context_workspace_id)
        if not operator_workspace:
            return JsonResponse({"error": "workspace context is required for xyn instance install flow"}, status=400)
        return JsonResponse(
            {
                "status": "DraftReady",
                "action_type": "CreateDraft",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": (
                    f'Will create/find workspace for "{customer_name}", install xyn runtime artifacts, '
                    f"and configure deployment for {fqdn} using instance {instance_ref}."
                ),
                "draft_payload": {
                    "__operation": "deploy_release_spec",
                    "customer_name": customer_name,
                    "fqdn": fqdn,
                    "operator_workspace_id": str(operator_workspace.id),
                    "target_environment": "local",
                    "dns_mode": dns_mode,
                    "dns": {"enabled": dns_enabled, "ttl": 60},
                    "instance_ref": {"artifact_id": instance_ref},
                    "tls_mode": "letsencrypt",
                },
                "next_actions": [
                    {"label": "Install Xyn Instance", "action": "CreateDraft"},
                ],
                "audit": {
                    "request_id": str(uuid.uuid4()),
                    "timestamp": timezone.now().isoformat(),
                },
            }
        )

    ems_instance_request = _match_create_ems_instance_command(message)
    if ems_instance_request:
        customer_name, fqdn = ems_instance_request
        operator_workspace = _resolve_workspace_for_identity(identity, context_workspace_id)
        if not operator_workspace:
            return JsonResponse({"error": "workspace context is required for EMS instance provisioning flow"}, status=400)
        return JsonResponse(
            {
                "status": "DraftReady",
                "action_type": "CreateDraft",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": (
                    f'Will create/find workspace for "{customer_name}", install EMS, '
                    f'and provision local app instance for {fqdn}.'
                ),
                "draft_payload": {
                    "__operation": "create_ems_instance",
                    "customer_name": customer_name,
                    "fqdn": fqdn,
                    "operator_workspace_id": str(operator_workspace.id),
                    "deployment_target": "local",
                },
                "next_actions": [
                    {"label": "Create EMS Instance", "action": "CreateDraft"},
                ],
                "audit": {
                    "request_id": str(uuid.uuid4()),
                    "timestamp": timezone.now().isoformat(),
                },
            }
        )

    ems_panel_request = _match_ems_panel_command(message)
    if ems_panel_request:
        panel_key, params = ems_panel_request
        operator_workspace = _resolve_workspace_for_identity(identity, context_workspace_id)
        if not operator_workspace:
            return JsonResponse({"error": "workspace context is required for EMS panel flow"}, status=400)
        return JsonResponse(
            {
                "status": "DraftReady",
                "action_type": "CreateDraft",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": "Will open EMS panel.",
                "draft_payload": {
                    "__operation": "open_ems_panel",
                    "panel_key": panel_key,
                    "params": params,
                    "operator_workspace_id": str(operator_workspace.id),
                },
                "next_actions": [
                    {"label": "Open panel", "action": "CreateDraft"},
                ],
                "audit": {
                    "request_id": str(uuid.uuid4()),
                    "timestamp": timezone.now().isoformat(),
                },
            }
        )

    customer_name = _match_deploy_ems_customer_command(message)
    if customer_name:
        operator_workspace = _resolve_workspace_for_identity(identity, context_workspace_id)
        if not operator_workspace:
            return JsonResponse({"error": "workspace context is required for deploy EMS customer flow"}, status=400)
        return JsonResponse(
            {
                "status": "DraftReady",
                "action_type": "CreateDraft",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": f'Will create customer workspace "{customer_name}" under "{operator_workspace.name}" and install EMS.',
                "draft_payload": {
                    "__operation": "deploy_ems_customer",
                    "customer_name": customer_name,
                    "operator_workspace_id": str(operator_workspace.id),
                    "kind": "customer",
                    "lifecycle_stage": "prospect",
                },
                "next_actions": [
                    {"label": "Create workspace + install EMS", "action": "CreateDraft"},
                ],
                "audit": {
                    "request_id": str(uuid.uuid4()),
                    "timestamp": timezone.now().isoformat(),
                },
            }
        )

    context_artifact = None
    if context_artifact_id:
        normalized_context_type = str(context_artifact_type or "").strip().lower()
        if normalized_context_type in {"contextpack", "context_pack"}:
            context_artifact = _resolve_context_pack_artifact_or_404(context_artifact_id)
            if not _can_manage_docs(identity):
                return JsonResponse({"error": "forbidden"}, status=403)
        else:
            context_artifact = _resolve_article_or_404(context_artifact_id)
            if not _can_edit_article(identity, context_artifact):
                return JsonResponse({"error": "forbidden"}, status=403)
            if context_artifact_type and context_artifact_type not in {"ArticleDraft", "article"}:
                return JsonResponse({"error": "unsupported artifact_type context"}, status=400)

    if not _should_use_legacy_intake_fallback(message, context_artifact=context_artifact):
        response_payload = {
            "status": "UnsupportedIntent",
            "summary": str((epic_d_intent.resolution_notes or ["Intent is unsupported in the current resolver scope."])[0]),
            "intent": epic_d_payload,
            "prompt_interpretation": prompt_interpretation,
            "conversation_action": conversation_action,
            "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
        }
        if not preview_mode:
            _audit_intent_event(
                message="intent.resolve",
                identity=identity,
                request_id=request_id,
                artifact_id=str(context_artifact.id) if context_artifact else None,
                proposal={"epic_d_intent": epic_d_payload, "prompt": message},
                resolution=response_payload,
            )
            _log_prompt_activity(
                request_id=request_id,
                identity=identity,
                status="failed",
                prompt=message,
                request_type="intent.resolve",
                workspace_id=context_workspace_id,
                summary=str(response_payload.get("summary") or ""),
                error=str(epic_d_intent.clarification_reason or ""),
                trace=epic_d_trace,
                structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                prompt_interpretation=prompt_interpretation,
                conversation_action=conversation_action,
                thread_id=context_thread_id,
            )
        return JsonResponse(response_payload)

    engine = _intent_engine()
    result, proposal = engine.resolve(message=message, context=ResolutionContext(artifact=context_artifact))
    if context_artifact is not None:
        result["artifact_id"] = str(context_artifact.id)

    request_id = str((result.get("audit") or {}).get("request_id") or request_id)
    if isinstance(proposal, dict):
        proposal["_prompt"] = message
    intent_telemetry_increment(
        {
            "DraftReady": "resolve_success",
            "MissingFields": "resolve_missing_fields",
            "ValidationError": "resolve_validation_error",
        }.get(str(result.get("status") or ""), "resolve_success")
    )
    if not preview_mode:
        _audit_intent_event(
            message="intent.resolve",
            identity=identity,
            request_id=request_id,
            artifact_id=str(context_artifact.id) if context_artifact else None,
            proposal=proposal,
            resolution=result,
        )
        _log_prompt_activity(
            request_id=request_id,
            identity=identity,
            status="failed" if str(result.get("status") or "") in {"UnsupportedIntent", "ValidationError"} else "completed",
            prompt=message,
            request_type="intent.resolve",
            workspace_id=context_workspace_id,
            summary=str(result.get("summary") or ""),
            error=str((result.get("validation_errors") or [""])[0] or "") if str(result.get("status") or "") in {"UnsupportedIntent", "ValidationError"} else "",
            thread_id=context_thread_id,
            ai_resolution=proposal.get("_ai_resolution") if isinstance(proposal, dict) and isinstance(proposal.get("_ai_resolution"), dict) else None,
        )
    return JsonResponse(result)


@csrf_exempt
def xyn_intent_apply(request: HttpRequest) -> JsonResponse:
    if not _intent_engine_enabled():
        return JsonResponse({"error": "intent engine disabled"}, status=404)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)

    payload = _parse_json(request)
    action_type = str(payload.get("action_type") or "").strip()
    artifact_type = str(payload.get("artifact_type") or "").strip()
    body_payload = payload.get("payload") if isinstance(payload.get("payload"), dict) else {}
    thread_id = str(payload.get("thread_id") or body_payload.get("thread_id") or "").strip()
    request_id = str(uuid.uuid4())
    _log_prompt_activity(
        request_id=request_id,
        identity=identity,
        status="running",
        prompt=str(body_payload.get("raw_prompt") or payload.get("message") or ""),
        request_type="intent.apply",
        workspace_id=str(body_payload.get("workspace_id") or body_payload.get("operator_workspace_id") or ""),
        summary=f"Applying intent action {action_type or 'unknown'}.",
        thread_id=thread_id,
    )

    if action_type not in {"CreateDraft", "ApplyPatch"}:
        return JsonResponse({"error": "action_type must be CreateDraft or ApplyPatch"}, status=400)
    if action_type == "CreateDraft":
        if artifact_type not in {"ArticleDraft", "Workspace"}:
            return JsonResponse({"error": "artifact_type must be ArticleDraft or Workspace"}, status=400)
    else:
        if artifact_type not in {"ArticleDraft", "ContextPack"}:
            return JsonResponse({"error": "artifact_type must be ArticleDraft or ContextPack"}, status=400)

    if action_type == "CreateDraft":
        if artifact_type != "ArticleDraft":
            operation = str(body_payload.get("__operation") or "").strip().lower()
            if operation == "deploy_ems_customer":
                return _intent_apply_deploy_ems_customer(identity=identity, payload=body_payload, request_id=request_id)
            if operation == "create_ems_instance":
                return _intent_apply_create_ems_instance(identity=identity, payload=body_payload, request_id=request_id)
            if operation == "install_xyn_instance":
                return _intent_apply_install_xyn_instance(identity=identity, payload=body_payload, request_id=request_id)
            if operation == "deploy_release_spec":
                return _intent_apply_provision_xyn_remote(identity=identity, payload=body_payload, request_id=request_id)
            if operation == "open_ems_panel":
                return _intent_apply_open_ems_panel(identity=identity, payload=body_payload, request_id=request_id)
            if operation == "open_artifact_panel":
                return _intent_apply_open_artifact_panel(identity=identity, payload=body_payload, request_id=request_id)
            if operation == "execute_conversation_action":
                workspace = _resolve_workspace_for_identity(identity, str(body_payload.get("workspace_id") or "").strip())
                if not workspace:
                    return JsonResponse({"error": "workspace context is required for conversation actions"}, status=400)
                raw_prompt = str(body_payload.get("raw_prompt") or payload.get("message") or "").strip()
                worker_mention = _parse_worker_mention(raw_prompt)
                resolved_message = str(worker_mention.get("clean_message") or raw_prompt).strip() or raw_prompt
                epic_d_intent = _intent_engine(identity=identity, workspace=workspace).resolve_intent(
                    user_message=resolved_message,
                    context=ResolutionContext(
                        artifact=None,
                        workspace_id=str(workspace.id),
                        user_identity_id=str(identity.id),
                        worker_mention_token=str(worker_mention.get("mention_token") or ""),
                        requested_worker_type=str(worker_mention.get("worker_type") or ""),
                        requested_worker_id=str(worker_mention.get("worker_id") or ""),
                        requested_worker_status=str(worker_mention.get("status") or ""),
                        requested_worker_capabilities=worker_mention.get("capabilities") if isinstance(worker_mention.get("capabilities"), list) else [],
                        worker_mention_error=str(worker_mention.get("error") or ""),
                        conversation_context=_conversation_execution_context(identity, str(workspace.id), thread_id),
                    ),
                )
                epic_d_payload = epic_d_intent.model_dump(mode="json")
                prompt_interpretation = _prompt_interpretation_from_intent(
                    message=raw_prompt,
                    intent_payload=epic_d_payload,
                    resolution_status=(
                        "UnsupportedIntent"
                        if str(epic_d_intent.intent_type or "") == "unsupported_declared_entity"
                        else "IntentClarificationRequired"
                        if epic_d_intent.needs_clarification
                        else "IntentResolved"
                    ),
                    summary=str((epic_d_intent.resolution_notes or [""])[0] or ""),
                )
                conversation_action = _conversation_action_from_intent(
                    source_message_id=request_id,
                    intent_payload=epic_d_payload,
                    prompt_interpretation=prompt_interpretation,
                    thread_id=thread_id,
                )
                if epic_d_intent.needs_clarification:
                    result_payload = {
                        "status": "IntentClarificationRequired",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": str((epic_d_intent.resolution_notes or ["clarification required"])[0]),
                        "intent": epic_d_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": conversation_action,
                        "operation_result": False,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary=result_payload["summary"],
                        error=str(epic_d_intent.clarification_reason or "clarification required"),
                        trace=[{"step": "intent_resolved", "intent": epic_d_payload}],
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=thread_id,
                    )
                    return JsonResponse(result_payload, status=409)
                if str(epic_d_intent.intent_type or "") in {"unsupported_declared_entity", "unsupported_intent"} or not conversation_action:
                    result_payload = {
                        "status": "UnsupportedIntent",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": str((epic_d_intent.resolution_notes or ["Conversation action is not supported."])[0]),
                        "intent": epic_d_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": conversation_action,
                        "operation_result": False,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary=result_payload["summary"],
                        error="unsupported conversation action",
                        trace=[{"step": "intent_resolved", "intent": epic_d_payload}],
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=thread_id,
                    )
                    return JsonResponse(result_payload, status=409)
                try:
                    response = _execute_conversation_action(
                        identity=identity,
                        user=request.user,
                        workspace=workspace,
                        action=conversation_action,
                        prompt=raw_prompt,
                        request_id=request_id,
                        intent_payload=epic_d_payload,
                        prompt_interpretation=prompt_interpretation,
                    )
                except RuntimeError as exc:
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary="Conversation action failed.",
                        error=str(exc),
                        trace=[{"step": "intent_resolved", "intent": epic_d_payload}, {"step": "conversation_action_failed", "error": str(exc)}],
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=thread_id,
                    )
                    return JsonResponse(
                        {
                            "status": "ValidationError",
                            "artifact_type": "Workspace",
                            "artifact_id": None,
                            "summary": "Conversation action failed.",
                            "validation_errors": [str(exc)],
                            "intent": epic_d_payload,
                            "prompt_interpretation": prompt_interpretation,
                            "conversation_action": conversation_action,
                            "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                        },
                        status=502,
                    )
                result_body = json.loads(response.content.decode("utf-8")) if response.content else {}
                logged_conversation_action = conversation_action
                result_goal = ((result_body.get("result") or {}) if isinstance(result_body.get("result"), dict) else {}).get("goal")
                if isinstance(logged_conversation_action, dict) and isinstance(result_goal, dict):
                    target_object = logged_conversation_action.get("target_object") if isinstance(logged_conversation_action.get("target_object"), dict) else {}
                    if not str(target_object.get("id") or "").strip():
                        logged_conversation_action = {
                            **logged_conversation_action,
                            "target_object": {
                                **target_object,
                                "id": str(result_goal.get("id") or "").strip() or None,
                                "label": str(result_goal.get("title") or target_object.get("label") or "").strip() or None,
                                "workspace_id": str(result_goal.get("workspace_id") or target_object.get("workspace_id") or "").strip() or None,
                            },
                        }
                _log_prompt_activity(
                    request_id=request_id,
                    identity=identity,
                    status="completed" if response.status_code < 400 else "failed",
                    prompt=raw_prompt,
                    request_type="intent.apply",
                    workspace_id=str(workspace.id),
                    summary=str(result_body.get("summary") or "Conversation action complete."),
                    trace=[{"step": "intent_resolved", "intent": epic_d_payload}, {"step": "conversation_action_executed", "action": conversation_action}],
                    structured_operation=result_body.get("result") if isinstance(result_body.get("result"), dict) else {},
                    prompt_interpretation=prompt_interpretation,
                    conversation_action=logged_conversation_action,
                    thread_id=thread_id,
                )
                return response
            if operation == "execute_generated_app_crud":
                workspace = _resolve_workspace_for_identity(identity, str(body_payload.get("workspace_id") or "").strip())
                if not workspace:
                    return JsonResponse({"error": "workspace context is required for generated app operations"}, status=400)
                runtime_target_record = _workspace_runtime_target(workspace, "net-inventory")
                generated_artifact_issue = _workspace_generated_artifact_issue(workspace, "net-inventory")
                capability_manifest = _workspace_installed_capability_manifest(workspace, "net-inventory")
                raw_prompt = str(body_payload.get("raw_prompt") or payload.get("message") or "").strip()
                if (
                    runtime_target_record
                    and generated_artifact_issue
                    and _looks_like_generated_crud_prompt(raw_prompt)
                    and not _match_generated_app_evolution_command(raw_prompt, workspace)
                ):
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary="Generated app contract is unavailable for the installed artifact.",
                        error=str(generated_artifact_issue.get("reason") or "invalid_generated_artifact_contract"),
                        trace=[
                            _generated_trace_step("user_command", source="agent", prompt=raw_prompt),
                            _generated_trace_step("invalid_generated_artifact_contract", **generated_artifact_issue),
                        ],
                        thread_id=thread_id,
                    )
                    return JsonResponse(
                        {
                            "status": "ValidationError",
                            "action_type": "CreateDraft",
                            "artifact_type": "Workspace",
                            "artifact_id": None,
                            "summary": "Generated app contract is unavailable for the installed artifact.",
                            "validation_errors": ["Generated app contract is unavailable for this installed artifact. Rebuild or reinstall the app."],
                            "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                        },
                        status=409,
                    )
                if not runtime_target_record or not capability_manifest:
                    return JsonResponse({"error": "generated app runtime is not available"}, status=404)
                structured_payload = body_payload.get("structured_operation") if isinstance(body_payload.get("structured_operation"), dict) else {}
                structured: Optional[Dict[str, Any]] = None
                if structured_payload:
                    contract = _manifest_entity_contracts(capability_manifest).get(str(structured_payload.get("entity_key") or "").strip())
                    operation_name = str(structured_payload.get("operation") or "").strip()
                    if contract and operation_name:
                        structured = {
                            "operation": operation_name,
                            "entity_key": str(structured_payload.get("entity_key") or "").strip(),
                            "contract": contract,
                            "command_key": str(structured_payload.get("command_key") or "").strip(),
                            "target_reference": str(structured_payload.get("target_reference") or "").strip(),
                            "fields": structured_payload.get("fields") if isinstance(structured_payload.get("fields"), dict) else {},
                            "field_mutations": (
                                structured_payload.get("field_mutations")
                                if isinstance(structured_payload.get("field_mutations"), dict)
                                else {}
                            ),
                            "direct_target_reference": bool(structured_payload.get("direct_target_reference")),
                        }
                epic_d_intent = _intent_engine(identity=identity, workspace=workspace).resolve_intent(
                    user_message=raw_prompt,
                    context=ResolutionContext(
                        artifact=None,
                        workspace_id=str(workspace.id),
                        user_identity_id=str(identity.id),
                        conversation_context=_conversation_execution_context(identity, str(workspace.id), thread_id),
                    ),
                )
                epic_d_payload = epic_d_intent.model_dump(mode="json")
                prompt_interpretation = _prompt_interpretation_from_intent(
                    message=raw_prompt,
                    intent_payload=epic_d_payload,
                    resolution_status=(
                        "UnsupportedIntent"
                        if str(epic_d_intent.intent_type or "") == "unsupported_declared_entity"
                        else "IntentClarificationRequired"
                        if epic_d_intent.needs_clarification
                        else "IntentResolved"
                    ),
                    summary=str((epic_d_intent.resolution_notes or [""])[0] or ""),
                )
                conversation_action = _conversation_action_from_intent(
                    source_message_id=request_id,
                    intent_payload=epic_d_payload,
                    prompt_interpretation=prompt_interpretation,
                    thread_id=thread_id,
                )
                if structured is None and epic_d_intent.needs_clarification:
                    result_payload = {
                        "status": "IntentClarificationRequired",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": str((epic_d_intent.resolution_notes or ["clarification required"])[0]),
                        "intent": epic_d_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": conversation_action,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary=result_payload["summary"],
                        error=str(epic_d_intent.clarification_reason or "clarification required"),
                        trace=[{"step": "intent_resolved", "intent": epic_d_payload}],
                        structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=thread_id,
                    )
                    return JsonResponse(result_payload, status=409)
                if structured is None and str(epic_d_intent.intent_type or "") == "unsupported_declared_entity":
                    result_payload = {
                        "status": "UnsupportedIntent",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": str((epic_d_intent.resolution_notes or ["Requested entity is not declared in the installed capability manifest."])[0]),
                        "intent": epic_d_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": conversation_action,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary=result_payload["summary"],
                        error="unsupported declared entity",
                        trace=[{"step": "intent_resolved", "intent": epic_d_payload}],
                        structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=thread_id,
                    )
                    return JsonResponse(result_payload, status=409)
                if structured is None and (
                    str(epic_d_intent.intent_family or "") != "app_operation"
                    or str(epic_d_intent.intent_type or "") not in {"create_record", "update_record", "delete_record", "list_records", "get_record"}
                ):
                    result_payload = {
                        "status": "UnsupportedIntent",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": "Prompt is not executable as a generated app operation.",
                        "intent": epic_d_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": conversation_action,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary=result_payload["summary"],
                        error="unsupported generated app operation",
                        trace=[{"step": "intent_resolved", "intent": epic_d_payload}],
                        structured_operation=epic_d_payload.get("action_payload") if isinstance(epic_d_payload.get("action_payload"), dict) else {},
                        prompt_interpretation=prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=thread_id,
                    )
                    return JsonResponse(result_payload, status=400)
                if structured is None:
                    structured = _resolve_generated_entity_operation_with_runtime(
                        prompt=raw_prompt,
                        capability_manifest=capability_manifest,
                        runtime_base_url=str(runtime_target_record.get("runtime_base_url") or ""),
                        workspace=workspace,
                    )
                if not structured:
                    result_payload = {
                        "status": "ValidationError",
                        "action_type": "CreateDraft",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": "Generated app operation could not be resolved.",
                        "validation_errors": ["No matching generated app CRUD operation found."],
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary=result_payload["summary"],
                        error="No matching generated app CRUD operation found.",
                        trace=[_generated_trace_step("user_command", source="agent", prompt=raw_prompt), _generated_trace_step("error", error="unresolved_operation")],
                        thread_id=thread_id,
                    )
                    return JsonResponse(result_payload, status=400)
                try:
                    result, trace, normalized = _run_generated_entity_operation(
                        prompt=raw_prompt,
                        structured=structured,
                        capability_manifest=capability_manifest,
                        runtime_base_url=str(runtime_target_record.get("runtime_base_url") or ""),
                        workspace=workspace,
                        source="agent",
                    )
                except RuntimeError as exc:
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary="Generated app operation failed.",
                        error=str(exc),
                        trace=[_generated_trace_step("user_command", source="agent", prompt=raw_prompt), _generated_trace_step("error", error=str(exc))],
                        structured_operation=_normalized_generated_operation(structured),
                        thread_id=thread_id,
                    )
                    return JsonResponse(
                        {
                            "status": "ValidationError",
                            "action_type": "CreateDraft",
                            "artifact_type": "Workspace",
                            "artifact_id": None,
                            "summary": "Generated app operation failed.",
                            "validation_errors": [str(exc)],
                            "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                        },
                        status=502,
                    )
                disambiguation = (
                    (result.get("meta") or {}).get("disambiguation")
                    if isinstance(result, dict) and isinstance(result.get("meta"), dict)
                    else None
                )
                if isinstance(disambiguation, dict):
                    clarification_intent = dict(epic_d_payload)
                    clarification_intent["needs_clarification"] = True
                    clarification_intent["clarification_reason"] = "ambiguous_target"
                    clarification_intent["clarification_options"] = [
                        {
                            "id": str(index),
                            "label": str(match),
                            "kind": str(disambiguation.get("entity_key") or ""),
                            "payload": {},
                        }
                        for index, match in enumerate(disambiguation.get("matches") if isinstance(disambiguation.get("matches"), list) else [], start=1)
                    ]
                    clarification_prompt_interpretation = dict(prompt_interpretation)
                    clarification_prompt_interpretation["needs_clarification"] = True
                    clarification_prompt_interpretation["execution_mode"] = "awaiting_clarification"
                    clarification_prompt_interpretation["clarification_reason"] = "ambiguous_target"
                    clarification_prompt_interpretation["clarification_options"] = clarification_intent["clarification_options"]
                    _log_prompt_activity(
                        request_id=request_id,
                        identity=identity,
                        status="failed",
                        prompt=raw_prompt,
                        request_type="intent.apply",
                        workspace_id=str(workspace.id),
                        summary=str(result.get("text") or "Clarification required."),
                        error="ambiguous target",
                        trace=trace,
                        structured_operation=normalized,
                        prompt_interpretation=clarification_prompt_interpretation,
                        conversation_action=conversation_action,
                        thread_id=thread_id,
                    )
                    return JsonResponse(
                        {
                            "status": "IntentClarificationRequired",
                            "artifact_type": "Workspace",
                            "artifact_id": None,
                            "summary": str(result.get("text") or "Clarification required."),
                            "intent": clarification_intent,
                            "prompt_interpretation": clarification_prompt_interpretation,
                            "conversation_action": conversation_action,
                            "result": result,
                            "structured_operation": normalized,
                            "operation_result": False,
                            "next_actions": [],
                            "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                        },
                        status=409,
                    )
                summary = str(result.get("text") or "Generated app operation complete.")
                _log_prompt_activity(
                    request_id=request_id,
                    identity=identity,
                    status="completed",
                    prompt=raw_prompt,
                    request_type="intent.apply",
                    workspace_id=str(workspace.id),
                    summary=summary,
                    trace=trace,
                    structured_operation=normalized,
                    prompt_interpretation=prompt_interpretation,
                    conversation_action=conversation_action,
                    thread_id=thread_id,
                )
                generated_artifact = _installed_generated_artifact(workspace, "net-inventory")
                return JsonResponse(
                    {
                        "status": "DraftReady",
                        "action_type": "CreateDraft",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": summary,
                        "result": result,
                        "intent": epic_d_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": conversation_action,
                        "structured_operation": normalized,
                        "operation_result": True,
                        "next_actions": [],
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                )
            if operation in {"create_app_intent_draft", "evolve_app_intent_draft"}:
                return _intent_apply_create_app_intent_draft(identity=identity, payload=body_payload, request_id=request_id)
            return JsonResponse({"error": "CreateDraft currently supports ArticleDraft only"}, status=400)
        return _intent_apply_create_draft(identity=identity, payload=body_payload, request_id=request_id)

    artifact_id = str(payload.get("artifact_id") or "").strip()
    if not artifact_id:
        return JsonResponse({"error": "artifact_id is required for ApplyPatch"}, status=400)
    return _intent_apply_patch(
        identity=identity,
        artifact_type=artifact_type,
        artifact_id=artifact_id,
        patch_object=body_payload,
        request_id=request_id,
    )


def xyn_intent_options(request: HttpRequest) -> JsonResponse:
    if not _intent_engine_enabled():
        return JsonResponse({"error": "intent engine disabled"}, status=404)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)
    artifact_type = str(request.GET.get("artifact_type") or "").strip()
    field_name = str(request.GET.get("field") or "").strip().lower()
    if artifact_type not in {"ArticleDraft", "ContextPack"}:
        return JsonResponse({"error": "artifact_type must be ArticleDraft or ContextPack"}, status=400)
    allowed_fields = {"category", "format", "duration"} if artifact_type == "ArticleDraft" else {"format"}
    if field_name not in allowed_fields:
        return JsonResponse({"error": f"field must be {'|'.join(sorted(allowed_fields))}"}, status=400)
    contract = _intent_contract_registry().get(artifact_type)
    options = contract.options_for_field(field_name) if contract else []
    return JsonResponse({"artifact_type": artifact_type, "field": field_name, "options": options})


@csrf_exempt
def ai_invoke(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    agent_slug = str(payload.get("agent_slug") or "").strip()
    if not agent_slug:
        return JsonResponse({"error": "agent_slug is required"}, status=400)
    messages = payload.get("messages")
    if not isinstance(messages, list):
        return JsonResponse({"error": "messages must be a list"}, status=400)
    metadata = payload.get("metadata") if isinstance(payload.get("metadata"), dict) else {}
    # Server owns the system prompt; client-provided system messages are ignored.
    filtered_messages = [msg for msg in messages if isinstance(msg, dict) and str(msg.get("role") or "").strip().lower() != "system"]
    try:
        resolved = resolve_ai_config(agent_slug=agent_slug)
        result = invoke_model(resolved_config=resolved, messages=filtered_messages)
    except (AiConfigError, AiInvokeError) as exc:
        return JsonResponse({"error": str(exc)}, status=400)
    AuditLog.objects.create(
        message="ai_invocation",
        metadata_json={
            "actor_identity_id": str(identity.id),
            "agent_slug": resolved.get("agent_slug") or agent_slug,
            "agent_id": resolved.get("agent_id"),
            "agent_name": resolved.get("agent_name"),
            "provider": resolved.get("provider"),
            "model_name": resolved.get("model_name"),
            "purpose": resolved.get("purpose"),
            "agent_resolution": resolved.get("agent_resolution") if isinstance(resolved.get("agent_resolution"), dict) else {},
            "metadata": metadata,
        },
    )
    return JsonResponse(
        {
            "content": result.get("content") or "",
            "provider": result.get("provider"),
            "model": result.get("model"),
            "usage": result.get("usage"),
            "effective_params": result.get("effective_params") if isinstance(result.get("effective_params"), dict) else {},
            "warnings": result.get("warnings") if isinstance(result.get("warnings"), list) else [],
            "agent_slug": resolved.get("agent_slug") or agent_slug,
            "agent_name": resolved.get("agent_name"),
            "purpose": resolved.get("purpose"),
            "agent_resolution": resolved.get("agent_resolution") if isinstance(resolved.get("agent_resolution"), dict) else {},
        }
    )


@csrf_exempt
def ai_activity(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)

    workspace_id = str(request.GET.get("workspace_id") or "").strip()
    thread_id = str(request.GET.get("thread_id") or "").strip()
    artifact_id = str(request.GET.get("artifact_id") or "").strip()
    limit_raw = str(request.GET.get("limit") or "100").strip()
    try:
        limit = max(1, min(int(limit_raw), 300))
    except ValueError:
        limit = 100

    is_manager = _can_manage_ai(identity)
    if workspace_id and not is_manager and not _workspace_membership(identity, workspace_id):
        return JsonResponse({"error": "forbidden"}, status=403)

    artifact_lookup: Dict[str, Artifact] = {}
    if workspace_id or artifact_id:
        artifact_qs = Artifact.objects.all()
        if artifact_id:
            artifact_qs = artifact_qs.filter(id=artifact_id)
        elif workspace_id:
            artifact_qs = artifact_qs.filter(workspace_id=workspace_id)
        artifact_lookup = {str(item.id): item for item in artifact_qs.select_related("type")}

    items: List[Dict[str, Any]] = []
    audit_qs = AuditLog.objects.filter(message__in=["ai_invocation", "prompt_submission"]).order_by("-created_at")[:1200]
    for entry in audit_qs:
        meta = entry.metadata_json if isinstance(entry.metadata_json, dict) else {}
        actor_identity_id = str(meta.get("actor_identity_id") or "")
        if not is_manager and not workspace_id and actor_identity_id and actor_identity_id != str(identity.id):
            continue
        payload_meta = meta.get("metadata") if isinstance(meta.get("metadata"), dict) else {}
        is_prompt_event = entry.message == "prompt_submission"
        prompt_workspace_id = str(meta.get("workspace_id") or "")
        prompt_thread_id = str(meta.get("thread_id") or "")
        event_thread_id = prompt_thread_id if is_prompt_event else str(payload_meta.get("thread_id") or "")
        event_artifact_id = str((meta.get("artifact_id") if is_prompt_event else payload_meta.get("artifact_id")) or "")
        if artifact_id and event_artifact_id != artifact_id:
            continue
        if thread_id and event_thread_id != thread_id:
            continue
        if workspace_id:
            candidate_workspace_id = prompt_workspace_id if is_prompt_event else str(payload_meta.get("workspace_id") or "")
            if candidate_workspace_id != workspace_id:
                if event_artifact_id and event_artifact_id in artifact_lookup:
                    pass
                else:
                    continue
        artifact = artifact_lookup.get(event_artifact_id) if event_artifact_id else None
        if is_prompt_event:
            raw_status = str(meta.get("status") or "queued").strip().lower()
            if raw_status in {"completed", "succeeded", "success"}:
                status = "succeeded"
            elif raw_status == "failed":
                status = "failed"
            else:
                status = "running"
            prompt_text = str(meta.get("prompt") or "").strip()
            draft_id = str(meta.get("draft_id") or "").strip() or None
            job_id = str(meta.get("job_id") or "").strip() or None
            summary = str(meta.get("summary") or "Prompt submitted")
            items.append(
                {
                    "id": str(entry.id),
                    "event_type": "prompt_submission",
                    "status": status,
                    "summary": summary,
                    "created_at": entry.created_at,
                    "actor_id": actor_identity_id or None,
                    "agent_slug": "xyn-intent-router",
                    "provider": "",
                    "model_name": "",
                    "artifact_id": event_artifact_id or None,
                    "artifact_type": (artifact.type.slug if artifact and artifact.type_id else "") or "",
                    "artifact_title": artifact.title if artifact else "",
                    "request_type": str(meta.get("request_type") or "intent.resolve"),
                    "prompt": prompt_text,
                    "workspace_id": prompt_workspace_id or None,
                    "thread_id": str(meta.get("thread_id") or "") or None,
                    "draft_id": draft_id,
                    "job_id": job_id,
                    "error": str(meta.get("error") or ""),
                    "trace": meta.get("trace") if isinstance(meta.get("trace"), list) else [],
                    "structured_operation": meta.get("structured_operation") if isinstance(meta.get("structured_operation"), dict) else {},
                    "prompt_interpretation": meta.get("prompt_interpretation") if isinstance(meta.get("prompt_interpretation"), dict) else {},
                    "conversation_action": meta.get("conversation_action") if isinstance(meta.get("conversation_action"), dict) else {},
                    "conversation_message": _conversation_message_from_prompt_activity(meta, status=status, summary=summary),
                    "source": "audit_log",
                }
            )
            if len(items) >= limit:
                break
            continue
        if workspace_id and str(payload_meta.get("workspace_id") or "") != workspace_id:
            if event_artifact_id and event_artifact_id in artifact_lookup:
                pass
            else:
                continue
        items.append(
            {
                "id": str(entry.id),
                "event_type": entry.message,
                "status": "succeeded",
                "summary": str(payload_meta.get("mode") or "AI invocation complete"),
                "created_at": entry.created_at,
                "actor_id": actor_identity_id or None,
                "agent_slug": str(meta.get("agent_slug") or ""),
                "provider": str(meta.get("provider") or ""),
                "model_name": str(meta.get("model_name") or ""),
                "artifact_id": event_artifact_id or None,
                "artifact_type": (artifact.type.slug if artifact and artifact.type_id else "") or "article",
                "artifact_title": artifact.title if artifact else "",
                "request_type": "ai.invoke",
                "prompt": "",
                "workspace_id": str(payload_meta.get("workspace_id") or "") or None,
                "thread_id": str(payload_meta.get("thread_id") or "") or None,
                "draft_id": None,
                "job_id": None,
                "error": "",
                "source": "audit_log",
            }
        )
        if len(items) >= limit:
            break

    if workspace_id and len(items) < limit:
        events = (
            ArtifactEvent.objects.filter(artifact__workspace_id=workspace_id, event_type__in=["ai_invoked", "article_revision_created"])
            .select_related("artifact")
            .order_by("-created_at")[:300]
        )
        for event in events:
            if artifact_id and str(event.artifact_id) != artifact_id:
                continue
            payload = event.payload_json if isinstance(event.payload_json, dict) else {}
            if thread_id and str(payload.get("thread_id") or "") != thread_id:
                continue
            summary = str(payload.get("mode") or payload.get("source") or event.event_type)
            items.append(
                {
                    "id": str(event.id),
                    "event_type": event.event_type,
                    "status": "succeeded",
                    "summary": summary,
                    "created_at": event.created_at,
                    "actor_id": str(event.actor_id) if event.actor_id else None,
                    "agent_slug": str(payload.get("agent_slug") or ""),
                    "provider": str(payload.get("provider") or ""),
                    "model_name": str(payload.get("model_name") or ""),
                "artifact_id": str(event.artifact_id),
                "artifact_type": event.artifact.type.slug if event.artifact.type_id else "",
                "artifact_title": event.artifact.title,
                "thread_id": str(payload.get("thread_id") or "") or None,
                "source": "artifact_event",
            }
            )
            if len(items) >= limit:
                break

    if workspace_id and len(items) < limit:
        workspace = _resolve_workspace_for_identity(identity, workspace_id)
        if workspace:
            items.extend(_list_runtime_activity_entries(workspace, limit=max(1, limit - len(items)), thread_id=thread_id))

    if workspace_id and len(items) < limit:
        coordination_events = (
            CoordinationEvent.objects.filter(thread__workspace_id=workspace_id)
            .select_related("thread", "work_item")
            .order_by("-created_at")[:300]
        )
        for event in coordination_events:
            if thread_id and str(event.thread.source_conversation_id or "") != thread_id:
                continue
            items.append(_coordination_activity_item_from_event(event))
            if len(items) >= limit:
                break

    items.sort(key=lambda entry: str(entry.get("created_at") or ""), reverse=True)
    return JsonResponse({"items": items[:limit]})


@csrf_exempt
def ai_activity_stream(request: HttpRequest) -> HttpResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)

    workspace_id = str(request.GET.get("workspace_id") or "").strip()
    thread_id = str(request.GET.get("thread_id") or "").strip()
    if not workspace_id:
        return JsonResponse({"error": "workspace_id is required"}, status=400)
    workspace = _resolve_workspace_for_identity(identity, workspace_id)
    if not workspace:
        return JsonResponse({"error": "forbidden"}, status=403)

    last_event_id = str(request.GET.get("last_event_id") or request.headers.get("Last-Event-ID") or "").strip()
    since = str(request.GET.get("since") or "").strip()

    def stream():
        try:
            upstream = _seed_runtime_stream_request(workspace=workspace, last_event_id=last_event_id, since=since)
        except requests.RequestException as exc:
            yield f"event: stream.error\ndata: {json.dumps({'message': 'failed to reach xyn-core', 'details': exc.__class__.__name__})}\n\n"
            return
        with upstream:
            for message in _iter_sse_messages(upstream):
                payload = message.get("data") if isinstance(message.get("data"), dict) else {}
                if not payload:
                    continue
                envelope = _runtime_stream_envelope_from_event(payload)
                if envelope.get("workspace_id") != str(workspace.id):
                    continue
                if thread_id and str(envelope.get("thread_id") or "") != thread_id:
                    continue
                yield _serialize_runtime_stream_sse(envelope)

    response = StreamingHttpResponse(stream(), content_type="text/event-stream")
    response["Cache-Control"] = "no-cache"
    response["X-Accel-Buffering"] = "no"
    return response


@csrf_exempt
def ai_purposes_collection(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    _ensure_default_agent_purposes()
    if request.method == "GET":
        status_filter = str(request.GET.get("status") or "").strip().lower()
        enabled_filter = str(request.GET.get("enabled") or "").strip().lower()
        purposes = AgentPurpose.objects.select_related("model_config__provider").order_by("slug")
        if status_filter in {"active", "deprecated"}:
            purposes = purposes.filter(status=status_filter)
        if enabled_filter in {"1", "true", "yes"}:
            purposes = purposes.exclude(status="deprecated")
        elif enabled_filter in {"0", "false", "no"}:
            purposes = purposes.filter(status="deprecated")
        return JsonResponse({"purposes": [_serialize_agent_purpose(item) for item in purposes]})
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if not _can_manage_ai(identity):
        return JsonResponse({"error": "forbidden"}, status=403)
    payload = _parse_json(request)
    slug = str(payload.get("slug") or "").strip().lower()
    if not slug:
        return JsonResponse({"error": "slug is required"}, status=400)
    if not PURPOSE_SLUG_PATTERN.match(slug):
        return JsonResponse({"error": "slug must match ^[a-z0-9][a-z0-9-]{1,62}$"}, status=400)
    if AgentPurpose.objects.filter(slug=slug).exists():
        return JsonResponse({"error": "slug already exists"}, status=400)
    preamble = str(payload.get("preamble") or "")
    if len(preamble) > 1000:
        return JsonResponse({"error": "preamble must be 1000 characters or less"}, status=400)
    purpose = AgentPurpose.objects.create(
        slug=slug,
        name=str(payload.get("name") or "").strip(),
        description=str(payload.get("description") or "").strip(),
        preamble=preamble,
        status=(
            str(payload.get("status") or "").strip().lower()
            if str(payload.get("status") or "").strip().lower() in {"active", "deprecated"}
            else ("active" if bool(payload.get("enabled", True)) else "deprecated")
        ),
        enabled=bool(payload.get("enabled", True)),
        updated_by=request.user if getattr(request, "user", None) and request.user.is_authenticated else None,
    )
    purpose.enabled = purpose.status == "active"
    purpose.save(update_fields=["enabled", "updated_at"])
    return JsonResponse({"purpose": _serialize_agent_purpose(purpose)})


@csrf_exempt
def ai_purpose_detail(request: HttpRequest, purpose_slug: str) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    _ensure_default_agent_purposes()
    purpose = get_object_or_404(AgentPurpose.objects.select_related("model_config__provider"), slug=purpose_slug)
    if request.method == "GET":
        return JsonResponse({"purpose": _serialize_agent_purpose(purpose)})
    if request.method == "DELETE":
        if not _can_manage_ai(identity):
            return JsonResponse({"error": "forbidden"}, status=403)
        purpose.status = "deprecated"
        purpose.enabled = False
        purpose.updated_by = request.user if getattr(request, "user", None) and request.user.is_authenticated else None
        purpose.save(update_fields=["status", "enabled", "updated_by", "updated_at"])
        return JsonResponse({"purpose": _serialize_agent_purpose(purpose)})
    if request.method not in {"PUT", "PATCH"}:
        return JsonResponse({"error": "method not allowed"}, status=405)
    if not _can_manage_ai(identity):
        return JsonResponse({"error": "forbidden"}, status=403)
    payload = _parse_json(request)
    if "slug" in payload and str(payload.get("slug") or "").strip().lower() != purpose.slug:
        return JsonResponse({"error": "Purpose slug is immutable. Create a new purpose instead."}, status=400)
    if "enabled" in payload:
        purpose.status = "active" if bool(payload.get("enabled")) else "deprecated"
    if "status" in payload:
        next_status = str(payload.get("status") or "").strip().lower()
        if next_status not in {"active", "deprecated"}:
            return JsonResponse({"error": "status must be one of: active, deprecated"}, status=400)
        purpose.status = next_status
    if "name" in payload:
        purpose.name = str(payload.get("name") or purpose.name)
    if "description" in payload:
        purpose.description = str(payload.get("description") or "")
    preamble_value = None
    if "preamble" in payload:
        preamble_value = str(payload.get("preamble") or "")
    elif "system_prompt" in payload:
        # Backward compatibility for one release.
        preamble_value = str(payload.get("system_prompt") or "")
    elif "system_prompt_markdown" in payload:
        # Backward compatibility for one release.
        preamble_value = str(payload.get("system_prompt_markdown") or "")
    if preamble_value is not None:
        if len(preamble_value) > 1000:
            return JsonResponse({"error": "preamble must be 1000 characters or less"}, status=400)
        purpose.preamble = preamble_value
    model_payload = payload.get("model_config")
    if isinstance(model_payload, dict):
        provider_slug = str(model_payload.get("provider") or "").strip().lower()
        model_name = str(model_payload.get("model_name") or "").strip()
        provider = None
        if provider_slug:
            provider = ModelProvider.objects.filter(slug=provider_slug).first()
            if not provider:
                return JsonResponse({"error": "invalid provider"}, status=400)
        if model_name:
            if not provider:
                provider = purpose.model_config.provider if purpose.model_config else ModelProvider.objects.filter(slug="openai").first()
            if not provider:
                return JsonResponse({"error": "model provider unavailable"}, status=400)
            model_config = purpose.model_config
            if model_config and model_config.provider_id == provider.id and model_config.model_name == model_name:
                pass
            else:
                model_config = ModelConfig.objects.create(
                    provider=provider,
                    model_name=model_name,
                    temperature=float(model_payload.get("temperature") if model_payload.get("temperature") is not None else 0.2),
                    max_tokens=int(model_payload.get("max_tokens") or 1200),
                    top_p=float(model_payload.get("top_p") if model_payload.get("top_p") is not None else 1.0),
                    frequency_penalty=float(model_payload.get("frequency_penalty") if model_payload.get("frequency_penalty") is not None else 0.0),
                    presence_penalty=float(model_payload.get("presence_penalty") if model_payload.get("presence_penalty") is not None else 0.0),
                    extra_json=model_payload.get("extra_json") if isinstance(model_payload.get("extra_json"), dict) else {},
                )
            purpose.model_config = model_config
    purpose.updated_by = request.user if getattr(request, "user", None) and request.user.is_authenticated else None
    purpose.enabled = purpose.status != "deprecated"
    purpose.save(
        update_fields=["name", "description", "status", "enabled", "preamble", "model_config", "updated_by", "updated_at"]
    )
    return JsonResponse({"purpose": _serialize_agent_purpose(purpose)})


@csrf_exempt
@require_role("platform_admin")
def tenants_collection(request: HttpRequest) -> JsonResponse:
    if request.method == "POST":
        payload = _parse_json(request)
        name = (payload.get("name") or "").strip()
        if not name:
            return JsonResponse({"error": "name is required"}, status=400)
        slug = (payload.get("slug") or slugify(name)).lower()
        status = payload.get("status") or "active"
        metadata_json = payload.get("metadata_json")
        if Tenant.objects.filter(slug=slug).exists():
            return JsonResponse({"error": "slug already exists"}, status=400)
        tenant = Tenant.objects.create(
            name=name,
            slug=slug,
            status=status,
            metadata_json=metadata_json,
        )
        return JsonResponse({"id": str(tenant.id)})

    qs = Tenant.objects.all().order_by("name")
    if query := request.GET.get("q"):
        qs = qs.filter(models.Q(name__icontains=query) | models.Q(slug__icontains=query))
    data = [_serialize_tenant(t) for t in qs]
    return _paginate(request, data, "tenants")


@csrf_exempt
@require_role("platform_admin")
def tenant_detail(request: HttpRequest, tenant_id: str) -> JsonResponse:
    tenant = get_object_or_404(Tenant, id=tenant_id)
    if request.method == "GET":
        return JsonResponse(_serialize_tenant(tenant))
    if request.method in ("PATCH", "PUT"):
        payload = _parse_json(request)
        if "name" in payload:
            tenant.name = payload.get("name") or tenant.name
        if "slug" in payload:
            slug = (payload.get("slug") or tenant.slug).lower()
            if slug != tenant.slug and Tenant.objects.filter(slug=slug).exists():
                return JsonResponse({"error": "slug already exists"}, status=400)
            tenant.slug = slug
        if "status" in payload:
            tenant.status = payload.get("status") or tenant.status
        if "metadata_json" in payload:
            tenant.metadata_json = payload.get("metadata_json")
        tenant.save(update_fields=["name", "slug", "status", "metadata_json", "updated_at"])
        return JsonResponse({"id": str(tenant.id)})
    if request.method == "DELETE":
        tenant.status = "suspended"
        tenant.save(update_fields=["status", "updated_at"])
        return JsonResponse({"status": "suspended"})
    return JsonResponse({"error": "method not allowed"}, status=405)


@csrf_exempt
def tenant_contacts_collection(request: HttpRequest, tenant_id: str) -> JsonResponse:
    tenant = get_object_or_404(Tenant, id=tenant_id)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if not _is_platform_admin(identity):
        if not _require_tenant_access(identity, tenant_id, "tenant_viewer"):
            return JsonResponse({"error": "forbidden"}, status=403)
    if request.method == "POST":
        if not _is_platform_admin(identity):
            if not _require_tenant_access(identity, tenant_id, "tenant_operator"):
                return JsonResponse({"error": "forbidden"}, status=403)
        payload = _parse_json(request)
        name = (payload.get("name") or "").strip()
        if not name:
            return JsonResponse({"error": "name is required"}, status=400)
        email = payload.get("email")
        if email and Contact.objects.filter(tenant=tenant, email=email).exists():
            return JsonResponse({"error": "email already exists for tenant"}, status=400)
        contact = Contact.objects.create(
            tenant=tenant,
            name=name,
            email=email,
            phone=payload.get("phone"),
            role_title=payload.get("role_title"),
            status=payload.get("status") or "active",
            metadata_json=payload.get("metadata_json"),
        )
        return JsonResponse({"id": str(contact.id)})

    contacts = Contact.objects.filter(tenant=tenant).order_by("name")
    data = [_serialize_contact(c) for c in contacts]
    return JsonResponse({"contacts": data})


@csrf_exempt
def contact_detail(request: HttpRequest, contact_id: str) -> JsonResponse:
    contact = get_object_or_404(Contact, id=contact_id)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if not _is_platform_admin(identity):
        if not _require_tenant_access(identity, str(contact.tenant_id), "tenant_viewer"):
            return JsonResponse({"error": "forbidden"}, status=403)
    if request.method == "GET":
        return JsonResponse(_serialize_contact(contact))
    if request.method in ("PATCH", "PUT"):
        if not _is_platform_admin(identity):
            if not _require_tenant_access(identity, str(contact.tenant_id), "tenant_operator"):
                return JsonResponse({"error": "forbidden"}, status=403)
        payload = _parse_json(request)
        if "name" in payload:
            contact.name = payload.get("name") or contact.name
        if "email" in payload:
            email = payload.get("email")
            if email and Contact.objects.filter(tenant=contact.tenant, email=email).exclude(id=contact.id).exists():
                return JsonResponse({"error": "email already exists for tenant"}, status=400)
            contact.email = email
        if "phone" in payload:
            contact.phone = payload.get("phone")
        if "role_title" in payload:
            contact.role_title = payload.get("role_title")
        if "status" in payload:
            contact.status = payload.get("status") or contact.status
        if "metadata_json" in payload:
            contact.metadata_json = payload.get("metadata_json")
        contact.save(
            update_fields=["name", "email", "phone", "role_title", "status", "metadata_json", "updated_at"]
        )
        return JsonResponse({"id": str(contact.id)})
    if request.method == "DELETE":
        if not _is_platform_admin(identity):
            if not _require_tenant_access(identity, str(contact.tenant_id), "tenant_operator"):
                return JsonResponse({"error": "forbidden"}, status=403)
        contact.status = "inactive"
        contact.save(update_fields=["status", "updated_at"])
        return JsonResponse({"status": "inactive"})
    return JsonResponse({"error": "method not allowed"}, status=405)


