@login_required
def runtime_runs_collection(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    workspace_ref = str(request.GET.get("workspace_id") or request.GET.get("workspace") or "").strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_ref)
    if not workspace:
        return JsonResponse({"error": "workspace context is required"}, status=400)
    status_filter = str(request.GET.get("status") or "").strip().lower()
    try:
        response = _seed_api_request(method="GET", path="/api/v1/runs", timeout=20)
    except requests.RequestException as exc:
        return JsonResponse({"error": "failed to reach xyn-core", "details": exc.__class__.__name__}, status=502)
    if response.status_code >= 400:
        return JsonResponse({"error": "runtime runs unavailable"}, status=502)
    try:
        payload = response.json() if response.content else {}
    except ValueError:
        return JsonResponse({"error": "invalid runtime runs response"}, status=502)
    items = payload.get("items") if isinstance(payload, dict) else []
    now = timezone.now()
    runs = []
    for item in items if isinstance(items, list) else []:
        if not isinstance(item, dict):
            continue
        if not _runtime_run_belongs_to_workspace(item, workspace):
            continue
        if status_filter and str(item.get("status") or "").strip().lower() != status_filter:
            continue
        runs.append(_runtime_run_summary_payload(item, now=now))
    runs.sort(key=lambda item: str(item.get("started_at") or item.get("created_at") or ""), reverse=True)
    return JsonResponse({"runs": runs})


@login_required
def runtime_run_detail(request: HttpRequest, run_id: uuid.UUID) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    workspace_ref = str(request.GET.get("workspace_id") or request.GET.get("workspace") or "").strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_ref)
    if not workspace:
        return JsonResponse({"error": "workspace context is required"}, status=400)
    try:
        run_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}", timeout=20)
        steps_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}/steps", timeout=20)
        artifacts_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}/artifacts", timeout=20)
    except requests.RequestException as exc:
        return JsonResponse({"error": "failed to reach xyn-core", "details": exc.__class__.__name__}, status=502)
    if run_response.status_code == 404:
        return JsonResponse({"error": "run not found"}, status=404)
    if run_response.status_code >= 400 or steps_response.status_code >= 400 or artifacts_response.status_code >= 400:
        return JsonResponse({"error": "runtime run detail unavailable"}, status=502)
    try:
        run_payload = run_response.json() if run_response.content else {}
        steps_payload = steps_response.json() if steps_response.content else []
        artifacts_payload = artifacts_response.json() if artifacts_response.content else []
    except ValueError:
        return JsonResponse({"error": "invalid runtime run response"}, status=502)
    if not isinstance(run_payload, dict) or not _runtime_run_belongs_to_workspace(run_payload, workspace):
        return JsonResponse({"error": "run not found"}, status=404)
    detail = _runtime_run_detail_payload(
        run_payload,
        steps=steps_payload if isinstance(steps_payload, list) else [],
        artifacts=artifacts_payload if isinstance(artifacts_payload, list) else [],
        now=timezone.now(),
    )
    return JsonResponse(detail)


@login_required
def runtime_run_artifact_detail(request: HttpRequest, run_id: uuid.UUID, artifact_id: uuid.UUID) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    workspace_ref = str(request.GET.get("workspace_id") or request.GET.get("workspace") or "").strip()
    workspace = _resolve_workspace_for_identity(identity, workspace_ref)
    if not workspace:
        return JsonResponse({"error": "workspace context is required"}, status=400)
    try:
        run_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}", timeout=20)
        artifact_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}/artifacts/{artifact_id}", timeout=20)
    except requests.RequestException as exc:
        return JsonResponse({"error": "failed to reach xyn-core", "details": exc.__class__.__name__}, status=502)
    if run_response.status_code == 404:
        return JsonResponse({"error": "run not found"}, status=404)
    if run_response.status_code >= 400:
        return JsonResponse({"error": "runtime run unavailable"}, status=502)
    if artifact_response.status_code == 404:
        return JsonResponse({"error": "artifact not found"}, status=404)
    if artifact_response.status_code >= 400:
        return JsonResponse({"error": "runtime artifact unavailable"}, status=502)
    try:
        run_payload = run_response.json() if run_response.content else {}
        artifact_payload = artifact_response.json() if artifact_response.content else {}
    except ValueError:
        return JsonResponse({"error": "invalid runtime artifact response"}, status=502)
    if not isinstance(run_payload, dict) or not _runtime_run_belongs_to_workspace(run_payload, workspace):
        return JsonResponse({"error": "run not found"}, status=404)
    if not isinstance(artifact_payload, dict):
        return JsonResponse({"error": "runtime artifact unavailable"}, status=502)
    return JsonResponse(_runtime_run_artifact_detail_payload_for_workspace(workspace=workspace, run_id=run_id, artifact_id=artifact_id, artifact_payload=artifact_payload))


def _runtime_run_artifact_detail_payload_for_workspace(
    *,
    workspace: Workspace,
    run_id: uuid.UUID | str,
    artifact_id: uuid.UUID | str,
    artifact_payload: Dict[str, Any],
) -> Dict[str, Any]:
    payload = dict(artifact_payload or {})
    payload["run_id"] = str(run_id)
    evolution = build_artifact_evolution(
        workspace=workspace,
        current_run_id=str(run_id),
        current_artifact_id=str(artifact_id),
        current_artifact=payload,
        runtime_detail_lookup=_project_runtime_status_to_task,
    )
    payload["evolution"] = evolution
    analysis_context = build_artifact_analysis_context(
        workspace=workspace,
        evolution=evolution,
        runtime_detail_lookup=_project_runtime_status_to_task,
    )
    payload["analysis"] = serialize_artifact_analysis(
        compute_artifact_analysis(
            current_artifact=payload,
            evolution=evolution,
            run_status_by_run_id=analysis_context.get("run_status_by_run_id") if isinstance(analysis_context, dict) else None,
            supervised_run_ids=analysis_context.get("supervised_run_ids") if isinstance(analysis_context, dict) else None,
        )
    )
    return payload


EPIC_C_DEV_TASK_TYPES = {"codegen"}
RUNTIME_DEV_TASK_ACTIVE_STATUSES = {"queued", "running"}


def _dev_task_uses_epic_c_runtime(task: DevTask) -> bool:
    return str(task.task_type or "").strip().lower() in EPIC_C_DEV_TASK_TYPES


def _dev_task_runtime_workspace(identity: UserIdentity, task: DevTask, request: Optional[HttpRequest] = None) -> Optional[Workspace]:
    if task.runtime_workspace_id:
        return _resolve_workspace_for_identity(identity, str(task.runtime_workspace_id))
    workspace_ref = ""
    if request is not None:
        workspace_ref = str(request.GET.get("workspace_id") or request.GET.get("workspace") or "").strip()
    return _resolve_workspace_for_identity(identity, workspace_ref)


def _runtime_repo_candidates_from_target(target: Dict[str, Any]) -> List[str]:
    candidates: List[str] = []
    name = str(target.get("name") or "").strip()
    url = str(target.get("url") or "").strip().lower()
    if name in {"xyn", "xyn-platform"}:
        candidates.append(name)
    if "xyn-platform" in url and "xyn-platform" not in candidates:
        candidates.append("xyn-platform")
    if re.search(r"(^|/|:)xyn(?:\\.git)?$", url) and "xyn" not in candidates:
        candidates.append("xyn")
    return candidates


def _fallback_dev_task_runtime_source(task: DevTask) -> Dict[str, Any]:
    work_item_id = str(task.work_item_id or "").strip()
    if not work_item_id:
        raise ValueError("dev task is missing work_item_id")
    handoff = resolve_execution_brief(task)
    brief = handoff.brief if isinstance(handoff.brief, dict) else {}
    target = handoff.target
    target_repo = str(target.repository_slug or task.target_repo or "").strip()
    target_branch = str(target.branch or task.target_branch or "").strip()
    if not target_repo:
        raise ValueError("dev task is missing runtime target context required for runtime submission")
    validation = brief.get("validation") if isinstance(brief.get("validation"), dict) else {}
    acceptance = validation.get("acceptance_criteria") if isinstance(validation.get("acceptance_criteria"), list) else []
    commands = validation.get("commands") if isinstance(validation.get("commands"), list) else []
    work_item: Dict[str, Any] = {
        "id": work_item_id,
        "title": str(brief.get("summary") or task.title or work_item_id).strip() or work_item_id,
        "summary": str(brief.get("summary") or task.title or work_item_id).strip() or work_item_id,
        "description": str(brief.get("implementation_intent") or brief.get("objective") or task.description or "").strip(),
        "execution_brief": brief,
        "acceptance_criteria": [str(item).strip() for item in acceptance if str(item).strip()],
        "verify": [{"command": str(command).strip()} for command in commands if str(command).strip()],
    }
    repo_target = repo_target_payload_for_resolution(target, branch=target_branch)
    if repo_target:
        work_item["repo_targets"] = [repo_target]
    return {
        "plan_json": {"work_items": [work_item], "source": "execution_brief_fallback"},
        "work_item": work_item,
        "target_repo": target_repo,
        "target_branch": target_branch,
    }


def _load_dev_task_runtime_source(task: DevTask) -> Dict[str, Any]:
    if not task.source_run_id or not task.input_artifact_key:
        return _fallback_dev_task_runtime_source(task)
    plan_json = _download_artifact_json(str(task.source_run_id), task.input_artifact_key)
    if not plan_json:
        raise ValueError(f"{task.input_artifact_key} not found for dev task source run")
    work_item_id = str(task.work_item_id or "").strip()
    if not work_item_id:
        raise ValueError("dev task is missing work_item_id")
    work_item = None
    for item in plan_json.get("work_items", []):
        if str(item.get("id") or "").strip() == work_item_id:
            work_item = item
            break
    if not isinstance(work_item, dict):
        raise ValueError(f"work_item_id not found in source plan: {work_item_id}")
    target = resolve_development_target(task=task, work_item=work_item)
    repo_name = str(target.repository_slug or "").strip()
    branch = str(target.branch or "").strip()
    if not repo_name:
        repo_targets = work_item.get("repo_targets") if isinstance(work_item.get("repo_targets"), list) else []
        repo_candidates: List[Tuple[str, str]] = []
        for row in repo_targets:
            if not isinstance(row, dict):
                continue
            row_branch = str(row.get("ref") or "").strip() or "develop"
            for candidate in _runtime_repo_candidates_from_target(row):
                repo_candidates.append((candidate, row_branch))
        unique_candidates = {(repo, row_branch) for repo, row_branch in repo_candidates}
        if not unique_candidates:
            raise ValueError("unable to resolve a canonical runtime target repo from work item repo_targets")
        repo_names = {repo for repo, _branch in unique_candidates}
        if len(repo_names) > 1:
            raise ValueError(f"multiple runtime target repos found for work item: {sorted(repo_names)}")
        repo_name = next(iter(repo_names))
        branch = next(row_branch for repo, row_branch in unique_candidates if repo == repo_name)
    return {
        "plan_json": plan_json,
        "work_item": work_item,
        "target_repo": repo_name,
        "target_branch": branch,
    }


def _build_dev_task_runtime_prompt(task: DevTask, work_item: Dict[str, Any]) -> Dict[str, str]:
    handoff = resolve_execution_brief(task, work_item=work_item)
    brief = handoff.brief if isinstance(handoff.brief, dict) else {}
    title = str(brief.get("summary") or task.title or work_item.get("title") or task.work_item_id or f"Dev task {task.id}").strip()
    body_lines: List[str] = []
    objective = str(brief.get("objective") or work_item.get("description") or work_item.get("summary") or "").strip()
    implementation_intent = str(brief.get("implementation_intent") or "").strip()
    if objective:
        body_lines.append(objective)
    if implementation_intent and implementation_intent != objective:
        body_lines.append(f"Requested change: {implementation_intent}")
    brief_target = brief.get("target") if isinstance(brief.get("target"), dict) else {}
    repo_slug = str(brief_target.get("repository_slug") or "").strip()
    repo_branch = str(brief_target.get("branch") or "").strip()
    if repo_slug:
        body_lines.append(f"Target repository: {repo_slug}{' @ ' + repo_branch if repo_branch else ''}")
    scope = brief.get("scope") if isinstance(brief.get("scope"), dict) else {}
    allowed_areas = scope.get("allowed_areas") if isinstance(scope.get("allowed_areas"), list) else []
    allowed_files = scope.get("allowed_files") if isinstance(scope.get("allowed_files"), list) else []
    if allowed_areas:
        body_lines.append("Allowed areas:")
        body_lines.extend(f"- {str(item).strip()}" for item in allowed_areas if str(item).strip())
    if allowed_files:
        body_lines.append("Allowed files:")
        body_lines.extend(f"- {str(item).strip()}" for item in allowed_files if str(item).strip())
    validation = brief.get("validation") if isinstance(brief.get("validation"), dict) else {}
    acceptance = validation.get("acceptance_criteria") if isinstance(validation.get("acceptance_criteria"), list) else []
    if acceptance:
        body_lines.append("Acceptance criteria:")
        body_lines.extend(f"- {str(item).strip()}" for item in acceptance if str(item).strip())
    validation_commands = validation.get("commands") if isinstance(validation.get("commands"), list) else []
    if validation_commands:
        body_lines.append("Validation commands:")
        body_lines.extend(f"- {str(command).strip()}" for command in validation_commands if str(command).strip())
    boundaries = brief.get("boundaries") if isinstance(brief.get("boundaries"), list) else []
    if boundaries:
        body_lines.append("Boundaries:")
        body_lines.extend(f"- {str(item).strip()}" for item in boundaries if str(item).strip())
    if not body_lines:
        body_lines.append(title)
    return {"title": title, "body": "\n".join(body_lines).strip()}


def _dev_task_dispatch_purpose(task: DevTask) -> str:
    task_type = str(task.task_type or "").strip().lower()
    intent_type = str(task.intent_type or "").strip().lower()
    context_purpose = str(task.context_purpose or "").strip().lower()
    if "plan" in task_type or "plan" in intent_type or context_purpose == "planning":
        return "planning"
    return "coding"


def _agent_resolution_label(*, purpose: str, resolution_source: str) -> str:
    source = str(resolution_source or "").strip().lower()
    if source == "explicit":
        return f"Explicit {purpose} assignment"
    if source == "default_fallback":
        return "Default fallback"
    if not source:
        return "Unresolved routing"
    return source.replace("_", " ").strip().title()


def _resolve_dev_task_agent_selection(task: DevTask, *, agent_override_id: Optional[str] = None) -> Dict[str, Any]:
    purpose = _dev_task_dispatch_purpose(task)
    routed = resolve_agent_routing(purpose_slug=purpose)
    routed_agent_id = str(routed.get("resolved_agent_id") or "").strip()
    routed_agent_name = str(routed.get("resolved_agent_name") or "").strip()
    routed_resolution_source = str(routed.get("resolution_source") or "").strip().lower()
    effective_agent_id = routed_agent_id or None
    effective_agent_name = routed_agent_name or None
    effective_resolution_source = routed_resolution_source
    override_id = str(agent_override_id or "").strip()
    override_applied = False
    if override_id:
        _ensure_default_agent_purposes()
        override_agent = (
            AgentDefinition.objects.prefetch_related("purposes")
            .filter(id=override_id, enabled=True)
            .first()
        )
        if not override_agent:
            raise ValueError("agent override is invalid or disabled")
        purpose_slugs = {str(item.slug or "").strip().lower() for item in override_agent.purposes.all()}
        if purpose not in purpose_slugs:
            raise ValueError(f"agent override is not compatible with purpose '{purpose}'")
        effective_agent_id = str(override_agent.id)
        effective_agent_name = str(override_agent.name or "").strip()
        override_applied = effective_agent_id != (routed_agent_id or None)
        if override_applied:
            effective_resolution_source = "action_override"
    return {
        "purpose": purpose,
        "routed_agent_id": routed_agent_id,
        "routed_agent_name": routed_agent_name,
        "routed_resolution_source": routed_resolution_source,
        "routed_resolution_label": _agent_resolution_label(
            purpose=purpose,
            resolution_source=routed_resolution_source,
        ),
        "effective_agent_id": effective_agent_id,
        "effective_agent_name": effective_agent_name,
        "effective_resolution_source": effective_resolution_source,
        "effective_resolution_label": "Action override"
        if effective_resolution_source == "action_override"
        else _agent_resolution_label(
            purpose=purpose,
            resolution_source=effective_resolution_source,
        ),
        "override_agent_id": override_id or None,
        "override_applied": override_applied,
    }


def _build_dev_task_runtime_payload(
    task: DevTask,
    workspace: Workspace,
    *,
    agent_selection: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    source = _load_dev_task_runtime_source(task)
    work_item = source["work_item"]
    handoff = resolve_execution_brief(task, work_item=work_item)
    prompt = _build_dev_task_runtime_prompt(task, work_item)
    requested_outputs = ["patch", "log", "summary"]
    verify_rows = work_item.get("verify") if isinstance(work_item.get("verify"), list) else []
    if verify_rows and "report" not in requested_outputs:
        requested_outputs.append("report")
    try:
        timeout_seconds = int(os.environ.get("XYN_DEV_TASK_RUNTIME_TIMEOUT_SECONDS", "1800") or "1800")
    except ValueError:
        timeout_seconds = 1800
    attachments = []
    if task.source_run_id and task.input_artifact_key:
        attachments.append(
            {
                "kind": "plan",
                "uri": f"xyn://runs/{task.source_run_id}/artifacts/{task.input_artifact_key}",
                "label": task.input_artifact_key,
            }
        )
    return {
        "schema_version": "v1",
        "run_id": str(uuid.uuid4()),
        "work_item_id": str(task.work_item_id or f"dev-task:{task.id}"),
        "worker_type": "codex_local",
        "target": {
            "repo": task.target_repo or source["target_repo"],
            "branch": task.target_branch or source["target_branch"],
            "workspace_id": str(workspace.id),
            "artifact_id": None,
        },
        "prompt": prompt,
        "context": {
            "epic_id": "epic_c",
            "attachments": attachments,
            "metadata": {
                "source": "dev_task",
                "dev_task_id": str(task.id),
                "task_type": str(task.task_type or ""),
                "source_entity_type": str(task.source_entity_type or ""),
                "source_entity_id": str(task.source_entity_id or ""),
                "execution_brief": handoff.brief,
                "execution_brief_source": handoff.source_kind,
                "ai_agent_selection": agent_selection if isinstance(agent_selection, dict) else {},
            },
        },
        "policy": {
            "auto_continue": bool((task.execution_policy or {}).get("auto_continue", True)),
            "max_retries": int((task.execution_policy or {}).get("max_retries", max(int(task.max_attempts or 0) - 1, 0))),
            "require_human_review_on_failure": bool((task.execution_policy or {}).get("require_human_review_on_failure", True)),
            "timeout_seconds": timeout_seconds,
        },
        "requested_outputs": requested_outputs,
    }


def _fetch_runtime_run_payload(run_id: uuid.UUID) -> Optional[Dict[str, Any]]:
    try:
        response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}", timeout=20)
    except requests.RequestException:
        return None
    if response.status_code == 404 or response.status_code >= 400:
        return None
    try:
        payload = response.json() if response.content else {}
    except ValueError:
        return None
    return payload if isinstance(payload, dict) else None


def _fetch_runtime_run_detail_payload(run_id: uuid.UUID) -> Optional[Dict[str, Any]]:
    try:
        run_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}", timeout=20)
        steps_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}/steps", timeout=20)
        artifacts_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{run_id}/artifacts", timeout=20)
    except requests.RequestException:
        return None
    if run_response.status_code == 404 or run_response.status_code >= 400 or steps_response.status_code >= 400 or artifacts_response.status_code >= 400:
        return None
    try:
        run_payload = run_response.json() if run_response.content else {}
        steps_payload = steps_response.json() if steps_response.content else []
        artifacts_payload = artifacts_response.json() if artifacts_response.content else []
    except ValueError:
        return None
    if not isinstance(run_payload, dict):
        return None
    return _runtime_run_detail_payload(
        run_payload,
        steps=steps_payload if isinstance(steps_payload, list) else [],
        artifacts=artifacts_payload if isinstance(artifacts_payload, list) else [],
        now=timezone.now(),
    )


def _canonical_work_item_status(status: str, *, execution_policy: Optional[Dict[str, Any]] = None) -> str:
    token = str(status or "").strip().lower()
    policy = execution_policy if isinstance(execution_policy, dict) else {}
    if token in {"completed", "succeeded"}:
        if bool(policy.get("require_human_review_on_success")):
            return "awaiting_review"
        return "completed"
    if token in {"failed", "blocked"}:
        return "awaiting_review"
    if token in {"canceled", "cancelled"}:
        return "canceled"
    if token == "running":
        return "running"
    return "queued"


def _task_requested_by(task: DevTask) -> Optional[str]:
    if task.created_by_id and getattr(task.created_by, "email", ""):
        return str(task.created_by.email or "").strip() or None
    if task.created_by_id and getattr(task.created_by, "username", ""):
        return str(task.created_by.username or "").strip() or None
    return None


def _project_runtime_status_to_task(task: DevTask) -> Optional[Dict[str, Any]]:
    if not task.runtime_run_id:
        return None
    detail = _fetch_runtime_run_detail_payload(task.runtime_run_id)
    if not detail:
        return None
    runtime_status = _canonical_work_item_status(
        str(detail.get("status") or "").strip() or task.status,
        execution_policy=task.execution_policy,
    )
    failure_reason = str(detail.get("failure_reason") or "").strip()
    escalation_reason = str(detail.get("escalation_reason") or "").strip()
    status_changed = task.status != runtime_status
    last_error = escalation_reason or failure_reason
    last_error_changed = (task.last_error or "") != last_error
    if status_changed or last_error_changed:
        task.status = runtime_status
        task.last_error = last_error
        update_fields = ["status", "last_error", "updated_at"]
        task.save(update_fields=update_fields)
    return detail


def _serialize_runtime_run_for_dev_task(detail: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "id": str(detail.get("run_id") or detail.get("id") or ""),
        "status": detail.get("status"),
        "summary": detail.get("summary"),
        "error": detail.get("failure_reason") or detail.get("escalation_reason"),
        "log_text": "",
        "started_at": detail.get("started_at"),
        "finished_at": detail.get("completed_at"),
        "failure_reason": detail.get("failure_reason"),
        "escalation_reason": detail.get("escalation_reason"),
        "agent_selection": detail.get("agent_selection") if isinstance(detail.get("agent_selection"), dict) else None,
    }


def _serialize_runtime_artifacts_for_dev_task(detail: Dict[str, Any]) -> List[Dict[str, Any]]:
    rows = detail.get("artifacts") if isinstance(detail.get("artifacts"), list) else []
    artifacts: List[Dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        uri = str(row.get("uri") or "").strip()
        artifacts.append(
            {
                "id": str(row.get("id") or ""),
                "run_id": str(detail.get("id") or detail.get("run_id") or ""),
                "name": str(row.get("label") or row.get("artifact_type") or "artifact"),
                "kind": row.get("artifact_type"),
                "url": uri if uri.startswith("http://") or uri.startswith("https://") else None,
                "metadata": {**(row.get("metadata") or {}), "uri": uri},
                "created_at": row.get("created_at"),
            }
        )
    return artifacts


def _serialize_runtime_artifacts_for_thread(detail: Dict[str, Any], *, work_item_id: str = "") -> List[Dict[str, Any]]:
    rows = detail.get("artifacts") if isinstance(detail.get("artifacts"), list) else []
    artifacts: List[Dict[str, Any]] = []
    run_id = str(detail.get("id") or detail.get("run_id") or "").strip()
    for row in rows:
        if not isinstance(row, dict):
            continue
        uri = str(row.get("uri") or "").strip()
        artifacts.append(
            {
                "id": str(row.get("artifact_id") or row.get("id") or "").strip(),
                "run_id": run_id or None,
                "work_item_id": str(work_item_id or "").strip() or None,
                "artifact_type": str(row.get("artifact_type") or row.get("kind") or "").strip() or None,
                "label": str(row.get("label") or row.get("name") or row.get("artifact_type") or "artifact"),
                "uri": uri or None,
                "created_at": row.get("created_at"),
                "metadata": row.get("metadata") if isinstance(row.get("metadata"), dict) else {},
            }
        )
    return artifacts


def _normalize_execution_run_state(
    *,
    run_status: Any,
    task_status: str,
    has_runtime_run: bool,
) -> str:
    token = str(run_status or "").strip().lower()
    if token in {"queued", "pending"}:
        return "queued"
    if token in {"running", "in_progress"}:
        return "running"
    if token in {"completed", "succeeded"}:
        return "completed"
    if token in {"failed", "error"}:
        return "failed"
    if token in {"blocked", "awaiting_review", "paused"}:
        return "awaiting_review"
    canonical = _canonical_work_item_status(task_status)
    if canonical in {"running", "completed", "awaiting_review"}:
        return canonical
    if has_runtime_run:
        return "queued"
    return "not_started"


def _validation_status_for_execution_run(
    *,
    execution_state: str,
    commands_payload: List[Dict[str, Any]],
    failure_reason: str,
    escalation_reason: str,
) -> str:
    command_statuses = {
        str(item.get("status") or "").strip().lower()
        for item in commands_payload
        if isinstance(item, dict)
    }
    if escalation_reason or execution_state == "awaiting_review":
        return "needs_review"
    if "failed" in command_statuses or failure_reason or execution_state == "failed":
        return "failed"
    if execution_state == "completed":
        return "passed"
    if execution_state in {"queued", "running"}:
        return "pending"
    return "not_run"


def _execution_run_message(
    *,
    execution_state: str,
    summary: str,
    error: str,
) -> str:
    if summary:
        return summary
    if error:
        return error
    if execution_state == "queued":
        return "Task has been dispatched and is waiting to start."
    if execution_state == "running":
        return "Execution is in progress."
    if execution_state == "completed":
        return "Execution completed successfully."
    if execution_state == "failed":
        return "Execution failed."
    if execution_state == "awaiting_review":
        return "Execution completed and requires review."
    return "No execution run has been dispatched yet."


def _resolve_dev_task_execution_payload(
    task: DevTask,
    *,
    runtime_detail: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    detail = runtime_detail or _project_runtime_status_to_task(task)
    run_payload: Optional[Dict[str, Any]] = None
    artifacts_payload: List[Dict[str, Any]] = []
    commands_payload: List[Dict[str, Any]] = []
    source: Optional[str] = None
    if detail:
        run_payload = _serialize_runtime_run_for_dev_task(detail)
        artifacts_payload = _serialize_runtime_artifacts_for_dev_task(detail)
        source = "runtime"
    elif task.result_run_id and task.result_run is not None:
        result_run = task.result_run
        run_payload = {
            "id": str(result_run.id),
            "status": result_run.status,
            "summary": result_run.summary,
            "error": result_run.error,
            "log_text": result_run.log_text,
            "started_at": result_run.started_at,
            "finished_at": result_run.finished_at,
            "failure_reason": "",
            "escalation_reason": "",
        }
        artifacts_payload = [
            {
                "id": str(artifact.id),
                "name": artifact.name,
                "kind": artifact.kind,
                "url": artifact.url,
                "metadata": artifact.metadata_json,
                "created_at": artifact.created_at,
            }
            for artifact in result_run.artifacts.all().order_by("created_at")
        ]
        commands_payload = [
            {
                "id": str(cmd.id),
                "step_name": cmd.step_name,
                "command_index": cmd.command_index,
                "shell": cmd.shell,
                "status": cmd.status,
                "exit_code": cmd.exit_code,
                "started_at": cmd.started_at,
                "finished_at": cmd.finished_at,
                "ssm_command_id": cmd.ssm_command_id,
                "stdout": cmd.stdout,
                "stderr": cmd.stderr,
            }
            for cmd in result_run.command_executions.all().order_by("created_at")
        ]
        source = "result"

    run_summary = str((run_payload or {}).get("summary") or "").strip()
    failure_reason = str((run_payload or {}).get("failure_reason") or "").strip()
    escalation_reason = str((run_payload or {}).get("escalation_reason") or "").strip()
    error = str((run_payload or {}).get("error") or escalation_reason or failure_reason or "").strip()
    execution_state = _normalize_execution_run_state(
        run_status=(run_payload or {}).get("status"),
        task_status=str(task.status or ""),
        has_runtime_run=bool(task.runtime_run_id),
    )
    execution_summary = {
        "has_run": bool(run_payload),
        "run_id": str((run_payload or {}).get("id") or "") or None,
        "source": source,
        "state": execution_state,
        "raw_status": str((run_payload or {}).get("status") or "").strip() or None,
        "validation_status": _validation_status_for_execution_run(
            execution_state=execution_state,
            commands_payload=commands_payload,
            failure_reason=failure_reason,
            escalation_reason=escalation_reason,
        ),
        "summary": run_summary or None,
        "error": error or None,
        "started_at": (run_payload or {}).get("started_at"),
        "finished_at": (run_payload or {}).get("finished_at"),
        "artifact_count": len(artifacts_payload),
        "artifact_labels": [
            str(item.get("name") or item.get("kind") or "artifact")
            for item in artifacts_payload[:3]
            if isinstance(item, dict)
        ],
        "agent_selection": (run_payload or {}).get("agent_selection") if isinstance((run_payload or {}).get("agent_selection"), dict) else None,
        "message": _execution_run_message(
            execution_state=execution_state,
            summary=run_summary,
            error=error,
        ),
    }
    return {
        "runtime_detail": detail,
        "run_payload": run_payload,
        "artifacts_payload": artifacts_payload,
        "commands_payload": commands_payload,
        "execution_summary": execution_summary,
    }


def _serialize_work_item_summary(task: DevTask, *, runtime_detail: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    execution_payload = _resolve_dev_task_execution_payload(task, runtime_detail=runtime_detail)
    detail = execution_payload["runtime_detail"]
    status = _canonical_work_item_status(str((detail or {}).get("status") or task.status), execution_policy=task.execution_policy)
    brief_review = serialize_execution_brief_review(task)
    queue_state = serialize_dev_task_queue_state(task, normalized_status=status)
    recovery_state = serialize_dev_task_recovery_state(task, execution_summary=execution_payload["execution_summary"])
    change_set = serialize_dev_task_change_summary(task, execution_payload=execution_payload)
    publish_state = serialize_dev_task_publish_state(task, change_set=change_set)
    return {
        "id": str(task.id),
        "work_item_id": task.work_item_id or str(task.id),
        "title": task.title,
        "description": task.description or "",
        "source_conversation_id": task.source_conversation_id or None,
        "requested_by": _task_requested_by(task),
        "intent_type": task.intent_type or None,
        "target_repo": task.target_repo or None,
        "target_branch": task.target_branch or None,
        "execution_policy": task.execution_policy or {},
        "has_execution_brief": isinstance(task.execution_brief, dict) and bool(task.execution_brief),
        "execution_brief_revision": int(((task.execution_brief or {}) if isinstance(task.execution_brief, dict) else {}).get("revision") or 0),
        "execution_brief_history_count": len(task.execution_brief_history if isinstance(task.execution_brief_history, list) else []),
        "execution_brief_review_state": normalize_execution_brief_review_state(task.execution_brief_review_state),
        "execution_brief_review_notes": task.execution_brief_review_notes or "",
        "execution_brief_reviewed_at": task.execution_brief_reviewed_at,
        "execution_brief_reviewed_by": str(task.execution_brief_reviewed_by_id) if task.execution_brief_reviewed_by_id else None,
        "execution_brief_review": brief_review,
        "execution_queue": queue_state,
        "execution_run": execution_payload["execution_summary"],
        "execution_recovery": recovery_state,
        "change_set": change_set,
        "publish_state": publish_state,
        "thread_id": str(task.coordination_thread_id) if task.coordination_thread_id else None,
        "thread_title": str(task.coordination_thread.title) if task.coordination_thread_id else None,
        "goal_id": str(task.goal_id) if task.goal_id else None,
        "goal_title": str(task.goal.title) if task.goal_id else None,
        "dependency_work_item_ids": task.dependency_work_item_ids if isinstance(task.dependency_work_item_ids, list) else [],
        "task_type": task.task_type,
        "status": status,
        "priority": task.priority,
        "attempts": task.attempts,
        "max_attempts": task.max_attempts,
        "locked_by": task.locked_by,
        "locked_at": task.locked_at,
        "source_entity_type": task.source_entity_type,
        "source_entity_id": str(task.source_entity_id),
        "source_run": str(task.source_run_id) if task.source_run_id else None,
        "result_run": str(task.result_run_id) if task.result_run_id and not task.runtime_run_id else None,
        "runtime_run_id": str(task.runtime_run_id) if task.runtime_run_id else None,
        "runtime_workspace_id": str(task.runtime_workspace_id) if task.runtime_workspace_id else None,
        "context_purpose": task.context_purpose,
        "target_instance_id": str(task.target_instance_id) if task.target_instance_id else None,
        "force": task.force,
        "created_at": task.created_at,
        "updated_at": task.updated_at,
    }


def _serialize_dev_task_summary(task: DevTask, *, runtime_detail: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    return _serialize_work_item_summary(task, runtime_detail=runtime_detail)


def _serialize_selected_work_item_queue_state(task: DevTask, *, normalized_status: str) -> Dict[str, Any]:
    queue_state = serialize_dev_task_queue_state(task, normalized_status=normalized_status)
    enriched_state: Dict[str, Any] = {
        **queue_state,
        "selected_for_dispatch": queue_state.get("dispatchable", False),
        "next_dispatchable_task_id": None,
        "next_dispatchable_work_item_id": None,
        "next_dispatchable_title": None,
        "next_dispatchable_thread_id": None,
        "next_dispatchable_thread_title": None,
    }
    if not task.coordination_thread_id:
        return enriched_state

    workspace = task.coordination_thread.workspace
    workspace_id = str(workspace.id)
    threads = _active_coordination_threads_for_workspace(workspace).select_related("workspace", "goal")
    task_lookup = _coordination_task_lookup_factory(workspace_id)
    queue_task_lookup = lambda reference: DevTask.objects.filter(id=reference).first()
    for thread in threads:
        _update_thread_status_from_tasks(thread)
    queue = derive_work_queue(threads=threads, status_lookup=_xco_status_lookup, task_lookup=task_lookup)
    selected = find_dispatchable_queue_entry(
        queue,
        task_id=str(task.id),
        task_lookup=queue_task_lookup,
        status_lookup=_xco_status_lookup,
    )
    if selected:
        return enriched_state

    next_selected = select_next_dispatchable_queue_entry(queue, task_lookup=queue_task_lookup, status_lookup=_xco_status_lookup)
    if not next_selected:
        return enriched_state

    next_entry, next_task, _ = next_selected
    enriched_state["selected_for_dispatch"] = False
    enriched_state["next_dispatchable_task_id"] = str(next_task.id)
    enriched_state["next_dispatchable_work_item_id"] = str(next_task.work_item_id or next_task.id)
    enriched_state["next_dispatchable_title"] = next_task.title
    enriched_state["next_dispatchable_thread_id"] = next_entry.thread_id
    enriched_state["next_dispatchable_thread_title"] = next_entry.thread_title
    if queue_state.get("dispatchable"):
        enriched_state["message"] = (
            f"{task.title} is approved, but {next_task.title} is next in the execution queue "
            f"for {next_entry.thread_title}."
        )
    return enriched_state


def _serialize_goal_summary(goal: Goal) -> Dict[str, Any]:
    return serialize_goal_summary(goal)


def _campaign_slug_exists(workspace_id: str, slug: str, *, exclude_campaign_id: Optional[str] = None) -> bool:
    qs = Campaign.objects.filter(workspace_id=workspace_id, slug=slug)
    if exclude_campaign_id:
        qs = qs.exclude(id=exclude_campaign_id)
    return qs.exists()


def _next_available_campaign_slug(workspace_id: str, name: str, *, exclude_campaign_id: Optional[str] = None) -> str:
    base = slugify(name)[:120] or "campaign"
    candidate = base
    suffix = 2
    while _campaign_slug_exists(workspace_id, candidate, exclude_campaign_id=exclude_campaign_id):
        token = f"-{suffix}"
        candidate = f"{base[: max(1, 120 - len(token))]}{token}"
        suffix += 1
    return candidate


def _builtin_campaign_type_definition() -> Dict[str, Any]:
    return {
        "key": "generic",
        "label": "Generic Campaign",
        "description": "Default campaign type for platform-level workflows.",
        "icon": "campaign",
        "scope": "global",
        "workspace_id": None,
        "enabled": True,
        "metadata": {},
    }


def _campaign_type_definitions_for_workspace(workspace: Workspace) -> List[Dict[str, Any]]:
    rows: Dict[str, Dict[str, Any]] = {"generic": _builtin_campaign_type_definition()}
    for record in (
        CampaignType.objects.filter(Q(workspace__isnull=True) | Q(workspace=workspace))
        .filter(enabled=True)
        .order_by("label", "key")
    ):
        key = str(record.key or "").strip()
        if not key:
            continue
        rows[key] = {
            "key": key,
            "label": str(record.label or key),
            "description": str(record.description or ""),
            "icon": str(record.icon or ""),
            "scope": "workspace" if record.workspace_id else "global",
            "workspace_id": str(record.workspace_id) if record.workspace_id else None,
            "enabled": bool(record.enabled),
            "metadata": record.metadata_json if isinstance(record.metadata_json, dict) else {},
        }
    return list(rows.values())


def _serialize_campaign_summary(campaign: Campaign) -> Dict[str, Any]:
    return {
        "id": str(campaign.id),
        "workspace_id": str(campaign.workspace_id),
        "slug": str(campaign.slug or ""),
        "name": campaign.name,
        "campaign_type": campaign.campaign_type,
        "status": campaign.status,
        "description": campaign.description or "",
        "archived": bool(campaign.archived),
        "created_by": str(campaign.created_by_id) if campaign.created_by_id else None,
        "created_at": campaign.created_at,
        "updated_at": campaign.updated_at,
    }


def _serialize_campaign_detail(campaign: Campaign, *, workspace: Optional[Workspace] = None) -> Dict[str, Any]:
    resolved_workspace = workspace or Workspace.objects.filter(id=campaign.workspace_id).first()
    available_types = _campaign_type_definitions_for_workspace(resolved_workspace) if resolved_workspace else [_builtin_campaign_type_definition()]
    type_lookup = {
        str(entry.get("key") or "").strip(): entry
        for entry in available_types
        if isinstance(entry, dict) and str(entry.get("key") or "").strip()
    }
    return {
        **_serialize_campaign_summary(campaign),
        "campaign_type_definition": type_lookup.get(campaign.campaign_type) or _builtin_campaign_type_definition(),
        "available_campaign_types": available_types,
        "metadata": campaign.metadata_json if isinstance(campaign.metadata_json, dict) else {},
    }


def _serialize_goal_recent_result(goal: Goal, result: Any, *, goal_status: str) -> Dict[str, Any]:
    task = goal.work_items.filter(work_item_id=result.work_item_id).select_related("coordination_thread").first()
    artifact_labels: List[str] = []
    if task:
        runtime_detail = _project_runtime_status_to_task(task)
        if isinstance(runtime_detail, dict):
            artifact_labels = [
                str(artifact.get("label") or artifact.get("artifact_type") or "artifact")
                for artifact in (runtime_detail.get("artifacts") if isinstance(runtime_detail.get("artifacts"), list) else [])
                if isinstance(artifact, dict)
            ]
    return {
        "work_item_id": result.work_item_id,
        "title": result.title,
        "status": result.status,
        "run_id": result.run_id,
        "thread_id": str(task.coordination_thread_id) if task and task.coordination_thread_id else None,
        "thread_title": str(task.coordination_thread.title) if task and task.coordination_thread_id else "",
        "artifact_count": len(artifact_labels),
        "artifact_labels": artifact_labels[:5],
        "goal_status": goal_status,
    }


def _serialize_goal_detail(goal: Goal) -> Dict[str, Any]:
    progress = compute_goal_progress(goal)
    metrics = compute_goal_execution_metrics(goal, runtime_detail_lookup=_project_runtime_status_to_task)
    health = compute_goal_health_indicators(goal, runtime_detail_lookup=_project_runtime_status_to_task)
    portfolio_row = build_goal_portfolio_row(goal, runtime_detail_lookup=_project_runtime_status_to_task)
    recommendation = recommend_next_slice(goal)
    development_loop_summary = compute_goal_development_loop_summary(goal, recommendation=recommendation)
    development_insights = serialize_development_insights(
        compute_goal_development_insights(goal, runtime_detail_lookup=_project_runtime_status_to_task)
    )
    goal_diagnostic = serialize_goal_diagnostic(
        compute_goal_diagnostic(goal, runtime_detail_lookup=_project_runtime_status_to_task)
    )
    recommendation_actions = [
        {
            "type": action.type,
            "label": action.label,
            "target_work_item": action.target_work_item,
            "target_thread": action.target_thread,
            "queueable": action.queueable,
        }
        for action in recommendation.actions
    ]
    return {
        **_serialize_goal_summary(goal),
        "threads": [_coordination_thread_summary(thread) for thread in goal.threads.all().order_by("created_at", "id")],
        "work_items": [_serialize_work_item_summary(task) for task in goal.work_items.all().order_by("priority", "created_at", "id")],
        "goal_progress": {
            "goal_progress_status": progress.goal_progress_status,
            "completed_work_items": progress.completed_work_items,
            "active_work_items": progress.active_work_items,
            "blocked_work_items": progress.blocked_work_items,
            "active_threads": progress.active_threads,
            "blocked_threads": progress.blocked_threads,
            "artifact_production_count": progress.artifact_production_count,
        },
        "metrics": {
            "active_threads": metrics.active_threads,
            "blocked_threads": metrics.blocked_threads,
            "total_completed_work_items": metrics.total_completed_work_items,
            "artifact_production_count": metrics.artifact_production_count,
        },
        "goal_health": {
            "progress_percent": health.progress_percent,
            "active_threads": health.active_threads,
            "blocked_threads": health.blocked_threads,
            "recent_artifacts": health.recent_artifacts,
        },
        "coordination_priority": {
            "value": portfolio_row.coordination_priority.value,
            "reasons": portfolio_row.coordination_priority.reasons,
            "recent_execution_count": portfolio_row.recent_execution_count,
            "health_status": portfolio_row.health_status,
        },
        "development_insights": development_insights,
        "goal_diagnostic": goal_diagnostic,
        "recommended_next_slice": {
            "recommendation_id": recommendation.recommendation_id,
            "goal_id": recommendation.goal_id,
            "thread_id": recommendation.thread_id,
            "thread_title": recommendation.thread_title,
            "work_item_id": recommendation.work_item_id,
            "work_item_title": recommendation.work_item_title,
            "recommended_work_items": [
                {
                    "id": item.id,
                    "title": item.title,
                    "thread_id": item.thread_id,
                    "thread_title": item.thread_title,
                }
                for item in recommendation.recommended_work_items
            ],
            "queue_suggestion": {
                "action_type": recommendation.queue_suggestion.action_type,
                "thread_id": recommendation.queue_suggestion.thread_id,
                "work_item_id": recommendation.queue_suggestion.work_item_id,
                "reason": recommendation.queue_suggestion.reason,
                "summary": recommendation.queue_suggestion.summary,
            }
            if recommendation.queue_suggestion
            else None,
            "actions": recommendation_actions,
            "reasoning_summary": recommendation.reasoning_summary,
            "summary": recommendation.summary,
        },
        "development_loop_summary": {
            "goal_status": development_loop_summary.goal_status,
            "threads": [
                {
                    "thread_id": item.thread_id,
                    "title": item.title,
                    "thread_status": item.thread_status,
                }
                for item in development_loop_summary.threads
            ],
            "recent_work_results": [
                _serialize_goal_recent_result(goal, item, goal_status=development_loop_summary.goal_status)
                for item in development_loop_summary.recent_work_results
            ],
            "recommended_next_slice": development_loop_summary.recommended_next_slice,
        },
        "recommendation": {
            "recommendation_id": recommendation.recommendation_id,
            "goal_id": recommendation.goal_id,
            "thread_id": recommendation.thread_id,
            "thread_title": recommendation.thread_title,
            "work_item_id": recommendation.work_item_id,
            "work_item_title": recommendation.work_item_title,
            "recommended_work_items": [
                {
                    "id": item.id,
                    "title": item.title,
                    "thread_id": item.thread_id,
                    "thread_title": item.thread_title,
                }
                for item in recommendation.recommended_work_items
            ],
            "queue_suggestion": {
                "action_type": recommendation.queue_suggestion.action_type,
                "thread_id": recommendation.queue_suggestion.thread_id,
                "work_item_id": recommendation.queue_suggestion.work_item_id,
                "reason": recommendation.queue_suggestion.reason,
                "summary": recommendation.queue_suggestion.summary,
            }
            if recommendation.queue_suggestion
            else None,
            "actions": recommendation_actions,
            "reasoning_summary": recommendation.reasoning_summary,
            "summary": recommendation.summary,
        },
    }


