@csrf_exempt
@login_required
def dev_task_run(request: HttpRequest, task_id: str) -> JsonResponse:
    if staff_error := _require_staff(request):
        return staff_error
    if request.method != "POST":
        return JsonResponse({"error": "POST required"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    task = get_object_or_404(DevTask, id=task_id)
    if _dev_task_uses_epic_c_runtime(task):
        runtime_detail = _project_runtime_status_to_task(task)
        if runtime_detail and str(runtime_detail.get("status") or "").strip().lower() in RUNTIME_DEV_TASK_ACTIVE_STATUSES and task.runtime_run_id:
            return JsonResponse({"run_id": str(task.runtime_run_id), "status": str(runtime_detail.get("status") or task.status)})
        workspace = _dev_task_runtime_workspace(identity, task, request=request)
        if not workspace:
            return JsonResponse({"error": "workspace context is required for Epic C runtime submission"}, status=400)
        try:
            result = _submit_dev_task_runtime_run(task, workspace=workspace, user=request.user)
        except ValueError as exc:
            task.status = "awaiting_review"
            task.last_error = str(exc)
            task.updated_by = request.user
            task.save(update_fields=["status", "last_error", "updated_by", "updated_at"])
            return JsonResponse({"error": str(exc)}, status=409)
        except RuntimeError as exc:
            task.status = "failed"
            task.last_error = str(exc)
            task.updated_by = request.user
            task.save(update_fields=["status", "last_error", "updated_by", "updated_at"])
            return JsonResponse({"error": str(exc)}, status=502)
        return JsonResponse(result)
    if task.status == "running":
        return JsonResponse({"error": "Task already running"}, status=409)
    if task.task_type == "deploy_release_plan" and not task.target_instance_id:
        return JsonResponse({"error": "target_instance_id required for deploy_release_plan"}, status=400)
    if request.GET.get("force") == "1":
        task.force = True
    task.force = bool(task.force)
    task.status = "queued"
    task.updated_by = request.user
    task.save(update_fields=["status", "updated_by", "updated_at", "force"])
    run = Run.objects.create(
        entity_type="dev_task",
        entity_id=task.id,
        status="pending",
        summary=f"Run dev task {task.title}",
        created_by=request.user,
        started_at=timezone.now(),
    )
    task.result_run = run
    task.save(update_fields=["result_run", "updated_at"])
    resolved = _resolve_context_pack_list(list(task.context_packs.all()))
    run.context_pack_refs_json = resolved.get("refs", [])
    run.context_hash = resolved.get("hash", "")
    _build_context_artifacts(run, resolved)
    run.save(update_fields=["context_pack_refs_json", "context_hash", "updated_at"])
    mode = _async_mode()
    if mode == "redis":
        _enqueue_job("xyn_orchestrator.worker_tasks.run_dev_task", str(task.id), "worker")
        return JsonResponse({"run_id": str(run.id), "status": "queued"})
    return JsonResponse({"run_id": str(run.id), "status": "pending"})


@csrf_exempt
@login_required
def dev_task_retry(request: HttpRequest, task_id: str) -> JsonResponse:
    if staff_error := _require_staff(request):
        return staff_error
    if request.method != "POST":
        return JsonResponse({"error": "POST required"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    task = get_object_or_404(DevTask, id=task_id)
    execution_payload = _resolve_dev_task_execution_payload(task)
    recovery = evaluate_dev_task_recovery_state(task, execution_summary=execution_payload["execution_summary"])
    if not recovery.retryable:
        return JsonResponse({"error": recovery.message}, status=409)
    if _dev_task_uses_epic_c_runtime(task):
        workspace = _dev_task_runtime_workspace(identity, task, request=request)
        if not workspace:
            return JsonResponse({"error": "workspace context is required for Epic C runtime submission"}, status=400)
        try:
            record_execution_failure_snapshot(
                task,
                execution_summary=execution_payload["execution_summary"],
                action="retry",
                recorded_at=timezone.now().isoformat(),
            )
            result = _submit_dev_task_runtime_run(task, workspace=workspace, user=request.user)
        except ValueError as exc:
            task.status = "awaiting_review"
            task.last_error = str(exc)
            task.updated_by = request.user
            task.save(update_fields=["execution_policy", "status", "last_error", "updated_by", "updated_at"])
            return JsonResponse({"error": str(exc)}, status=409)
        except RuntimeError as exc:
            task.status = "failed"
            task.last_error = str(exc)
            task.updated_by = request.user
            task.save(update_fields=["execution_policy", "status", "last_error", "updated_by", "updated_at"])
            return JsonResponse({"error": str(exc)}, status=502)
        task.refresh_from_db()
        return JsonResponse({"status": "queued", "run_id": result.get("run_id"), "work_item": _serialize_work_item_detail(task)})
    record_execution_failure_snapshot(
        task,
        execution_summary=execution_payload["execution_summary"],
        action="retry",
        recorded_at=timezone.now().isoformat(),
    )
    task.status = "queued"
    task.updated_by = request.user
    task.save(update_fields=["execution_policy", "status", "updated_by", "updated_at"])
    run = Run.objects.create(
        entity_type="dev_task",
        entity_id=task.id,
        status="pending",
        summary=f"Retry dev task {task.title}",
        created_by=request.user,
        started_at=timezone.now(),
    )
    task.result_run = run
    task.save(update_fields=["result_run", "updated_at"])
    resolved = _resolve_context_pack_list(list(task.context_packs.all()))
    run.context_pack_refs_json = resolved.get("refs", [])
    run.context_hash = resolved.get("hash", "")
    _build_context_artifacts(run, resolved)
    run.save(update_fields=["context_pack_refs_json", "context_hash", "updated_at"])
    mode = _async_mode()
    if mode == "redis":
        _enqueue_job("xyn_orchestrator.worker_tasks.run_dev_task", str(task.id), "worker")
        task.refresh_from_db()
        return JsonResponse({"run_id": str(run.id), "status": "queued", "work_item": _serialize_work_item_detail(task)})
    task.refresh_from_db()
    return JsonResponse({"run_id": str(run.id), "status": "pending", "work_item": _serialize_work_item_detail(task)})


