def _serialize_artifact_surface(surface: ArtifactSurface) -> Dict[str, Any]:
    renderer = getattr(surface, "renderer", None)
    if renderer is None:
        renderer = getattr(surface, "renderer_json", {}) or {}
    context = getattr(surface, "context", None)
    if context is None:
        context = getattr(surface, "context_json", {}) or {}
    permissions = getattr(surface, "permissions", None)
    if permissions is None:
        permissions = getattr(surface, "permissions_json", {}) or {}
    return {
        "id": str(surface.id),
        "artifact_id": str(surface.artifact_id),
        "key": surface.key,
        "title": surface.title,
        "description": surface.description or "",
        "surface_kind": surface.surface_kind,
        "route": surface.route,
        "nav_visibility": surface.nav_visibility,
        "nav_label": surface.nav_label,
        "nav_icon": surface.nav_icon,
        "nav_group": surface.nav_group,
        "renderer": renderer or {},
        "context": context or {},
        "permissions": permissions or {},
        "sort_order": int(surface.sort_order or 0),
        "created_at": surface.created_at,
        "updated_at": surface.updated_at,
    }


def _serialize_artifact_runtime_role(role: ArtifactRuntimeRole) -> Dict[str, Any]:
    return {
        "id": str(role.id),
        "artifact_id": str(role.artifact_id),
        "role_kind": role.role_kind,
        "spec": role.spec_json or {},
        "enabled": bool(role.enabled),
        "created_at": role.created_at,
        "updated_at": role.updated_at,
    }


def _normalize_surface_path(value: str) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    without_query = raw.split("?", 1)[0].split("#", 1)[0].strip()
    if not without_query.startswith("/"):
        without_query = f"/{without_query}"
    return without_query


def _workspace_prefix(workspace_id: Optional[str]) -> str:
    token = str(workspace_id or "").strip()
    if not token:
        return ""
    return f"/w/{token}"


def _manifest_ui_mount_scope(manifest: Dict[str, Any]) -> str:
    roles = manifest.get("roles") if isinstance(manifest.get("roles"), list) else []
    for role in roles:
        if not isinstance(role, dict):
            continue
        if str(role.get("role") or "").strip().lower() != "ui_mount":
            continue
        scope = str(role.get("scope") or "").strip().lower()
        if scope in {"global", "workspace"}:
            return scope
        return "workspace"
    return "workspace"


def _resolve_manifest_surface_path(manifest: Dict[str, Any], surface_path: str, workspace_id: Optional[str] = None) -> str:
    normalized = _normalize_surface_path(surface_path)
    if not normalized:
        return ""
    if normalized.startswith("/app/"):
        return normalized
    if normalized.startswith("/apps/"):
        if _manifest_ui_mount_scope(manifest) == "global":
            return normalized
        if workspace_id:
            return f"{_workspace_prefix(workspace_id)}{normalized}"
        return normalized
    if _manifest_ui_mount_scope(manifest) == "global":
        return normalized
    if workspace_id:
        return f"{_workspace_prefix(workspace_id)}{normalized}"
    return normalized


def _thread_status_for_task(task: DevTask) -> str:
    detail = _project_runtime_status_to_task(task)
    normalized = _canonical_work_item_status(str((detail or {}).get("status") or task.status), execution_policy=task.execution_policy)
    if task.status != normalized:
        task.status = normalized
        task.save(update_fields=["status", "updated_at"])
    if task.coordination_thread_id:
        policy = effective_thread_policy(task.coordination_thread)
        if normalized in {"awaiting_review", "failed"} and policy.get("pause_on_failure") and task.coordination_thread.status == "active":
            transition_thread_status(task.coordination_thread, "paused", work_item=task, run_id=str(task.runtime_run_id or ""), payload={"reason": "pause_on_failure"})
    return normalized


def _coordination_thread_summary(thread: CoordinationThread) -> Dict[str, Any]:
    progress = compute_thread_progress(thread)
    metrics = compute_thread_execution_metrics(thread, runtime_detail_lookup=_project_runtime_status_to_task)
    policy = effective_thread_policy(thread)
    tasks = list(thread.work_items.all().order_by("-updated_at", "-created_at")[:50])
    queued = 0
    running = 0
    awaiting_review = 0
    completed = 0
    failed = 0
    recent_runs: List[str] = []
    for task in tasks:
        status = _thread_status_for_task(task)
        if status == "queued":
            queued += 1
        elif status == "running":
            running += 1
        elif status == "awaiting_review":
            awaiting_review += 1
        elif status == "completed":
            completed += 1
        elif status in {"failed", "canceled"}:
            failed += 1
        if task.runtime_run_id and len(recent_runs) < 5:
            recent_runs.append(str(task.runtime_run_id))
    return {
        "id": str(thread.id),
        "workspace_id": str(thread.workspace_id),
        "goal_id": str(thread.goal_id) if thread.goal_id else None,
        "goal_title": str(thread.goal.title) if thread.goal_id else None,
        "title": thread.title,
        "description": thread.description or "",
        "owner": str(thread.owner_id) if thread.owner_id else None,
        "priority": thread.priority,
        "status": thread.status,
        "domain": thread.domain or None,
        "work_in_progress_limit": thread.work_in_progress_limit,
        "execution_policy": policy,
        "source_conversation_id": thread.source_conversation_id or None,
        "thread_progress_status": progress.thread_status,
        "work_items_completed": progress.work_items_completed,
        "work_items_ready": progress.work_items_ready,
        "work_items_blocked": progress.work_items_blocked,
        "metrics": {
            "average_run_duration_seconds": metrics.average_run_duration_seconds,
            "total_completed_work_items": metrics.total_completed_work_items,
            "failed_work_items": metrics.failed_work_items,
            "blocked_work_items": metrics.blocked_work_items,
        },
        "queued_work_items": queued,
        "running_work_items": running,
        "awaiting_review_work_items": awaiting_review,
        "completed_work_items": completed,
        "failed_work_items": failed,
        "recent_run_ids": recent_runs,
        "created_at": thread.created_at,
        "updated_at": thread.updated_at,
    }


def _coordination_thread_detail(thread: CoordinationThread) -> Dict[str, Any]:
    work_items = [_serialize_work_item_summary(task) for task in thread.work_items.all().order_by("-updated_at", "-created_at")[:100]]
    bundle = build_thread_observability_bundle(thread, runtime_detail_lookup=_project_runtime_status_to_task)
    progress = bundle["progress"]
    metrics = bundle["metrics"]
    return {
        **_coordination_thread_summary(thread),
        "thread_progress_status": progress.thread_status,
        "work_items_completed": progress.work_items_completed,
        "work_items_ready": progress.work_items_ready,
        "work_items_blocked": progress.work_items_blocked,
        "metrics": {
            "average_run_duration_seconds": metrics.average_run_duration_seconds,
            "total_completed_work_items": metrics.total_completed_work_items,
            "failed_work_items": metrics.failed_work_items,
            "blocked_work_items": metrics.blocked_work_items,
        },
        "work_items": work_items,
        "recent_runs": bundle["recent_runs"],
        "recent_artifacts": bundle["recent_artifacts"],
        "timeline": bundle["timeline"],
        "thread_diagnostic": serialize_thread_diagnostic(bundle["diagnostic"]),
    }


def _manifest_capability(manifest: Dict[str, Any]) -> Dict[str, Any]:
    raw = manifest.get("capability") if isinstance(manifest.get("capability"), dict) else {}
    visibility = str(raw.get("visibility") or "hidden").strip().lower() or "hidden"
    if visibility not in {"capabilities", "platform", "hidden"}:
        visibility = "hidden"
    try:
        order = int(raw.get("order", 1000))
    except (TypeError, ValueError):
        order = 1000
    payload: Dict[str, Any] = {"visibility": visibility, "order": order}
    label = str(raw.get("label") or "").strip()
    if label:
        payload["label"] = label
    category = str(raw.get("category") or "").strip().lower()
    if category in {"application", "integration", "platform", "library"}:
        payload["category"] = category
    icon = str(raw.get("icon") or "").strip()
    if icon:
        payload["icon"] = icon
    description = str(raw.get("description") or "").strip()
    if description:
        payload["description"] = description
    tags = raw.get("tags")
    if isinstance(tags, list):
        cleaned_tags = [str(entry).strip() for entry in tags if str(entry).strip()]
        if cleaned_tags:
            payload["tags"] = cleaned_tags
    permission_raw = raw.get("permission") if isinstance(raw.get("permission"), dict) else {}
    permission_resource = str(permission_raw.get("resource") or "").strip()
    permission_action = str(permission_raw.get("action") or "").strip()
    if permission_resource and permission_action:
        payload["permission"] = {"resource": permission_resource, "action": permission_action}
    return payload


def _manifest_suggestions(manifest: Dict[str, Any], workspace_id: Optional[str] = None) -> List[Dict[str, Any]]:
    raw_rows = manifest.get("suggestions") if isinstance(manifest.get("suggestions"), list) else []
    rows: List[Dict[str, Any]] = []
    allowed_visibility = {"landing", "capability", "palette", "hidden"}
    for idx, entry in enumerate(raw_rows):
        if not isinstance(entry, dict):
            continue
        suggestion_id = str(entry.get("id") or "").strip() or f"suggestion-{idx + 1}"
        prompt = str(entry.get("prompt") or "").strip()
        if not prompt:
            continue
        name = str(entry.get("name") or "").strip() or prompt
        description = str(entry.get("description") or "").strip()
        try:
            order = int(entry.get("order", 1000))
        except (TypeError, ValueError):
            order = 1000
        group = str(entry.get("group") or "").strip()
        capability_ref = str(entry.get("capability_ref") or "").strip()
        visibility_raw = entry.get("visibility")
        visibility_values: List[str] = []
        if isinstance(visibility_raw, list):
            visibility_values = [
                str(item).strip().lower()
                for item in visibility_raw
                if str(item).strip().lower() in allowed_visibility
            ]
        if not visibility_values:
            visibility_values = ["capability", "palette"]
        ui_raw = entry.get("ui") if isinstance(entry.get("ui"), dict) else {}
        ui_payload: Dict[str, Any] = {}
        ui_icon = str(ui_raw.get("icon") or "").strip()
        ui_badge = str(ui_raw.get("badge") or "").strip()
        if ui_icon:
            ui_payload["icon"] = ui_icon
        if ui_badge:
            ui_payload["badge"] = ui_badge
        permission_raw = entry.get("permission") if isinstance(entry.get("permission"), dict) else {}
        permission_resource = str(permission_raw.get("resource") or "").strip()
        permission_action = str(permission_raw.get("action") or "").strip()
        suggestion: Dict[str, Any] = {
            "id": suggestion_id,
            "name": name,
            "prompt": prompt,
            "visibility": visibility_values,
            "order": order,
        }
        if description:
            suggestion["description"] = description
        if group:
            suggestion["group"] = group
        if capability_ref:
            suggestion["capability_ref"] = capability_ref
        if ui_payload:
            suggestion["ui"] = ui_payload
        if permission_resource and permission_action:
            suggestion["permission"] = {"resource": permission_resource, "action": permission_action}
        rows.append(suggestion)
    rows.sort(
        key=lambda row: (
            int(row.get("order") or 1000),
            str(row.get("group") or "").lower(),
            str(row.get("name") or row.get("prompt") or "").lower(),
        )
    )
    return rows


def _resolved_capability_manifest(manifest: Dict[str, Any]) -> Dict[str, Any]:
    resolved = manifest.get("resolved_capability_manifest") if isinstance(manifest.get("resolved_capability_manifest"), dict) else {}
    if resolved:
        return resolved
    content = manifest.get("content") if isinstance(manifest.get("content"), dict) else {}
    resolved = content.get("resolved_capability_manifest") if isinstance(content.get("resolved_capability_manifest"), dict) else {}
    return resolved


def _manifest_payload(manifest: Dict[str, Any]) -> Dict[str, Any]:
    content = manifest.get("content") if isinstance(manifest.get("content"), dict) else {}
    return content or manifest


def _resolved_manifest_suggestions(artifact: Artifact, resolved: Dict[str, Any], payload: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    artifact_slug = _artifact_slug(artifact) or str(artifact.id)
    payload_rows = payload.get("suggestions") if isinstance(payload, dict) and isinstance(payload.get("suggestions"), list) else []
    latent_keys = _manifest_latent_command_keys(resolved)
    if payload_rows:
        rows: List[Dict[str, Any]] = []
        for suggestion in payload_rows:
            if not isinstance(suggestion, dict):
                continue
            prompt = str(suggestion.get("prompt") or "").strip()
            if not prompt:
                continue
            normalized_prompt = _normalize_palette_prompt(prompt)
            if normalized_prompt in latent_keys:
                continue
            row = copy.deepcopy(suggestion)
            row["prompt"] = normalized_prompt
            rows.append(row)
        rows.sort(
            key=lambda row: (
                int(row.get("order") or 1000),
                str(row.get("group") or "").lower(),
                str(row.get("name") or row.get("prompt") or "").lower(),
            )
        )
        return rows
    rows: List[Dict[str, Any]] = []
    for command in resolved.get("commands") if isinstance(resolved.get("commands"), list) else []:
        if not isinstance(command, dict):
            continue
        prompt = str(command.get("prompt") or "").strip()
        if not prompt:
            continue
        key = str(command.get("key") or prompt).strip().lower().replace(" ", "-")
        visibility = command.get("visibility") if isinstance(command.get("visibility"), list) else ["capability", "palette"]
        rows.append(
            {
                "id": f"{artifact_slug}-{key}",
                "name": str(command.get("name") or prompt).strip() or prompt,
                "prompt": prompt,
                "description": str(command.get("name") or "").strip(),
                "visibility": [str(item).strip() for item in visibility if str(item).strip()],
                "group": str(command.get("group") or "").strip(),
                "order": int(command.get("order") or 1000),
            }
        )
    rows.sort(
        key=lambda row: (
            int(row.get("order") or 1000),
            str(row.get("group") or "").lower(),
            str(row.get("name") or row.get("prompt") or "").lower(),
        )
    )
    return rows


def _resolved_manifest_surfaces(resolved: Dict[str, Any], workspace_id: Optional[str] = None) -> Dict[str, List[Dict[str, Any]]]:
    surfaces: Dict[str, List[Dict[str, Any]]] = {"nav": [], "manage": [], "docs": []}
    for view in resolved.get("views") if isinstance(resolved.get("views"), list) else []:
        if not isinstance(view, dict):
            continue
        surface = str(view.get("surface") or "").strip().lower()
        if surface not in surfaces:
            continue
        path = _resolve_manifest_surface_path(
            {"ui_mount_scope": "workspace"},
            str(view.get("path") or ""),
            workspace_id=workspace_id,
        )
        label = str(view.get("label") or "").strip()
        if not label or not path:
            continue
        surfaces[surface].append(
            {
                "label": label,
                "path": path,
                "order": int(view.get("order") or (100 if surface == "manage" else 1000)),
            }
        )
    for key in surfaces:
        surfaces[key].sort(key=lambda row: (int(row.get("order") or 1000), str(row.get("label") or "").lower()))
    return surfaces


def _resolved_manifest_entities(resolved: Dict[str, Any]) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    for entity in resolved.get("entities") if isinstance(resolved.get("entities"), list) else []:
        if not isinstance(entity, dict):
            continue
        rows.append(copy.deepcopy(entity))
    rows.sort(key=lambda row: str(row.get("key") or "").lower())
    return rows


def _manifest_contract_issue_summary(artifact: Artifact, resolved: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    issue = _generated_artifact_contract_issue(artifact, resolved)
    return copy.deepcopy(issue) if isinstance(issue, dict) else None


def _manifest_roots() -> List[Path]:
    resolved = Path(__file__).resolve()
    default_root = str(resolved.parents[1] if len(resolved.parents) > 1 else resolved.parent)
    raw = os.getenv("XYN_KERNEL_MANIFEST_ROOTS", default_root).strip()
    roots: List[Path] = []
    for token in raw.split(os.pathsep):
        part = token.strip()
        if not part:
            continue
        roots.append(Path(part))
    default_path = Path(default_root)
    if default_path not in roots:
        roots.append(default_path)
    return roots


def _resolve_manifest_path_for_artifact(artifact: Artifact) -> Optional[Path]:
    scope = artifact.scope_json if isinstance(artifact.scope_json, dict) else {}
    manifest_ref = str(scope.get("manifest_ref") or "").strip()
    if not manifest_ref:
        return None
    candidate = Path(manifest_ref)
    if candidate.is_absolute():
        return candidate if candidate.exists() else None
    for root in _manifest_roots():
        resolved = root / manifest_ref
        if resolved.exists():
            return resolved
    return None


def _load_artifact_manifest(artifact: Artifact) -> Dict[str, Any]:
    scope = artifact.scope_json if isinstance(artifact.scope_json, dict) else {}
    manifest_path = _resolve_manifest_path_for_artifact(artifact)
    if not manifest_path:
        embedded = scope.get("imported_manifest") if isinstance(scope.get("imported_manifest"), dict) else {}
        if embedded:
            manifest_artifact = embedded.get("artifact") if isinstance(embedded.get("artifact"), dict) else {}
            manifest_slug = str(manifest_artifact.get("id") or manifest_artifact.get("slug") or "").strip()
            expected_slug = str(_artifact_slug(artifact) or "").strip()
            if manifest_slug and expected_slug and manifest_slug != expected_slug:
                raise ValueError(
                    f"embedded manifest slug mismatch artifact_id={artifact.id} slug={expected_slug} "
                    f"manifest.artifact.id={manifest_slug}"
                )
            return embedded
        return {}
    try:
        payload = json.loads(manifest_path.read_text(encoding="utf-8"))
        if not isinstance(payload, dict):
            return {}
        manifest_artifact = payload.get("artifact") if isinstance(payload.get("artifact"), dict) else {}
        manifest_slug = str(manifest_artifact.get("id") or "").strip()
        expected_slug = str(_artifact_slug(artifact) or "").strip()
        if manifest_slug and expected_slug and manifest_slug != expected_slug:
            raise ValueError(
                f"manifest slug mismatch artifact_id={artifact.id} slug={expected_slug} "
                f"manifest.artifact.id={manifest_slug} file={manifest_path}"
            )
        return payload
    except Exception as exc:
        logger.warning("failed to load manifest artifact_id=%s path=%s error=%s", artifact.id, manifest_path, exc)
        raise ValueError(str(exc)) from exc


def _manifest_surface_entries(manifest: Dict[str, Any], surface_key: str, workspace_id: Optional[str] = None) -> List[Dict[str, Any]]:
    surfaces = manifest.get("surfaces") if isinstance(manifest.get("surfaces"), dict) else {}
    raw_rows = surfaces.get(surface_key) if isinstance(surfaces.get(surface_key), list) else []
    rows: List[Dict[str, Any]] = []
    for idx, entry in enumerate(raw_rows):
        if not isinstance(entry, dict):
            continue
        label = str(entry.get("label") or "").strip()
        path = _resolve_manifest_surface_path(manifest, str(entry.get("path") or ""), workspace_id=workspace_id)
        if not label or not path:
            continue
        try:
            order = int(entry.get("order", 1000))
        except (TypeError, ValueError):
            order = 1000
        item: Dict[str, Any] = {
            "label": label,
            "path": path,
            "order": order,
        }
        icon = str(entry.get("icon") or "").strip()
        group = str(entry.get("group") or "").strip()
        if icon:
            item["icon"] = icon
        if group:
            item["group"] = group
        rows.append(item)
    rows.sort(key=lambda item: (int(item.get("order") or 1000), str(item.get("label") or "").lower()))
    return rows


def _article_surface_variant(artifact: Artifact) -> str:
    fmt = _normalize_article_format(getattr(artifact, "format", None), fallback="standard")
    return "explainer_video" if fmt == "video_explainer" else "standard"


def _article_surface_base_path(artifact: Artifact, workspace_id: Optional[str]) -> str:
    artifact_slug = _artifact_slug(artifact)
    variant = _article_surface_variant(artifact)
    query = urlencode(
        {
            "artifact": artifact_slug,
            "id": str(artifact.id),
            "artifact_instance_id": str(artifact.id),
            "draft_id": str(artifact.id),
            "variant": variant,
        }
    )
    if workspace_id:
        return f"/w/{workspace_id}/apps/articles/edit?{query}"
    return f"/apps/articles/edit?{query}"


def _article_docs_surface_path(artifact: Artifact, workspace_id: Optional[str]) -> str:
    variant = _article_surface_variant(artifact)
    query = urlencode({"variant": variant})
    if workspace_id:
        return f"/w/{workspace_id}/apps/articles/docs?{query}"
    return f"/apps/articles/docs?{query}"


def _manifest_summary_for_artifact(artifact: Artifact, workspace_id: Optional[str] = None) -> Dict[str, Any]:
    manifest = _load_artifact_manifest(artifact)
    payload = _manifest_payload(manifest)
    suggestion_payload = payload
    if not isinstance(suggestion_payload.get("suggestions"), list) and isinstance(manifest.get("suggestions"), list):
        suggestion_payload = manifest
    resolved = _resolved_capability_manifest(manifest)
    contract_issue = _manifest_contract_issue_summary(artifact, resolved)
    roles_raw = payload.get("roles") if isinstance(payload.get("roles"), list) else []
    roles: List[str] = []
    for role in roles_raw:
        if not isinstance(role, dict):
            continue
        role_name = str(role.get("role") or "").strip().lower()
        if role_name:
            roles.append(role_name)
    unique_roles = sorted(set(roles))
    surfaces = {
        "nav": _manifest_surface_entries(payload, "nav", workspace_id=workspace_id),
        "manage": _manifest_surface_entries(payload, "manage", workspace_id=workspace_id),
        "docs": _manifest_surface_entries(payload, "docs", workspace_id=workspace_id),
    }
    suggestions = _manifest_suggestions(payload, workspace_id=workspace_id)
    if str(resolved.get("schema_version") or "").strip() == "xyn.capability_manifest.v1":
        suggestions = _resolved_manifest_suggestions(artifact, resolved, suggestion_payload)
        surfaces = _resolved_manifest_surfaces(resolved, workspace_id=workspace_id)
    if contract_issue and str(contract_issue.get("reason") or "") == "missing_entity_contracts":
        suggestions = []
    summary = {
        "roles": unique_roles,
        "ui_mount_scope": _manifest_ui_mount_scope(payload),
        "capability": _manifest_capability(payload),
        "suggestions": suggestions,
        "entities": [] if contract_issue else _resolved_manifest_entities(resolved),
        "surfaces": surfaces,
    }
    if contract_issue:
        summary["generated_artifact_contract_status"] = contract_issue
    if artifact.type_id and artifact.type.slug == "article":
        manage_rows = summary.get("surfaces", {}).get("manage") or []
        docs_rows = summary.get("surfaces", {}).get("docs") or []
        if not manage_rows:
            manage_rows = [
                {
                    "label": "Editor",
                    "path": _article_surface_base_path(artifact, workspace_id),
                    "order": 100,
                }
            ]
        if not docs_rows:
            docs_rows = [
                {
                    "label": "Article Variant Docs",
                    "path": _article_docs_surface_path(artifact, workspace_id),
                    "order": 1000,
                }
            ]
        summary["surfaces"]["manage"] = manage_rows
        summary["surfaces"]["docs"] = docs_rows
    return summary


def _manifest_nav_surfaces(binding: WorkspaceArtifactBinding) -> List[Dict[str, Any]]:
    artifact = binding.artifact
    manifest = _load_artifact_manifest(artifact)
    scope = _manifest_ui_mount_scope(manifest)
    nav_entries = _manifest_surface_entries(manifest, "nav", workspace_id=str(binding.workspace_id))
    rows: List[Dict[str, Any]] = []

    for idx, entry in enumerate(nav_entries):
        label = str(entry.get("label") or "").strip()
        route = _normalize_surface_path(str(entry.get("path") or ""))
        sort_order = int(entry.get("order") or 1000)
        nav_group = str(entry.get("group") or "build").strip().lower() or "build"
        nav_icon = str(entry.get("icon") or "").strip() or None
        rows.append(
            {
                "id": f"manifest-nav-{artifact.id}-{idx}",
                "artifact_id": str(artifact.id),
                "key": f"manifest-nav-{idx}",
                "title": label,
                "description": None,
                "surface_kind": "docs",
                "route": route,
                "nav_visibility": "always",
                "nav_label": label,
                "nav_icon": nav_icon,
                "nav_group": nav_group,
                "renderer": {"type": "ui_mount"},
                "context": {"source": "manifest"},
                "permissions": {},
                "sort_order": sort_order,
                "created_at": artifact.created_at,
                "updated_at": artifact.updated_at,
                "ui_mount_scope": scope,
                "_source_kind": "manifest",
                "_artifact_title": artifact.title,
            }
        )
    return rows


def _resolve_nav_workspace(identity: UserIdentity, requested_workspace_id: str) -> Optional[Workspace]:
    if requested_workspace_id:
        membership = WorkspaceMembership.objects.select_related("workspace").filter(
            workspace_id=requested_workspace_id, user_identity=identity
        ).first()
        return membership.workspace if membership else None
    fallback = WorkspaceMembership.objects.select_related("workspace").filter(user_identity=identity).order_by("workspace__name").first()
    return fallback.workspace if fallback else None


def _surface_route_match(route_pattern: str, path: str) -> Optional[Dict[str, str]]:
    pattern = _normalize_surface_path(route_pattern)
    candidate = _normalize_surface_path(path)
    if not pattern or not candidate:
        return None
    pattern_parts = [part for part in pattern.split("/") if part]
    candidate_parts = [part for part in candidate.split("/") if part]
    if len(pattern_parts) != len(candidate_parts):
        return None
    params: Dict[str, str] = {}
    for pattern_part, candidate_part in zip(pattern_parts, candidate_parts):
        if pattern_part.startswith(":"):
            key = pattern_part[1:].strip()
            if not key:
                return None
            params[key] = unquote(candidate_part)
            continue
        if pattern_part != candidate_part:
            return None
    return params


@csrf_exempt
@login_required
def artifact_surfaces_collection(request: HttpRequest, artifact_id: str) -> JsonResponse:
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if staff_error := _require_staff(request):
        return staff_error
    artifact = get_object_or_404(Artifact.objects.select_related("type"), id=artifact_id)
    surfaces = ArtifactSurface.objects.filter(artifact=artifact).order_by("sort_order", "key")
    return JsonResponse({"artifact_id": str(artifact.id), "surfaces": [_serialize_artifact_surface(row) for row in surfaces]})


